import React from 'react';
import { motion } from 'framer-motion';
import { TimerState } from '../types';

interface MiniTimerProps {
  state: TimerState;
  onClick: () => void;
}

export const MiniTimer: React.FC<MiniTimerProps> = ({ state, onClick }) => {
  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const currentTotalTime = state.mode === 'FOCUS' ? state.focusDuration * 60 : state.breakDuration * 60;
  // Prevent division by zero and ensure progress is between 0 and 1
  const safeTotal = currentTotalTime > 0 ? currentTotalTime : 1;
  const progress = Math.max(0, Math.min(1, 1 - (state.timeLeft / safeTotal)));

  // SVG Configuration to prevent clipping
  const viewBoxSize = 100;
  const strokeWidth = 8;
  const center = viewBoxSize / 2;
  // Radius calculation: (Size - Stroke) / 2 - Padding (to accommodate round line caps)
  const radius = (viewBoxSize - strokeWidth) / 2 - 4; 
  const circumference = 2 * Math.PI * radius;
  const dashOffset = circumference * (1 - progress);

  return (
    <motion.button
      layout
      initial={{ scale: 0, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      exit={{ scale: 0, opacity: 0 }}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      onClick={onClick}
      className="fixed bottom-28 right-6 z-40 bg-white rounded-full shadow-xl flex items-center justify-center w-16 h-16 border border-gray-100 overflow-hidden"
    >
      <div className="relative w-full h-full p-1">
        <svg 
          className="w-full h-full transform -rotate-90" 
          viewBox={`0 0 ${viewBoxSize} ${viewBoxSize}`}
        >
          {/* Background Track */}
          <circle
            cx={center} cy={center} r={radius}
            stroke="#F3F4F6" 
            strokeWidth={strokeWidth} 
            fill="none"
          />
          {/* Progress Indicator */}
          <circle
            cx={center} cy={center} r={radius}
            stroke={state.mode === 'FOCUS' ? "#374151" : "#34D399"}
            strokeWidth={strokeWidth} 
            fill="none"
            strokeDasharray={circumference}
            strokeDashoffset={dashOffset}
            strokeLinecap="round"
          />
        </svg>

        {/* Timer Text Overlay */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <span className="text-xs font-bold font-mono text-gray-800 tracking-tight">
            {formatTime(state.timeLeft)}
            </span>
        </div>
      </div>
    </motion.button>
  );
};

import React from 'react';
import { motion } from 'framer-motion';
import { GrammarDefinition } from '../types';

interface GrammarCardProps {
  data: GrammarDefinition;
  layoutId: string;
  onClick?: () => void;
  isExpanded?: boolean;
  onClose?: () => void;
}

export const GrammarCard: React.FC<GrammarCardProps> = ({ 
  data, 
  layoutId, 
  onClick, 
  isExpanded = false,
  onClose 
}) => {
  return (
    <motion.div
      layoutId={layoutId}
      onClick={onClick}
      className={`bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden relative ${
        isExpanded 
          ? 'w-full max-w-2xl p-8 shadow-2xl z-50 cursor-default h-auto max-h-[85vh] overflow-y-auto no-scrollbar' 
          : 'p-6 hover:shadow-md hover:border-gray-300 cursor-pointer'
      } transition-colors duration-300`}
      initial={isExpanded ? { opacity: 0 } : { opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ 
        layout: { duration: 0.3, ease: "easeInOut" },
        opacity: { duration: 0.2 }
      }}
    >
      {/* Close Button */}
      {isExpanded && onClose && (
        <button 
          onClick={(e) => {
            e.stopPropagation();
            onClose();
          }}
          className="absolute top-4 right-4 p-2 bg-gray-100 hover:bg-gray-200 rounded-full text-gray-500 transition-colors z-10"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
          </svg>
