      )}

      <motion.div className="mb-4" layout="position">
        <motion.div layout="position" className="flex items-center space-x-2 mb-2">
           <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-0.5 rounded uppercase tracking-wide">Grammar</span>
        </motion.div>

        <motion.h3 layout="position" className={`${isExpanded ? 'text-3xl' : 'text-xl'} font-bold text-gray-800 mb-2`}>
          {data.grammarPoint}
        </motion.h3>

        {/* Connection moved here, larger and black */}
        <motion.p layout="position" className={`${isExpanded ? 'text-lg' : 'text-base'} font-bold text-black`}>
          {data.connection}
