      </motion.div>

      <motion.div 
        layout="position" 
        className={`border-t border-gray-100 pt-4 ${!isExpanded ? 'line-clamp-4' : ''}`}
      >
        <motion.p layout="position" className={`${isExpanded ? 'text-xl mb-4' : 'text-base mb-2'} text-gray-700 font-medium`}>
