};

export const fetchGrammarDetails = async (grammarInput: string): Promise<GrammarDefinition[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `You are an expert Japanese grammar teacher for Traditional Chinese students.
      Analyze the following grammar points input by the user: "${grammarInput}".
      Provide the grammar point, connection rules (how to attach to verbs/nouns/etc), meaning, detailed explanation, and 2-3 example sentences with readings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: grammarSchema,
      },
    });

    const text = response.text;
    if (!text) return [];
    const rawData = JSON.parse(text);
    // Add ID for frontend use
    return rawData.map((item: any, index: number) => ({
      ...item,
      id: `grammar-${Date.now()}-${index}`
    })) as GrammarDefinition[];
  } catch (error) {
    console.error("Error fetching grammar:", error);
    throw error;
  }
};

