                 <option value="N5">N5 (ίΙζύ┤γ)</option>
                 <option value="N4">N4 (ίΙζύ┤γ)</option>
                 <option value="N3">N3 (ϊ╕φύ┤γ)</option>
                 <option value="N2">N2 (ϊ╕φώταύ┤γ)</option>
                 <option value="N1">N1 (ώταύ┤γ)</option>
               </select>
            </div>

            <div className="flex-1 overflow-y-auto pr-2 space-y-2 no-scrollbar">
               {filteredTokens.length === 0 ? (
                 <p className="text-center text-gray-400 py-8 text-sm">όφνύφΚύ┤γό▓ΤόεΚϋπμόηΡώιΖύδχήΑΓ</p>
               ) : (
                 filteredTokens.map((token, idx) => (
                   <motion.div
                     key={idx}
                     layout
                     onClick={() => setSelectedToken(selectedToken === token ? null : token)}
                     className={`p-3 rounded-xl border-2 transition-all cursor-pointer ${
                         selectedToken === token 
                         ? 'border-gray-400 bg-white shadow-md' 
                         : 'border-transparent bg-gray-50 hover:bg-white hover:shadow-sm'
                     }`}
                   >
                      <div className="flex items-center justify-between">
                         <div className="flex items-center gap-3">
                            <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${JLPT_COLORS[token.jlpt] || JLPT_COLORS.Unknown}`}>
                               {JLPT_LABELS[token.jlpt] || '?'}
                            </span>
                            <div>
                               <p className="font-bold text-gray-800">{token.text}</p>
                               {token.text !== token.dictionaryForm && (
                                   <p className="text-xs text-gray-400">({token.dictionaryForm})</p>
                               )}
                            </div>
                         </div>
                         <div className="text-xs text-gray-400 font-mono">
                           {token.reading}
                         </div>
                      </div>

                      {/* Expanded Details */}
                      <AnimatePresence>
                        {selectedToken === token && (
                           <motion.div 
                             initial={{ height: 0, opacity: 0 }}
                             animate={{ height: 'auto', opacity: 1 }}
                             exit={{ height: 0, opacity: 0 }}
                             className="overflow-hidden mt-2 pt-2 border-t border-gray-100"
                           >
                              <div className="flex gap-2 mb-1">
                                <span className={`text-[10px] uppercase tracking-wider font-bold ${token.type === 'GRAMMAR' ? 'text-pink-500' : 'text-indigo-500'}`}>
                                  {token.type}
                                </span>
                              </div>
                              <p className="text-gray-700 font-medium">{token.meaning}</p>
                           </motion.div>
                        )}
                      </AnimatePresence>
                   </motion.div>
                 ))
               )}
            </div>
         </div>
      </div>
    </motion.div>
  );
};

import React, { useState, useEffect } from 'react';
