export const fetchWordDefinitions = async (wordsInput: string): Promise<WordDefinition[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `You are a strict Japanese language teacher. 
      Analyze the following Japanese words input by the user: "${wordsInput}".
      If the input contains multiple words separated by spaces or commas, handle all of them.
      Provide the definition, reading (hiragana), meaning in Traditional Chinese (Taiwan usage), and one good example sentence.
      CRITICAL: Also provide a 'sentenceBreakdown' which lists the key words inside that example sentence with their readings and meanings to help a student understand the sentence structure.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: wordDefinitionSchema,
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text) as WordDefinition[];
  } catch (error) {
    console.error("Error fetching definitions:", error);
    throw error;
  }
};

