export const generateQuizFromContent = async (words: WordDefinition[], grammar: GrammarDefinition[]): Promise<QuizQuestion[]> => {
  try {
    if (words.length === 0 && grammar.length === 0) return [];

    // Serialize content
    const contentContext = JSON.stringify({ words, grammar });
    const totalItems = words.length + grammar.length;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `
      You are a specialized Japanese language quiz generator for Traditional Chinese (Taiwan) learners.

      Source Content (JSON):
      ${contentContext}

      Task: Create a multiple-choice quiz with exactly ${Math.min(totalItems * 3, 12)} questions based on the Source Content.

      Required Question Mix:
      1. **Translation**: Word/Grammar <-> Chinese Meaning.
      2. **Orthography**: Kanji/Hiragana identification.
      3. **Context/Fill-in-the-blank**: Choose the correct word or grammar form to complete the sentence.
      4. **Grammar Structure**: Test the correct connection (e.g., "Which form follows this verb?").
      5. **Sentence Composition**: "Select the correct order of words to form a sentence using [Grammar Point]".
      6. **Reading Comprehension**: 
         - Create a short passage incorporating source words/grammar.
         - Ask a comprehension question.

      Guidelines:
      - **Language**: Question prompts in Traditional Chinese. Target content in Japanese.
      - **Difficulty**: JLPT N5-N3 level appropriate to the input.
      - **Explanation**: Provide a detailed explanation in Traditional Chinese.

      Return purely JSON matching the schema.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: quizSchema,
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text) as QuizQuestion[];
  } catch (error) {
    console.error("Error generating quiz:", error);
    throw error;
  }
};

export const getChatResponse = async (history: ChatMessage[], newMessage: string): Promise<any> => {
  try {
    // Construct a simplified history context string
    const conversationContext = history.slice(-10).map(msg => 
      `${msg.role === 'user' ? 'Student' : 'Teacher'}: ${msg.text}`
    ).join('\n');

    const prompt = `
    You are a friendly Japanese friend/tutor chatting with a student.

    Conversation History:
    ${conversationContext}
    Student: ${newMessage}

    Your tasks:
    1. Reply naturally in Japanese (keep it conversational, adjust politeness based on context).
    2. Provide a Traditional Chinese (Taiwan) translation of your reply.
    3. If the student made a grammar/vocabulary mistake in their last message, provide a 'correction' (The corrected Japanese sentence + brief explanation). If natural, leave correction empty.

    Return JSON.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: chatResponseSchema
      }
    });

    const text = response.text;
    if(!text) throw new Error("Empty response");
    return JSON.parse(text);

  } catch (error) {
    console.error("Chat Error", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChatMessage } from '../types';
import { getChatResponse } from '../services/geminiService';
import { Button } from './Button';

interface ChatInterfaceProps {
  onBack: () => void;
  onXpUpdate: (amount: number) => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack, onXpUpdate }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'ήΒΥήΓΥήΒτήΒκήΒψΎ╝ΒήΒΛίΖΔό░ΩήΒπήΒβήΒΜΎ╝θϊ╜ΧήΒΜϋσ▒ήΒΩήΒ╛ήΒΩήΓΘήΒΗΎ╝Β',
      translation: 'ϊ╜ιίξ╜Ύ╝Βϊ╜ιίξ╜ίΩΟΎ╝θόΙΣίΑΣϊ╛ΗϋΒΛϋΒΛίνσίΡπΎ╝Β',
      timestamp: Date.now()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    // Auto scroll to bottom
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  useEffect(() => {
    // Initialize Speech Recognition
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.lang = 'ja-JP'; // Listen for Japanese
      recognitionRef.current.interimResults = false;

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInputText(prev => prev + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech error", event);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, []);

  const handleSend = async () => {
    if (!inputText.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    try {
      const response = await getChatResponse(messages, inputText);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.reply,
        translation: response.translation,
        correction: response.correction,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      onXpUpdate(5); // Reward XP per message

      // Auto play audio for AI response? Optional, maybe just provide button
    } catch (error) {
      console.error(error);
      // Add error message locally
    } finally {
      setIsLoading(false);
    }
  };

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      try {
        recognitionRef.current?.start();
      } catch (e) {
        console.error(e);
        setIsListening(false);
      }
    }
  };

