                   onClick={() => updatePetXp(1)}
                 />
               </div>
             </div>
          </div>
        );

      default:
        return null;
    }
  };

  const findWordData = (id: string | null) => {
    if (!id) return null;
    const currentMatch = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (currentMatch) return currentMatch;
    if (id.includes('-history-')) {
       const parts = id.split('-history-');
       const recordId = parts[1].split('-')[0];
       const record = history.find(h => h.id === recordId);
       if (record && record.words) {
          const wordIndex = parseInt(parts[1].split('-')[1]);
          return record.words[wordIndex];
       }
    }
    return null;
  };

  const findGrammarData = (id: string | null) => {
    if (!id) return null;
    const currentMatch = currentGrammar.find(g => g.id === id);
    if (currentMatch) return currentMatch;
    if (id.includes('grammar-history-')) {
        const parts = id.split('grammar-history-');
        const recordId = parts[1].split('-')[0];
        const record = history.find(h => h.id === recordId);
        if (record && record.grammar) {
           const idx = parseInt(parts[1].split('-')[1]);
           return record.grammar[idx];
        }
    }
    return null;
  };

  const selectedWordData = findWordData(selectedWordId);
  const selectedGrammarData = findGrammarData(selectedGrammarId);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-gray-200">
