             className="fixed bottom-24 left-1/2 transform -translate-x-1/2 z-50 bg-gray-900 text-white px-6 py-4 rounded-full shadow-2xl flex items-center space-x-4 border border-gray-700"
          >
             <div className="text-3xl">{newAchievement.icon}</div>
             <div>
               <p className="text-xs text-gray-400 font-bold uppercase tracking-wider">όΙΡί░▒ϋπμώΟΨΎ╝Β</p>
               <p className="font-bold text-lg">{newAchievement.title}</p>
