            onClick={() => setSelectedAchievement(null)}
          >
             <motion.div 
               initial={{ scale: 0.9, opacity: 0 }}
               animate={{ scale: 1, opacity: 1 }}
               exit={{ scale: 0.9, opacity: 0 }}
               className="bg-white rounded-2xl shadow-2xl p-8 max-w-sm w-full text-center"
               onClick={(e) => e.stopPropagation()}
             >
                <div className="text-6xl mb-4">{selectedAchievement.icon}</div>
                <h3 className="text-2xl font-bold text-gray-800 mb-2">{selectedAchievement.title}</h3>
                <p className="text-gray-600 mb-6">{selectedAchievement.description}</p>

                <div className={`text-xs font-bold uppercase tracking-wide py-1 px-3 rounded-full inline-block ${
                  petStats.unlockedAchievements.includes(selectedAchievement.id) 
                  ? 'bg-green-100 text-green-700' 
                  : 'bg-gray-100 text-gray-400'
                }`}>
                  {petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'ί╖▓ϋπμώΟΨ' : 'όεςϋπμώΟΨ'}
                </div>
             </motion.div>
