                className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center text-center max-w-sm"
             >
                <div className="text-6xl mb-4 animate-bounce">ΏθΟΚ</div>
                <h3 className="text-3xl font-bold text-gray-800 mb-2">ί░Ιό│ρώΒΦόρβΎ╝Β</h3>
                <p className="text-gray-500 mb-8">ίνςόμΤϊ║ΗΎ╝Νϊ╜ιίχΝόΙΡϊ║Ηϊ╕ΑίΑΜί░Ιό│ρί╛ςύΤ░ήΑΓ<br/>ϊ╝ΣόΒψόαψύΓ║ϊ║Ηϋ╡░όδ┤ώΧ╖ώΒιύγΕϋ╖ψήΑΓ</p>
                <div className="mb-8 scale-150">
                    <PetCompanion stats={{...petStats, mood: 'happy'}} onClick={() => {}} />
                </div>
                <Button onClick={() => setShowCelebration(false)} fullWidth>ύ╣╝ύ║ΝίΛιό▓╣</Button>
             </motion.div>
