                >
                    <p className="text-xs text-gray-400 mb-4 font-medium tracking-wide uppercase">
                        {isListening ? 'ϋΒ╜ίΠΨϊ╕φ...' : 'ώ╗ηόΥΛϋςςϋσ▒'}
