export const generateQuizFromContent = async (words: WordDefinition[], grammar: GrammarDefinition[]): Promise<QuizQuestion[]> => {
  try {
    if (words.length === 0 && grammar.length === 0) return [];

    // Serialize content
    const contentContext = JSON.stringify({ words, grammar });
    const totalItems = words.length + grammar.length;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `
      You are a specialized Japanese language quiz generator for Traditional Chinese (Taiwan) learners.

      Source Content (JSON):
      ${contentContext}

      Task: Create a multiple-choice quiz with exactly ${Math.min(totalItems * 3, 12)} questions based on the Source Content.

      Required Question Mix:
      1. **Translation**: Word/Grammar <-> Chinese Meaning.
      2. **Orthography**: Kanji/Hiragana identification.
      3. **Context/Fill-in-the-blank**: Choose the correct word or grammar form to complete the sentence.
      4. **Grammar Structure**: Test the correct connection (e.g., "Which form follows this verb?").
      5. **Sentence Composition**: "Select the correct order of words to form a sentence using [Grammar Point]".
      6. **Reading Comprehension**: 
         - Create a short passage incorporating source words/grammar.
         - Ask a comprehension question.

      Guidelines:
      - **Language**: Question prompts in Traditional Chinese. Target content in Japanese.
      - **Difficulty**: JLPT N5-N3 level appropriate to the input.
      - **Explanation**: Provide a detailed explanation in Traditional Chinese.

      Return purely JSON matching the schema.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: quizSchema,
      },
    });

    const text = response.text;
    if (!text) return [];
    return JSON.parse(text) as QuizQuestion[];
  } catch (error) {
    console.error("Error generating quiz:", error);
    throw error;
  }
};

export const getChatResponse = async (history: ChatMessage[], newMessage: string, replyContext?: string): Promise<any> => {
  try {
    // Construct a simplified history context string
    const conversationContext = history.slice(-10).map(msg => 
      `${msg.role === 'user' ? 'Student' : 'Teacher'}: ${msg.text}`
    ).join('\n');

    let prompt = `
    You are a friendly Japanese friend/tutor chatting with a student.

    Conversation History:
    ${conversationContext}
    `;

    if (replyContext) {
      prompt += `\nCONTEXT INFO: The student is specifically replying to this previous statement or context: "${replyContext}". Please ensure your answer addresses this specific context.\n`;
    }

    prompt += `
    Student: ${newMessage}

    Your tasks:
    1. Reply naturally in Japanese (keep it conversational, adjust politeness based on context).
    2. Provide a Traditional Chinese (Taiwan) translation of your reply.
    3. If the student made a grammar/vocabulary mistake in their last message, provide a 'correction' (The corrected Japanese sentence + brief explanation). If natural, leave correction empty.

    Return JSON.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: chatResponseSchema
      }
    });

    const text = response.text;
    if(!text) throw new Error("Empty response");
    return JSON.parse(text);

  } catch (error) {
    console.error("Chat Error", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChatMessage } from '../types';
import { getChatResponse } from '../services/geminiService';

interface ChatInterfaceProps {
  onBack: () => void;
  onXpUpdate: (amount: number) => void;
}

type ChatMode = 'TEXT' | 'VOICE';

const STORAGE_KEY = 'mk-nihongo-chat-history';

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack, onXpUpdate }) => {
  // Initialize messages from localStorage or use default welcome message
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    try {
      const savedMessages = localStorage.getItem(STORAGE_KEY);
      if (savedMessages) {
        return JSON.parse(savedMessages);
      }
    } catch (error) {
      console.error("Failed to load chat history:", error);
    }

    return [{
      id: 'welcome',
      role: 'model',
      text: 'ήΒΥήΓΥήΒτήΒκήΒψΎ╝ΒήΒΛίΖΔό░ΩήΒπήΒβήΒΜΎ╝θϊ╜ΧήΒΜϋσ▒ήΒΩήΒ╛ήΒΩήΓΘήΒΗΎ╝Β',
      translation: 'ϊ╜ιίξ╜Ύ╝Βϊ╜ιίξ╜ίΩΟΎ╝θόΙΣίΑΣϊ╛ΗϋΒΛϋΒΛίνσίΡπΎ╝Β',
      timestamp: Date.now()
    }];
  });

  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [chatMode, setChatMode] = useState<ChatMode>('TEXT');
  const [activeMessageId, setActiveMessageId] = useState<string | null>(null); // For showing options menu
  const [replyMessage, setReplyMessage] = useState<ChatMessage | null>(null); // For context replying

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  // Auto scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isListening, chatMode, replyMessage]);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false; // Stop after one sentence for cleaner turn-taking
      recognitionRef.current.lang = 'ja-JP'; 
      recognitionRef.current.interimResults = true;

      recognitionRef.current.onresult = (event: any) => {
        let finalTranscript = '';
        let interimTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }

        if (finalTranscript) {
          setInputText(finalTranscript);
          handleSend(finalTranscript, 'VOICE'); // Auto send on final result in voice mode
        } else {
            // Show interim results in input box if in text mode, or handle visually in voice mode
            if(chatMode === 'TEXT') setInputText(interimTranscript);
        }
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech error", event);
        setIsListening(false);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }

    return () => {
        if(recognitionRef.current) recognitionRef.current.stop();
        synthRef.current.cancel();
    }
  }, [chatMode]);

  const handleSend = async (textOverride?: string, sourceMode: ChatMode = chatMode) => {
    const textToSend = textOverride || inputText;
    if (!textToSend.trim()) return;

    // Stop listening if sending
    if (isListening) recognitionRef.current?.stop();

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setReplyMessage(null); // Clear reply state
    setIsLoading(true);

    try {
      // Pass reply context if available
      const replyContext = replyMessage ? replyMessage.text : undefined;
      const response = await getChatResponse(messages, textToSend, replyContext);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.reply,
        translation: response.translation,
        correction: response.correction,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      onXpUpdate(5);

      // Auto play audio ONLY if in VOICE mode
      if (sourceMode === 'VOICE') {
        playAudio(response.reply);
      }

    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      try {
        recognitionRef.current?.start();
      } catch (e) {
        console.error(e);
        setIsListening(false);
      }
    }
  };

  const playAudio = (text: string) => {
    synthRef.current.cancel(); // Stop previous audio
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'ja-JP';
    utterance.rate = 0.9; // Slightly slower for learning
    synthRef.current.speak(utterance);
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setActiveMessageId(null);
  };

  const handleReply = (msg: ChatMessage) => {
    setReplyMessage(msg);
    setActiveMessageId(null);
    setChatMode('TEXT'); // Switch to text mode for replying
  };

