                    exit={{ opacity: 0, scale: 0.9 }}
                    className="flex flex-col items-center justify-center py-2"
                >
                    <p className="text-xs text-gray-400 mb-4 font-medium tracking-wide uppercase">
                        {isListening ? 'ώ╗ηόΥΛίΒεόφλϊ╕ούβ╝ώΑΒ' : 'ώ╗ηόΥΛώΨΜίπΜϋςςϋσ▒'}
                    </p>
                    <button 
                        onClick={toggleListening}
                        disabled={isLoading}
                        className={`relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg ${
                            isLoading 
                             ? 'bg-gray-200 cursor-wait'
                             : isListening 
                                ? 'bg-red-500 text-white shadow-red-200 scale-110' 
                                : 'bg-white text-pink-600 border-2 border-pink-100 hover:border-pink-200 hover:shadow-xl'
