                    >
                        {/* Ripple Effect when listening */}
                        {isListening && (
                            <>
                                <span className="absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-20 animate-ping"></span>
                                <span className="absolute inline-flex h-[120%] w-[120%] rounded-full bg-red-400 opacity-10 animate-pulse"></span>
                            </>
                        )}

                        {isListening ? (
                             <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8">
                                <path fillRule="evenodd" d="M4.5 7.5a3 3 0 013-3h9a3 3 0 013 3v9a3 3 0 01-3 3h-9a3 3 0 01-3-3v-9z" clipRule="evenodd" />
                             </svg>
                        ) : (
                            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className={`w-8 h-8 ${isLoading ? 'text-gray-400' : ''}`}>
                                <path d="M8.25 4.5a3.75 3.75 0 117.5 0v8.25a3.75 3.75 0 11-7.5 0V4.5z" />
                                <path d="M6 10.5a.75.75 0 01.75.75v1.5a5.25 5.25 0 1010.5 0v-1.5a.75.75 0 011.5 0v1.5a6.751 6.751 0 01-6 6.709v2.291h3a.75.75 0 010 1.5h-7.5a.75.75 0 010-1.5h3v-2.291a6.751 6.751 0 01-6-6.709v-1.5A.75.75 0 016 10.5z" />
                            </svg>
                        )}
                    </button>
                    {isListening && inputText && (
                         <div className="mt-4 px-4 py-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm max-w-[80%]">
                             <p className="text-gray-600 text-sm text-center line-clamp-2">{inputText}</p>
                         </div>
                    )}
                </motion.div>
            )}
         </AnimatePresence>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChatMessage } from '../types';
import { getChatResponse } from '../services/geminiService';

interface ChatInterfaceProps {
  onBack: () => void;
  onXpUpdate: (amount: number) => void;
}

type ChatMode = 'TEXT' | 'VOICE';

const STORAGE_KEY = 'mk-nihongo-chat-history';

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onBack, onXpUpdate }) => {
  // Initialize messages from localStorage or use default welcome message
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    try {
      const savedMessages = localStorage.getItem(STORAGE_KEY);
      if (savedMessages) {
        return JSON.parse(savedMessages);
      }
    } catch (error) {
      console.error("Failed to load chat history:", error);
    }

    return [{
      id: 'welcome',
      role: 'model',
      text: 'ήΒΥήΓΥήΒτήΒκήΒψΎ╝ΒήΒΛίΖΔό░ΩήΒπήΒβήΒΜΎ╝θϊ╜ΧήΒΜϋσ▒ήΒΩήΒ╛ήΒΩήΓΘήΒΗΎ╝Β',
      translation: 'ϊ╜ιίξ╜Ύ╝Βϊ╜ιίξ╜ίΩΟΎ╝θόΙΣίΑΣϊ╛ΗϋΒΛϋΒΛίνσίΡπΎ╝Β',
      timestamp: Date.now()
    }];
  });

  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [chatMode, setChatMode] = useState<ChatMode>('TEXT');
  const [activeMessageId, setActiveMessageId] = useState<string | null>(null); // For showing options menu
  const [replyMessage, setReplyMessage] = useState<ChatMessage | null>(null); // For context replying

  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  // Refs for speech logic to avoid stale closures
  const transcriptRef = useRef('');
  const isManualStop = useRef(false);
  const handleSendRef = useRef<any>(null);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  // Auto scroll to bottom only in text mode
  useEffect(() => {
    if (chatMode === 'TEXT' && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isListening, chatMode, replyMessage]);

  const handleSend = async (textOverride?: string, sourceMode: ChatMode = chatMode) => {
    const textToSend = textOverride || inputText;
    if (!textToSend.trim()) return;

    // Stop listening if sending manually (though handleSend is usually called AFTER stop in voice mode)
    if (isListening) recognitionRef.current?.stop();

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setReplyMessage(null); // Clear reply state
    setIsLoading(true);

    try {
      // Pass reply context if available
      const replyContext = replyMessage ? replyMessage.text : undefined;
      const response = await getChatResponse(messages, textToSend, replyContext);

      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.reply,
        translation: response.translation,
        correction: response.correction,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, aiMsg]);
      onXpUpdate(5);

      // Auto play audio ONLY if in VOICE mode
      if (sourceMode === 'VOICE') {
        playAudio(response.reply);
      }

    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  // Keep ref updated
  useEffect(() => {
    handleSendRef.current = handleSend;
  }, [handleSend]);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();
      recognitionRef.current = recognition;

      // Continuous = true improves accuracy by providing more context and allows "Click to Stop" flow
      recognition.continuous = true;
      recognition.lang = 'ja-JP'; 
      recognition.interimResults = true;

      recognition.onresult = (event: any) => {
        let fullTranscript = '';
        // With continuous=true, we need to reconstruct the full transcript from all results
        for (let i = 0; i < event.results.length; ++i) {
          fullTranscript += event.results[i][0].transcript;
        }

        transcriptRef.current = fullTranscript;
        setInputText(fullTranscript);
      };

      recognition.onerror = (event: any) => {
        console.error("Speech error", event);
        setIsListening(false);
        isManualStop.current = false;
      };

      recognition.onend = () => {
        setIsListening(false);
        // Only send if it was a manual stop (user clicked button) and we have text
        if (isManualStop.current && transcriptRef.current.trim()) {
           handleSendRef.current(transcriptRef.current, 'VOICE');
        }
        isManualStop.current = false;
      };
    }

    return () => {
        if(recognitionRef.current) recognitionRef.current.stop();
        synthRef.current.cancel();
    }
  }, [chatMode]);

  const toggleListening = () => {
    if (isListening) {
      // User clicked stop
      isManualStop.current = true;
      recognitionRef.current?.stop();
    } else {
      // User clicked start
      isManualStop.current = false;
      transcriptRef.current = '';
      setInputText('');
      try {
        recognitionRef.current?.start();
        setIsListening(true);
      } catch (e) {
        console.error(e);
        setIsListening(false);
      }
    }
  };

  const playAudio = (text: string) => {
    synthRef.current.cancel(); // Stop previous audio
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'ja-JP';
    utterance.rate = 0.9; // Slightly slower for learning
    synthRef.current.speak(utterance);
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setActiveMessageId(null);
  };

  const handleReply = (msg: ChatMessage) => {
    setReplyMessage(msg);
    setActiveMessageId(null);
    setChatMode('TEXT'); // Switch to text mode for replying
  };

  const handleRegenerateUser = (text: string) => {
    setInputText(text);
    setActiveMessageId(null);
    setChatMode('TEXT');
  };

  // Get last AI message for Voice Mode display context
  const lastAiMessage = [...messages].reverse().find(m => m.role === 'model');

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] max-h-[800px] bg-gray-100 rounded-3xl overflow-hidden shadow-xl border border-gray-200 relative">
      {/* Chat Header */}
      <div className="bg-white/90 backdrop-blur p-4 border-b border-gray-200 flex justify-between items-center z-10 sticky top-0">
        <div className="flex items-center gap-3">
          <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full text-gray-500">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
              <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
            </svg>
          </button>
          <div>
            <h3 className="font-bold text-gray-800">AI ϋςηϊ╝┤</h3>
            <div className="flex items-center gap-1.5">
                <span className={`w-2 h-2 rounded-full ${isLoading ? 'bg-yellow-400 animate-pulse' : 'bg-green-500'}`}></span> 
                <span className="text-xs text-gray-500">{isLoading ? 'όΑζϋΑΔϊ╕φ...' : 'Online'}</span>
            </div>
          </div>
        </div>

        {/* Mode Switcher */}
        <div className="flex bg-gray-100 p-1 rounded-lg">
             <button 
               onClick={() => setChatMode('TEXT')}
               className={`p-2 rounded-md transition-all ${chatMode === 'TEXT' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-400'}`}
               title="Text Chat"
             >
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-4 h-4">
                    <path fillRule="evenodd" d="M3 6a3 3 0 013-3h12a3 3 0 013 3v12a3 3 0 01-3 3H6a3 3 0 01-3-3V6zm14.25 6a.75.75 0 01-.22.53l-2.25 2.25a.75.75 0 11-1.06-1.06L15.44 12l-1.72-1.72a.75.75 0 111.06-1.06l2.25 2.25c.141.14.22.331.22.53zm-10.28 0a.75.75 0 01.22-.53l2.25-2.25a.75.75 0 111.06 1.06L8.56 12l1.72 1.72a.75.75 0 11-1.06 1.06l-2.25-2.25a.75.75 0 01-.22-.53z" clipRule="evenodd" />
                </svg>
             </button>
             <button 
               onClick={() => setChatMode('VOICE')}
               className={`p-2 rounded-md transition-all ${chatMode === 'VOICE' ? 'bg-white shadow-sm text-pink-600' : 'text-gray-400'}`}
               title="Voice Chat"
             >
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-4 h-4">
                    <path d="M8.25 4.5a3.75 3.75 0 117.5 0v8.25a3.75 3.75 0 11-7.5 0V4.5z" />
                    <path d="M6 10.5a.75.75 0 01.75.75v1.5a5.25 5.25 0 1010.5 0v-1.5a.75.75 0 011.5 0v1.5a6.751 6.751 0 01-6 6.709v2.291h3a.75.75 0 010 1.5h-7.5a.75.75 0 010-1.5h3v-2.291a6.751 6.751 0 01-6-6.709v-1.5A.75.75 0 016 10.5z" />
                </svg>
             </button>
        </div>
      </div>

      {chatMode === 'TEXT' ? (
        <>
          {/* Messages Area - Only for TEXT */}
          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto p-4 space-y-6 bg-gray-50/50"
            onClick={() => setActiveMessageId(null)}
          >
            {messages.map((msg) => {
              const isUser = msg.role === 'user';
              const isActive = activeMessageId === msg.id;

              return (
                <div 
                  key={msg.id} 
                  className={`flex flex-col w-full ${isUser ? 'items-end' : 'items-start'}`}
                >
                  <div 
                    className={`flex max-w-[85%] md:max-w-[75%] gap-2 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}
                    onClick={(e) => {
                        e.stopPropagation();
                        setActiveMessageId(isActive ? null : msg.id);
                    }}
                  >
                    {/* Avatar */}
                    <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center text-xs font-bold shadow-sm ${isUser ? 'bg-indigo-600 text-white' : 'bg-white text-gray-800'}`}>
                      {isUser ? 'Me' : 'AI'}
                    </div>

                    <div className="flex flex-col gap-1 cursor-pointer">
                      {/* Message Bubble */}
                      <div className={`p-3.5 rounded-2xl text-[15px] leading-relaxed relative group shadow-sm transition-all ${
                        isUser 
                          ? 'bg-indigo-600 text-white rounded-tr-none' 
                          : 'bg-white text-gray-800 rounded-tl-none border border-gray-100'
                      } ${isActive ? 'ring-2 ring-offset-1 ring-indigo-200' : ''}`}>
                        {msg.text}

                        {/* Manual Audio Button (AI Only) */}
                        {!isUser && (
                            <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    playAudio(msg.text);
                                }}
                                className="absolute -right-10 top-2 p-2 text-gray-400 hover:text-indigo-600 bg-white hover:bg-gray-50 rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-4 h-4">
                                    <path d="M13.5 4.06c0-1.336-1.616-2.005-2.56-1.06l-4.5 4.5H4.508c-1.141 0-2.318.664-2.66 1.905A9.76 9.76 0 001.5 12c0 .898.121 1.768.35 2.595.341 1.24 1.518 1.905 2.659 1.905h1.93l4.5 4.5c.945.945 2.561.276 2.561-1.06V4.06zM18.584 5.106a.75.75 0 011.06 0c3.808 3.807 3.808 9.98 0 13.788a.75.75 0 11-1.06-1.06 8.25 8.25 0 000-11.668.75.75 0 010-1.06z" />
                                    <path d="M15.932 7.757a.75.75 0 011.061 0 6 6 0 010 8.486.75.75 0 01-1.06-1.061 4.5 4.5 0 000-6.364.75.75 0 010-1.06z" />
                                </svg>
                            </button>
                        )}
                      </div>

                      {/* Corrections & Translations (AI Only) */}
                      {!isUser && (
                        <div className="pl-1 space-y-2">
                          {msg.correction && (
                            <motion.div 
                              initial={{ opacity: 0, height: 0 }} 
                              animate={{ opacity: 1, height: 'auto' }}
                              className="text-xs bg-red-50 text-red-600 p-2.5 rounded-lg border border-red-100 inline-block"
                            >
                              <span className="font-bold block mb-1">ΏθΤκ ί╗║ϋφ░ϊ┐χόφμ:</span>
                              {msg.correction}
                            </motion.div>
                          )}
                          {msg.translation && (
                            <p className="text-xs text-gray-400 font-medium ml-1">
                              {msg.translation}
                            </p>
                          )}
                        </div>
                      )}

                      {/* Timestamp & Meta */}
                      <div className="flex justify-between items-center px-1 mt-1">
                        <span className="text-[10px] text-gray-300">
                          {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Message Options Menu */}
                  <AnimatePresence>
                    {isActive && (
                      <motion.div 
                        initial={{ opacity: 0, y: -10, scale: 0.95 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: -10, scale: 0.95 }}
                        className={`mt-2 bg-white rounded-xl shadow-lg border border-gray-100 p-1 flex gap-1 z-20 ${isUser ? 'mr-10' : 'ml-10'}`}
                      >
                        <button 
                          onClick={() => handleReply(msg)}
                          className="px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-gray-100 rounded-lg flex items-center gap-1"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-3 h-3">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M9 15L3 9m0 0l6-6M3 9h12a6 6 0 010 12h-3" />
                          </svg>
                          ίδηϋοΗ
                        </button>

                        {isUser && (
                            <button 
                                onClick={() => handleRegenerateUser(msg.text)}
                                className="px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-gray-100 rounded-lg flex items-center gap-1"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-3 h-3">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
                                </svg>
                                ώΘΞόΨ░ύΦθόΙΡ
                            </button>
                        )}

                        <button 
                          onClick={() => handleCopy(msg.text)}
                          className="px-3 py-1.5 text-xs font-medium text-gray-600 hover:bg-gray-100 rounded-lg flex items-center gap-1"
                        >
                          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-3 h-3">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 17.25v3.375c0 .621-.504 1.125-1.125 1.125h-9.75a1.125 1.125 0 01-1.125-1.125V7.875c0-.621.504-1.125 1.125-1.125H6.75a9.06 9.06 0 011.5.124m7.5 10.376h3.375c.621 0 1.125-.504 1.125-1.125V11.25c0-4.46-3.243-8.161-7.5-8.876a9.06 9.06 0 00-1.5-.124H9.375c-.621 0-1.125.504-1.125 1.125v3.5m7.5 10.375H9.375a1.125 1.125 0 01-1.125-1.125v-9.25m12 6.625v-1.875a3.375 3.375 0 00-3.375-3.375h-1.5" />
                          </svg>
                          ϋνΘϋμ╜
                        </button>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              );
            })}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-100 rounded-full px-4 py-3 flex space-x-1.5 shadow-sm">
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                </div>
              </div>
            )}
          </div>

          {/* Input Area - Only for TEXT */}
          <div className="bg-white border-t border-gray-200 p-4 transition-all duration-300">
             {/* Reply Preview */}
             <AnimatePresence>
                {replyMessage && (
                   <motion.div 
                     initial={{ opacity: 0, height: 0 }}
                     animate={{ opacity: 1, height: 'auto' }}
                     exit={{ opacity: 0, height: 0 }}
                     className="flex justify-between items-center bg-gray-100 border-l-4 border-indigo-500 rounded-md p-2 mb-2 text-sm"
                   >
                      <div className="flex flex-col">
                         <span className="text-[10px] font-bold text-gray-500 uppercase">
                            Replying to {replyMessage.role === 'user' ? 'Me' : 'AI'}
                         </span>
                         <span className="text-gray-700 line-clamp-1">{replyMessage.text}</span>
                      </div>
                      <button 
                         onClick={() => setReplyMessage(null)}
                         className="text-gray-400 hover:text-gray-600 p-1"
                      >
                         <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                         </svg>
                      </button>
                   </motion.div>
                )}
             </AnimatePresence>

            <div className="flex items-end gap-2 bg-gray-50 rounded-2xl border border-gray-200 p-2 focus-within:ring-2 focus-within:ring-indigo-100 focus-within:border-indigo-300 transition-all">
                <textarea
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === 'Enter' && !e.shiftKey) {
                            e.preventDefault();
                            handleSend();
                        }
                    }}
                    placeholder="ϋ╝╕ίΖξόΩξόΨΘϋρΛόΒψ..."
                    className="flex-1 bg-transparent border-none focus:ring-0 outline-none text-sm py-2 px-3 max-h-24 resize-none placeholder-gray-400 text-gray-800"
                    rows={1}
                    style={{ minHeight: '44px' }}
                />
                <button 
                    onClick={() => handleSend()}
                    disabled={!inputText.trim() || isLoading}
                    className={`p-2.5 rounded-xl mb-0.5 ${inputText.trim() ? 'bg-indigo-600 text-white shadow-md hover:bg-indigo-700' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 transform -rotate-45 translate-x-0.5 -translate-y-0.5">
                        <path d="M3.478 2.405a.75.75 0 00-.926.94l2.432 7.905H13.5a.75.75 0 010 1.5H4.984l-2.432 7.905a.75.75 0 00.926.94 60.519 60.519 0 0018.445-8.986.75.75 0 000-1.218A60.517 60.517 0 003.478 2.405z" />
                    </svg>
                </button>
            </div>
          </div>
        </>
      ) : (
        /* Voice Mode UI - Centered Recording Button */
        <div className="flex-1 flex flex-col items-center justify-center bg-gray-50/50 p-6 relative">
             {/* Context / Last Message Display */}
             <div className="absolute top-10 left-0 right-0 px-6 text-center z-10">
                {lastAiMessage && !isListening && !inputText && (
                    <motion.div 
                        initial={{ opacity: 0, y: -20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="bg-white p-6 rounded-3xl shadow-lg border border-gray-100 inline-block max-w-md"
                    >
                        <p className="text-gray-800 font-bold text-lg mb-2">{lastAiMessage.text}</p>
                        {lastAiMessage.translation && <p className="text-gray-400 text-sm">{lastAiMessage.translation}</p>}
                    </motion.div>
                )}
             </div>

             {/* Live Transcript Display */}
             <div className="h-40 flex items-center justify-center w-full max-w-lg mb-8 relative z-10">
                 <AnimatePresence mode="wait">
                     {inputText ? (
                        <motion.p 
                            key="transcript"
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -20 }}
                            className="text-2xl font-bold text-gray-800 text-center leading-relaxed px-4"
                        >
                            "{inputText}"
                        </motion.p>
                     ) : (
                        isListening && (
                            <motion.p 
                                key="listening"
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                exit={{ opacity: 0 }}
                                className="text-gray-400 animate-pulse text-xl font-medium"
                            >
                                όφμίερϋΒΗϋΒ╜...
                            </motion.p>
                        )
                     )}
                 </AnimatePresence>
             </div>

             {/* Centered Button */}
             <div className="relative z-20">
                 <button 
                    onClick={toggleListening}
                    disabled={isLoading}
                    className={`relative w-32 h-32 rounded-full flex items-center justify-center transition-all duration-300 shadow-xl ${
                        isLoading 
