                >
                    {/* Animations for listening state */}
                    {isListening && (
                        <>
                            <span className="absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-20 animate-ping"></span>
                            <span className="absolute inline-flex h-[140%] w-[140%] rounded-full bg-red-400 opacity-10 animate-pulse"></span>
                        </>
                    )}

                    {isLoading ? (
                        <div className="flex space-x-1.5">
                            <div className="w-2.5 h-2.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                            <div className="w-2.5 h-2.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                            <div className="w-2.5 h-2.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                        </div>
                    ) : isListening ? (
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-12 h-12">
                            <path fillRule="evenodd" d="M4.5 7.5a3 3 0 013-3h9a3 3 0 013 3v9a3 3 0 01-3 3h-9a3 3 0 01-3-3v-9z" clipRule="evenodd" />
                        </svg>
                    ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-12 h-12 ml-1">
                            <path d="M8.25 4.5a3.75 3.75 0 117.5 0v8.25a3.75 3.75 0 11-7.5 0V4.5z" />
                            <path d="M6 10.5a.75.75 0 01.75.75v1.5a5.25 5.25 0 1010.5 0v-1.5a.75.75 0 011.5 0v1.5a6.751 6.751 0 01-6 6.709v2.291h3a.75.75 0 010 1.5h-7.5a.75.75 0 010-1.5h3v-2.291a6.751 6.751 0 01-6-6.709v-1.5A.75.75 0 016 10.5z" />
                        </svg>
                    )}
                </button>
            </div>

            <p className="mt-8 text-gray-400 font-bold tracking-widest text-sm uppercase">
                {isLoading ? 'όΑζϋΑΔϊ╕φ...' : isListening ? 'ώ╗ηόΥΛίΒεόφλ' : 'ώ╗ηόΥΛώΨΜίπΜ'}
            </p>
        </div>
      )}
    </div>
  );
};

export interface SentenceWord {
  word: string;
  reading: string;
  meaning: string;
}

export interface WordDefinition {
  word: string;
  reading: string;
  meaning: string;
  exampleSentence: string;
  exampleReading?: string; // Hiragana reading of the example sentence
  exampleTranslation: string;
  sentenceBreakdown?: SentenceWord[]; // Detailed breakdown of words in the sentence
}

export interface GrammarExample {
  sentence: string;
  reading: string;
  translation: string;
}

export interface GrammarDefinition {
  id: string; // unique internal id
  grammarPoint: string; // e.g., Ύ╜ηήΒοήΒψήΒΕήΒΣήΒςήΒΕ
  connection: string; // e.g., Verb Te-form
  meaning: string;
  explanation: string;
  examples: GrammarExample[];
}

export interface AnalyzedToken {
  text: string; // The word as it appears
  dictionaryForm: string;
  reading: string;
  meaning: string;
  jlpt: 'N5' | 'N4' | 'N3' | 'N2' | 'N1' | 'Unknown';
  type: 'VOCAB' | 'GRAMMAR';
  // New fields for the Word Card feature
  exampleSentence?: string;
  exampleReading?: string;
  exampleTranslation?: string;
}

export interface ReadingMaterial {
  id: string;
  title: string;
  content: string; // Japanese text
  translation: string; // Chinese translation
  tokens: AnalyzedToken[]; // List of extracted vocab/grammar
}

export interface DailyRecord {
  id: string;
  date: string; // ISO Date string YYYY-MM-DD
  words: WordDefinition[];
  grammar?: GrammarDefinition[];
  readings?: ReadingMaterial[];
}

export interface QuizQuestion {
  id: string;
  context?: string; // For reading passages or additional context
  question: string; // Could be the word or the meaning
  options: string[]; // 4 options
  correctAnswerIndex: number;
  explanation: string;
}

