import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { generateQuizFromContent } from '../services/geminiService';
import { WordDefinition, GrammarDefinition, QuizQuestion } from '../types';
import { Loader } from './Loader';
import { Button } from './Button';

interface QuizProps {
  sourceWords: WordDefinition[];
  sourceGrammar: GrammarDefinition[];
  onExit: () => void;
  title?: string;
}

export const Quiz: React.FC<QuizProps> = ({ sourceWords, sourceGrammar, onExit, title }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  // Store user answers: index is question index, value is selected option index
  const [userAnswers, setUserAnswers] = useState<(number | null)[]>([]);
  const [showResult, setShowResult] = useState(false);
  const [selectedReviewIndex, setSelectedReviewIndex] = useState<number | null>(null);

  useEffect(() => {
    const loadQuiz = async () => {
      try {
        const qs = await generateQuizFromContent(sourceWords, sourceGrammar);
        setQuestions(qs);
        setUserAnswers(new Array(qs.length).fill(null));
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    loadQuiz();
  }, [sourceWords, sourceGrammar]);

  const handleAnswer = (optionIndex: number) => {
    if (userAnswers[currentIndex] !== null) return; // Prevent change

    const newAnswers = [...userAnswers];
    newAnswers[currentIndex] = optionIndex;
    setUserAnswers(newAnswers);

    setTimeout(() => {
      if (currentIndex < questions.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        setShowResult(true);
      }
    }, 1200); // Slightly longer delay to let user see the correct answer
  };

  const calculateScore = () => {
    return userAnswers.reduce((acc, ans, idx) => {
      return acc + (ans === questions[idx].correctAnswerIndex ? 1 : 0);
    }, 0);
  };

  if (loading) {
    return <div className="h-64 flex items-center justify-center"><Loader text="ίΘ║ώκΝϊ╕φ..." /></div>;
  }

  if (questions.length === 0) {
    return (
      <div className="text-center p-8">
        <p className="text-gray-500 mb-4">ύΕκό│ΧύΦλύΦθό╕υώσΩΎ╝ΝϋτΜίΖΙίαΩϋσοίφ╕ύ┐Τϊ╕Αϊ║δίΖπίχ╣ήΑΓ</p>
        <Button onClick={onExit}>ϋ┐Φίδη</Button>
      </div>
    );
  }

  // --- RESULT / REVIEW VIEW ---
  if (showResult) {
    const score = calculateScore();

    return (
      <>
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="max-w-3xl mx-auto pb-20"
        >
          <div className="text-center mb-10">
            <h2 className="text-3xl font-bold text-gray-800 mb-2">ό╕υώσΩύ╡Ρόζθ</h2>
            <div className="text-5xl font-black text-gray-900 mb-4">
              {score} <span className="text-2xl text-gray-400 font-normal">/ {questions.length}</span>
            </div>
            <p className="text-gray-500 mb-6">ώ╗ηόΥΛϊ╕ΜόΨ╣ώκΝύδχόθξύεΜϋσ│ύ┤░ϋπμόηΡήΑΓ</p>
            <Button onClick={onExit} variant="primary">ίδηίΙ░ώοΨώιΒ</Button>
          </div>

          <div className="grid gap-4">
            {questions.map((q, idx) => {
              const isCorrect = userAnswers[idx] === q.correctAnswerIndex;
              return (
                <motion.div
                  layoutId={`question-card-${idx}`}
                  key={q.id}
                  onClick={() => setSelectedReviewIndex(idx)}
                  className={`bg-white p-5 rounded-xl border cursor-pointer transition-all hover:shadow-md ${
                    isCorrect ? 'border-gray-200 hover:border-green-200' : 'border-red-100 hover:border-red-200 bg-red-50/30'
                  }`}
                >
                  <div className="flex items-start gap-4">
                    <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${
                      isCorrect ? 'bg-gray-800 text-white' : 'bg-red-500 text-white'
                    }`}>
                      {idx + 1}
                    </div>
                    <div className="flex-1">
                       {q.context && (
                         <p className="text-xs text-gray-400 mb-1 line-clamp-1">{q.context}</p>
                       )}
                       <h4 className="text-gray-800 font-medium mb-1 line-clamp-1">{q.question}</h4>
                       <div className="flex items-center text-sm gap-2">
                          <span className={`px-2 py-0.5 rounded text-xs font-semibold ${isCorrect ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                            {isCorrect ? 'όφμϋπμ' : 'ώΝψϋςν'}
                          </span>
                          {!isCorrect && (
                            <span className="text-gray-400 text-xs">όφμύλ║ύφΦόκΙ: {q.options[q.correctAnswerIndex]}</span>
                          )}
                       </div>
                    </div>
                    <div className="text-gray-400">
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                      </svg>
                    </div>
                  </div>
                </motion.div>
              );
            })}
          </div>
        </motion.div>

        {/* EXPANDED REVIEW CARD OVERLAY */}
        <AnimatePresence>
          {selectedReviewIndex !== null && (
            <motion.div 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 1 }} 
              exit={{ opacity: 0 }} 
              className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-sm"
              onClick={() => setSelectedReviewIndex(null)}
            >
              <motion.div 
                layoutId={`question-card-${selectedReviewIndex}`}
                className="w-full max-w-2xl bg-white rounded-2xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col"
                onClick={(e) => e.stopPropagation()}
              >
                 {/* Header */}
                 <div className="p-6 border-b border-gray-100 flex justify-between items-start bg-gray-50">
                    <div>
                      <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Question {selectedReviewIndex + 1}</span>
                      <h3 className="text-xl font-bold text-gray-800 mt-1">ώκΝύδχίδηώκπ</h3>
                    </div>
                    <button 
                      onClick={() => setSelectedReviewIndex(null)}
                      className="p-2 bg-white rounded-full text-gray-400 hover:text-gray-600 shadow-sm hover:shadow transition-all"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                 </div>

                 {/* Scrollable Content */}
                 <div className="p-8 overflow-y-auto no-scrollbar">
                    {questions[selectedReviewIndex].context && (
                      <div className="mb-6 p-4 bg-gray-50 border-l-4 border-gray-300 rounded-r-lg text-gray-800 text-lg leading-relaxed">
                        {questions[selectedReviewIndex].context}
                      </div>
                    )}

                    <h4 className="text-xl font-medium text-gray-900 mb-6">
                      {questions[selectedReviewIndex].question}
                    </h4>

                    <div className="space-y-3 mb-8">
                      {questions[selectedReviewIndex].options.map((opt, i) => {
                        const isSelected = userAnswers[selectedReviewIndex] === i;
                        const isCorrect = questions[selectedReviewIndex].correctAnswerIndex === i;

                        let style = "border-gray-200 text-gray-500";
                        if (isCorrect) style = "border-green-500 bg-green-50 text-green-800 font-bold";
                        else if (isSelected && !isCorrect) style = "border-red-500 bg-red-50 text-red-800";

                        return (
                          <div key={i} className={`p-4 border-2 rounded-lg flex justify-between items-center ${style}`}>
                            <span>{opt}</span>
                            {isCorrect && (
                              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                              </svg>
                            )}
                            {isSelected && !isCorrect && (
                              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                              </svg>
                            )}
                          </div>
                        );
                      })}
                    </div>

                    <div className="bg-gray-50 p-6 rounded-xl">
                      <h5 className="text-sm font-bold text-gray-500 uppercase tracking-wide mb-2">ϋπμόηΡ</h5>
                      <p className="text-gray-700 leading-relaxed">
                        {questions[selectedReviewIndex].explanation}
                      </p>
                    </div>
                 </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </>
    );
  }

  // --- ACTIVE QUIZ VIEW ---
  const currentQ = questions[currentIndex];
  const currentSelected = userAnswers[currentIndex];

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-6 flex items-center justify-between">
        <h2 className="text-xl font-bold text-gray-700">{title || "ό╕υώσΩόβΓώΨΥ"}</h2>
        <span className="text-sm font-medium text-gray-500 bg-gray-200 px-3 py-1 rounded-full">
          {currentIndex + 1} / {questions.length}
        </span>
      </div>

      <div className="relative min-h-[400px]">
        <AnimatePresence mode="wait">
          <motion.div
            key={currentQ.id}
            initial={{ x: 50, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -50, opacity: 0 }}
            transition={{ duration: 0.3 }}
            className="bg-white rounded-xl shadow-md p-8 border border-gray-100"
          >
            {/* Context/Reading - Removed Italic, Improved Typography */}
            {currentQ.context && (
              <div className="mb-6 p-5 bg-gray-50 border-l-4 border-gray-400 text-gray-800 leading-relaxed rounded-r-lg text-lg">
                {currentQ.context}
              </div>
            )}

            <h3 className="text-xl font-semibold text-gray-800 mb-8 leading-snug">{currentQ.question}</h3>

            <div className="grid gap-4">
              {currentQ.options.map((option, idx) => {
                const isSelected = currentSelected === idx;
                const isCorrect = idx === currentQ.correctAnswerIndex;
                const hasAnswered = currentSelected !== null;

                // Base style
                let btnClass = "bg-white border-2 border-gray-100 shadow-sm text-gray-700";

                if (hasAnswered) {
                  if (isCorrect) {
                    // Always highlight correct answer in green, whether user picked it or not
                    btnClass = "bg-green-50 border-green-500 text-green-800 font-bold shadow-md";
                  } else if (isSelected) {
                    // Highlight wrong selection in red
                    btnClass = "bg-red-50 border-red-400 text-red-800";
                  } else {
                    // Fade out other options
                     btnClass = "opacity-40 border-transparent bg-gray-50";
                  }
                } else {
                    // Idle state (not answered yet)
                    btnClass += " hover:border-indigo-300 hover:bg-gray-50 hover:shadow-md";
                }

                return (
                  <motion.button
                    key={idx}
                    onClick={() => handleAnswer(idx)}
                    className={`w-full text-left p-4 rounded-xl font-medium transition-colors duration-200 relative overflow-hidden ${btnClass}`}
                    disabled={hasAnswered}
                    whileHover={!hasAnswered ? { y: -2 } : {}}
                    whileTap={!hasAnswered ? { scale: 0.97 } : {}}
                    layout
                  >
                    <div className="flex justify-between items-center relative z-10">
                        <span className="text-lg">{option}</span>
                        {hasAnswered && isCorrect && (
                            <motion.span 
                                initial={{ scale: 0 }}
                                animate={{ scale: 1 }}
                                className="text-green-600 bg-green-100 rounded-full p-1"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5">
                                <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
                                </svg>
                            </motion.span>
                        )}
                         {hasAnswered && isSelected && !isCorrect && (
                            <motion.span 
                                initial={{ scale: 0 }}
                                animate={{ scale: 1 }}
                                className="text-red-500 bg-red-100 rounded-full p-1"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5">
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                                </svg>
                            </motion.span>
                        )}
                    </div>
                  </motion.button>
                );
              })}
            </div>
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
};

