    description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10',
    icon: 'ΏθΣΣ',
    condition: (stats) => stats.level >= 10
  }
];

const INITIAL_PET_STATS: PetStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  totalFocusMinutes: 0,
  mood: 'neutral',
  unlockedAchievements: []
};

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [history, setHistory] = useState<DailyRecord[]>([]);

  // Learning Method States
  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);

  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);

  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);

  // Selection states for overlays
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);

  // History accordion state
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);

  // Pet State
  const [petStats, setPetStats] = useState<PetStats>(INITIAL_PET_STATS);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);

  // Global Timer State
  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });
  const [showCelebration, setShowCelebration] = useState(false);

  // Load data from local storage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('mk-nihongo-history');
    if (savedHistory) {
      try {
        setHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }

    const savedPet = localStorage.getItem('mk-nihongo-pet');
    if (savedPet) {
      try {
        const parsed = JSON.parse(savedPet);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        setPetStats(parsed);
      } catch (e) {
        console.error("Failed to parse pet stats", e);
      }
    }
  }, []);

  // Save data whenever it changes
  useEffect(() => {
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
  }, [petStats]);

  // Global Timer Tick Logic (Robust Background Support)
  useEffect(() => {
    let interval: number | null = null;

    if (timerState.isActive && timerState.endTime) {
      // Run interval more frequently to update UI, but calculate based on endTime timestamp
      interval = window.setInterval(() => {
        const now = Date.now();
        // Calculate remaining seconds based on wall-clock time
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);

        if (newTimeLeft <= 0) {
          // Timer finished
          handleTimerComplete();
        } else {
           // Update UI if the second has changed
           setTimerState(prev => {
             if (prev.timeLeft === newTimeLeft) return prev;
             return { ...prev, timeLeft: newTimeLeft };
           });
        }
      }, 200); 
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [timerState.isActive, timerState.endTime]);

  // Sync pet mood with timer
  useEffect(() => {
    if (timerState.isActive && timerState.mode === 'FOCUS') {
      setPetStats(prev => ({ ...prev, mood: 'focus' }));
    } else if (!timerState.isActive && petStats.mood === 'focus') {
      setPetStats(prev => ({ ...prev, mood: 'neutral' }));
    }
  }, [timerState.isActive, timerState.mode]);

  // Check achievements logic
  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });

    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({
        ...prev,
        unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked]
      }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  // Calculate learning totals
  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;

      if (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }

      return {
        ...prev,
        level: newLevel,
        currentXp: newXp,
        nextLevelXp: nextXp,
        totalFocusMinutes: prev.totalFocusMinutes + minutes,
        mood: 'happy'
      };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);

    // Clear previous results based on mode
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') {
          newWords = await fetchWordDefinitions(input);
          setCurrentDefinitions(newWords);
        } else if (inputMode === 'GRAMMAR') {
          newGrammar = await fetchGrammarDetails(input);
          setCurrentGrammar(newGrammar);
        } else if (inputMode === 'READING') {
          newReading = await analyzeReadingText(input);
          setCurrentReading(newReading);
        }
      } else {
        // Recommendations
        let excludedWords: string[] = [];
        let excludedGrammar: string[] = [];
        history.forEach(rec => {
          if (rec.words) excludedWords.push(...rec.words.map(w => w.word));
          if (rec.grammar) excludedGrammar.push(...rec.grammar.map(g => g.grammarPoint));
        });

        if (inputMode === 'WORD') {
          newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords);
          setCurrentDefinitions(newWords);
        } else if (inputMode === 'GRAMMAR') {
          newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar);
          setCurrentGrammar(newGrammar);
        } else if (inputMode === 'READING') {
          newReading = await generateRecommendedReading(selectedLevel);
          setCurrentReading(newReading);
        }
      }

      const today = new Date().toISOString().split('T')[0];
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          const existingRecord = newHistory[existingIndex];
          newHistory[existingIndex] = {
            ...existingRecord,
            words: [...(newWords || []), ...(existingRecord.words || [])],
            grammar: [...(newGrammar || []), ...(existingRecord.grammar || [])],
            readings: newReading ? [newReading, ...(existingRecord.readings || [])] : existingRecord.readings
          };
          return newHistory;
        } else {
          return [{ 
             id: Date.now().toString(), 
             date: today, 
             words: newWords || [], 
             grammar: newGrammar || [],
             readings: newReading ? [newReading] : []
          }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      updatePetXp(10);
    } catch (error) {
      alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ");
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const startQuiz = (words: WordDefinition[], grammar: GrammarDefinition[] = [], title?: string) => {
    setQuizConfig({ sourceWords: words, sourceGrammar: grammar, dateLabel: title });
    setMode(AppMode.QUIZ);
  };

  const handleQuizExit = () => {
    setMode(AppMode.LEARN);
    updatePetXp(30); 
  };

  // Timer Handlers
  const handleTimerComplete = () => {
    setTimerState(prev => ({ 
      ...prev, 
      isActive: false,
      timeLeft: 0,
      endTime: undefined 
    }));

    if (timerState.mode === 'FOCUS') {
      updatePetXp(50, timerState.focusDuration);
      setShowCelebration(true);
    } else {
      // Break is over
      alert("ϊ╝ΣόΒψύ╡ΡόζθΎ╝Βό║ΨίΓβώΨΜίπΜόΨ░ύγΕί░Ιό│ρϊ║ΗίΩΟΎ╝θ");
      // Reset to Focus mode automatically for convenience? 
      // Let's just reset the current mode's time
      resetTimer();
    }
  };

  const toggleTimer = () => {
    setTimerState(prev => {
      const isStarting = !prev.isActive;
      if (isStarting) {
        // Start Timer: Set endTime based on current timeLeft
        const targetEndTime = Date.now() + (prev.timeLeft * 1000);
        return { ...prev, isActive: true, endTime: targetEndTime };
      } else {
        // Pause Timer: Clear endTime
        return { ...prev, isActive: false, endTime: undefined };
      }
    });
  };

  const resetTimer = () => {
    setTimerState(prev => ({
      ...prev,
      isActive: false,
      endTime: undefined,
      timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60
    }));
  };

  const switchTimerMode = () => {
    const newMode = timerState.mode === 'FOCUS' ? 'BREAK' : 'FOCUS';
    const newDuration = newMode === 'FOCUS' ? timerState.focusDuration : timerState.breakDuration;
    setTimerState(prev => ({
      ...prev,
      mode: newMode,
      isActive: false,
      endTime: undefined,
      timeLeft: newDuration * 60
    }));
  };

  const updateTimerSettings = (focus: number, breakTime: number) => {
    setTimerState(prev => {
      const isFocus = prev.mode === 'FOCUS';
      return {
        ...prev,
        focusDuration: focus,
        breakDuration: breakTime,
        isActive: false,
        endTime: undefined,
        timeLeft: isFocus ? focus * 60 : breakTime * 60
      };
    });
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-3xl mx-auto space-y-8 pb-20">
             <motion.div 
               initial={{ opacity: 0, y: 20 }}
               animate={{ opacity: 1, y: 0 }}
               className="bg-white p-8 rounded-2xl shadow-sm border border-gray-200"
             >
                {/* Mode Toggles */}
                <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">ϊ╗ΛίνσόΔ│ίφ╕ϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-2 flex-wrap">
                     <div className="flex bg-gray-100 p-1 rounded-lg">
                      <button 
                        onClick={() => setInputMode('WORD')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${inputMode === 'WORD' ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}
                      >
                        ίΨχίφΩ
                      </button>
                      <button 
                        onClick={() => setInputMode('GRAMMAR')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${inputMode === 'GRAMMAR' ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}
                      >
                        όΨΘό│Χ
                      </button>
                      <button 
                        onClick={() => setInputMode('READING')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${inputMode === 'READING' ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}
                      >
                        όΨΘύτι
                      </button>
                    </div>

                    <div className="flex bg-gray-100 p-1 rounded-lg">
                      <button 
                        onClick={() => setLearningMethod('MANUAL')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${learningMethod === 'MANUAL' ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}
                      >
                        ϋΘςϋκΝϋ╝╕ίΖξ
                      </button>
                      <button 
                        onClick={() => setLearningMethod('RECOMMEND')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${learningMethod === 'RECOMMEND' ? 'bg-indigo-600 text-white shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                      >
                        AI όΟρϋΨο έερ
                      </button>
                    </div>
                  </div>
                </div>

                {learningMethod === 'MANUAL' ? (
                  <>
                    <p className="text-gray-500 mb-6">
                      {inputMode === 'WORD' 
                        ? "ϋ╝╕ίΖξόΩξόΨΘίΨχίφΩΎ╝Ιό╝λίφΩόΙΨίΒΘίΡΞΎ╝ΚΎ╝ΝύΦρύσ║όι╝ίΙΗώΨΜήΑΓ"
                        : inputMode === 'GRAMMAR' 
                          ? "ϋ╝╕ίΖξόΨΘό│ΧίΠξίηΜΎ╝Ιϊ╛ΜίοΓΎ╝γήΑεήΒοήΒψήΒΕήΒΣήΒςήΒΕ, Ύ╜ηήΒΥήΒρήΒτήΒςήΓΜΎ╝ΚήΑΓ"
                          : "ϋ╝╕ίΖξϊ╕Αόχ╡όΩξόΨΘύθφόΨΘΎ╝ΝAI ί░ΘύΓ║όΓρύ┐╗ϋφψϊ╕οίΙΗόηΡώΘΞώ╗ηίΨχίφΩϋΙΘόΨΘό│ΧήΑΓ"
                      }
                    </p>
                    <div className="relative">
                      <textarea 
                        className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-gray-400 focus:border-transparent outline-none text-lg text-gray-800 transition-all resize-none h-32 placeholder-gray-300"
                        placeholder={
                            inputMode === 'WORD' ? "ϊ╛ΜίοΓ: ύΝτ ώμθήΒ╣ήΓΜ ίυΚήΒΩήΒΕ" 
                            : inputMode === 'GRAMMAR' ? "ϊ╛ΜίοΓ: Ύ╜ηώΑγήΓΛήΒτ, Ύ╜ηήΒ░ήΓΙήΒΜήΒμήΒθ"
                            : "ίερόφνϋ▓╝ϊ╕ΛόΩξόΨΘόΨΘύτι..."
                        }
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                      />
                      <div className="absolute bottom-4 right-4">
                        <Button onClick={handleLearn} disabled={loading} className={loading ? 'opacity-50 cursor-not-allowed' : ''}>
                           {loading ? 'όΑζϋΑΔϊ╕φ...' : 'ώΨΜίπΜϋπμόηΡ'}
                        </Button>
                      </div>
                    </div>
                  </>
                ) : (
                  <div className="space-y-6">
                    <div>
                       <label className="block text-sm font-bold text-gray-700 mb-3">ώΒ╕όΥΘ JLPT ώδμί║ο</label>
                       <div className="flex gap-2">
                         {(['N5', 'N4', 'N3', 'N2', 'N1'] as JLPTLevel[]).map(lvl => (
                           <button
                             key={lvl}
                             onClick={() => setSelectedLevel(lvl)}
                             className={`px-4 py-2 rounded-full font-bold transition-all ${
                               selectedLevel === lvl 
                               ? 'bg-gray-800 text-white shadow-md transform scale-105' 
                               : 'bg-gray-100 text-gray-400 hover:bg-gray-200'
                             }`}
                           >
                             {lvl}
                           </button>
                         ))}
                       </div>
                    </div>

                    {inputMode !== 'READING' && (
                        <div>
                        <div className="flex justify-between items-center mb-2">
                            <label className="block text-sm font-bold text-gray-700">
                            {inputMode === 'WORD' ? 'ίΨχίφΩόΧ╕ώΘΠ' : 'όΨΘό│ΧόΧ╕ώΘΠ'}
                            </label>
                            <span className="text-2xl font-bold text-indigo-600">{recommendCount}</span>
                        </div>
                        <input 
                            type="range" 
                            min="1"
                            max="20"
                            value={recommendCount}
                            onChange={(e) => setRecommendCount(parseInt(e.target.value))}
                            className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                        />
                        <div className="flex justify-between text-xs text-gray-400 mt-1">
                            <span>1</span>
                            <span>20</span>
                        </div>
                        </div>
                    )}

                    <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100 text-sm text-indigo-800 flex items-start gap-2">
                       <span className="text-xl">ΏθΤκ</span>
                       <p>
                         {inputMode === 'READING' 
                           ? `AI ί░ΘόεΔύΦθόΙΡϊ╕ΑύψΘώΒσίΡΙ ${selectedLevel} ύρΜί║ούγΕώΨ▒ϋχΑό╕υώσΩόΨΘύτιΎ╝Νϊ╕οόΧ┤ύΡΗίΘ║ώΩεώΞ╡ίΨχίφΩϋΙΘόΨΘό│Χϊ╛δόΓρίφ╕ύ┐ΤήΑΓ`
                           : `AI ί░ΘόεΔόΟρϋΨο ${selectedLevel} ύρΜί║ούγΕ${inputMode === 'WORD' ? 'ίΨχίφΩ' : 'όΨΘό│Χ'}Ύ╝Νϊ╕οϊ╕ΦόεΔϋΘςίΜΧώΒΟό┐╛όΟΚόΓρίερόφ╖ίΠ▓ύ┤ΑώΝΕϊ╕φί╖▓ύ╢Υίφ╕ύ┐ΤώΒΟύγΕίΖπίχ╣ήΑΓ`
                         }
                       </p>
                    </div>

                    <Button onClick={handleLearn} fullWidth disabled={loading} className={loading ? 'opacity-50 cursor-not-allowed' : ''}>
                       {loading ? 'όφμίερόΡεί░ΜώΒσίΡΙύγΕίΖπίχ╣...' : 
                        inputMode === 'READING' 
                        ? 'ύΦθόΙΡόΟρϋΨοόΨΘύτι'
                        : `ύΦθόΙΡ ${recommendCount} ίΑΜόΟρϋΨο${inputMode === 'WORD' ? 'ίΨχίφΩ' : 'όΨΘό│Χ'}`
                       }
                    </Button>
                  </div>
                )}
             </motion.div>

             {loading && <Loader text={learningMethod === 'MANUAL' ? "όφμίερόθξϋσλϋ╛φίΖ╕..." : "AI ϋΑΒί╕τόφμίερίΓβϋς▓ϊ╕φ..."} />}

             {!loading && (currentDefinitions.length > 0 || currentGrammar.length > 0) && (
               <div className="space-y-6">
                 <div className="flex items-center justify-between">
                    <h3 className="text-xl font-semibold text-gray-700">
                       {learningMethod === 'RECOMMEND' ? 'όΟρϋΨού╡Ρόηε' : 'ϋπμόηΡύ╡Ρόηε'}
                    </h3>
                    <Button variant="secondary" onClick={() => startQuiz(currentDefinitions, currentGrammar, "ί┐τώΑθϋνΘύ┐Τ")}>
                       ί░Πϋσοϋ║τόΚΜ
                    </Button>
                 </div>

                 {currentDefinitions.length > 0 && (
                   <div className="grid gap-6 md:grid-cols-2">
                     {currentDefinitions.map((word, idx) => {
                       const id = `${word.word}-${idx}`;
                       return (
                         <WordCard 
                           key={id} 
                           layoutId={id}
                           data={word} 
                           onClick={() => setSelectedWordId(id)}
                         />
                       );
                     })}
                   </div>
                 )}

                 {currentGrammar.length > 0 && (
                   <div className="grid gap-6 md:grid-cols-1">
                     {currentGrammar.map((g, idx) => {
                       const id = g.id || `grammar-${idx}`;
                       return (
                         <GrammarCard
                           key={id}
                           layoutId={id}
                           data={g}
                           onClick={() => setSelectedGrammarId(id)}
                         />
                       );
                     })}
                   </div>
                 )}
               </div>
             )}

             {/* Reading View Section */}
             {!loading && currentReading && (
                 <ReadingView material={currentReading} />
             )}

          </div>
        );

      case AppMode.HISTORY:
        return (
          <div className="max-w-3xl mx-auto pb-20">
             {/* Profile / Stats Section */}
             <div className="mb-10 bg-white p-8 rounded-3xl border border-gray-200 shadow-sm flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-32 bg-gray-50 rounded-full transform translate-x-1/3 -translate-y-1/3 z-0"></div>
                <div className="relative z-10 flex flex-col items-center">
                  <div className="w-28 h-28 flex items-center justify-center bg-gray-800 rounded-full text-5xl shadow-lg border-4 border-gray-100">
                     ΏθΣ╗
                  </div>
                  <span className="mt-3 font-bold text-gray-800 text-lg">ίλρώζΙ Lv.{petStats.level}</span>
                </div>
                <div className="flex-1 w-full relative z-10">
                   <h3 className="text-2xl font-bold text-gray-800 mb-6 text-center md:text-left">ίφ╕ύ┐ΤόοΓό│Β</h3>
                   <div className="grid grid-cols-3 gap-4 text-center">
                     <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100">
                        <span className="block text-2xl font-bold text-gray-800">{Math.floor(petStats.totalFocusMinutes / 60)}h</span>
                        <span className="text-xs text-gray-500 uppercase tracking-wide">ί░Ιό│ρόβΓώΨΥ</span>
                     </div>
                     <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100">
                        <span className="block text-2xl font-bold text-gray-800">{totalWordsLearned}</span>
                        <span className="text-xs text-gray-500 uppercase tracking-wide">ίφ╕ύ┐ΤίΨχίφΩ</span>
                     </div>
                     <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100">
                        <span className="block text-2xl font-bold text-gray-800">{totalGrammarLearned}</span>
                        <span className="text-xs text-gray-500 uppercase tracking-wide">ίφ╕ύ┐ΤόΨΘό│Χ</span>
                     </div>
                   </div>
                </div>
             </div>

             {/* Achievements List */}
             <div className="mb-12">
               <h3 className="text-xl font-bold text-gray-800 mb-4 px-2">όΙΡί░▒ύΞΟύτι</h3>
               <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                 {ACHIEVEMENTS.map(ach => {
                   const isUnlocked = petStats.unlockedAchievements.includes(ach.id);
                   return (
                     <motion.button 
                       key={ach.id} 
                       onClick={() => setSelectedAchievement(ach)}
                       whileHover={{ scale: 1.02 }}
                       whileTap={{ scale: 0.98 }}
