            </button>
            <button 
              onClick={() => setMode(AppMode.HISTORY)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all flex items-center space-x-2 ${mode === AppMode.HISTORY ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <ClockIcon />
              <span className="hidden sm:inline">ύ┤ΑώΝΕ</span>
            </button>
            <button 
              onClick={() => setMode(AppMode.FOCUS)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all flex items-center space-x-2 ${mode === AppMode.FOCUS ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <FocusIcon />
              <span className="hidden sm:inline">ί░Ιό│ρ</span>
            </button>
          </nav>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 sm:px-6 py-8 relative z-0">
        <AnimatePresence mode="wait">
          <motion.div
            key={mode}
            initial={{ opacity: 0, x: -10 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 10 }}
            transition={{ duration: 0.2 }}
          >
            {renderContent()}
          </motion.div>
        </AnimatePresence>
      </main>

      {/* Persistent Mini Timer */}
      <AnimatePresence>
        {mode !== AppMode.FOCUS && (timerState.isActive || timerState.timeLeft !== timerState.focusDuration * 60) && (
          <MiniTimer state={timerState} onClick={() => setMode(AppMode.FOCUS)} />
        )}
      </AnimatePresence>

      {/* Persistent Companion Widget (Visible unless in Focus Mode or Quiz or Chat) */}
      {mode !== AppMode.FOCUS && mode !== AppMode.QUIZ && mode !== AppMode.CHAT && (
        <PetCompanion 
          stats={petStats} 
          compact 
          onClick={() => {
             setPetStats(prev => ({...prev, mood: 'happy'}));
             setTimeout(() => setPetStats(prev => ({...prev, mood: 'neutral'})), 3000);
