             <motion.div
                initial={{ scale: 0.5, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.8, opacity: 0 }}
                className="bg-white p-12 rounded-3xl shadow-2xl flex flex-col items-center text-center max-w-sm"
