                <div className="mb-8">
                    <PetCompanion stats={{...petStats, mood: 'happy'}} onClick={() => {}} />
                </div>
                <Button onClick={() => setShowCelebration(false)} fullWidth>ύ╣╝ύ║ΝίΛιό▓╣</Button>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Expanded Word Card Overlay */}
      <AnimatePresence>
        {selectedWordId && selectedWordData && (
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }} 
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-sm"
            onClick={() => setSelectedWordId(null)}
          >
            <div className="w-full max-w-lg" onClick={(e) => e.stopPropagation()}>
              <WordCard 
                layoutId={selectedWordId} 
                data={selectedWordData} 
                isExpanded 
                onClose={() => setSelectedWordId(null)}
              />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Expanded Grammar Card Overlay */}
      <AnimatePresence>
        {selectedGrammarId && selectedGrammarData && (
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }} 
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-sm"
            onClick={() => setSelectedGrammarId(null)}
          >
            <div className="w-full max-w-2xl" onClick={(e) => e.stopPropagation()}>
              <GrammarCard 
                layoutId={selectedGrammarId} 
                data={selectedGrammarData} 
                isExpanded 
                onClose={() => setSelectedGrammarId(null)}
              />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Simple Footer */}
      <footer className="py-8 text-center text-gray-400 text-sm">
        <p>Powered by Gemini 2.5 Flash</p>
      </footer>
    </div>
  );
}

