];

const INITIAL_PET_STATS: PetStats = {
  level: 1,
  currentXp: 0,
  nextLevelXp: 100,
  totalFocusMinutes: 0,
  mood: 'neutral',
  unlockedAchievements: []
};

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [history, setHistory] = useState<DailyRecord[]>([]);

  // Learning Method States
  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);

  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);

  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);

  // Selection states for overlays
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);

  // History accordion state
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);

  // Pet State
  const [petStats, setPetStats] = useState<PetStats>(INITIAL_PET_STATS);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);

  // Global Timer State
  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });
  const [showCelebration, setShowCelebration] = useState(false);

  // Load data from local storage on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('mk-nihongo-history');
    if (savedHistory) {
      try {
        setHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }

    const savedPet = localStorage.getItem('mk-nihongo-pet');
    if (savedPet) {
      try {
        const parsed = JSON.parse(savedPet);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        setPetStats(parsed);
      } catch (e) {
        console.error("Failed to parse pet stats", e);
      }
    }
  }, []);

  // Save data whenever it changes
  useEffect(() => {
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
  }, [petStats]);

  // Global Timer Tick Logic (Robust Background Support)
  useEffect(() => {
    let interval: number | null = null;

    if (timerState.isActive && timerState.endTime) {
      // Run interval more frequently to update UI, but calculate based on endTime timestamp
      interval = window.setInterval(() => {
        const now = Date.now();
        // Calculate remaining seconds based on wall-clock time
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);

        if (newTimeLeft <= 0) {
          // Timer finished
          handleTimerComplete();
        } else {
           // Update UI if the second has changed
           setTimerState(prev => {
             if (prev.timeLeft === newTimeLeft) return prev;
             return { ...prev, timeLeft: newTimeLeft };
           });
        }
      }, 200); 
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [timerState.isActive, timerState.endTime]);

  // Sync pet mood with timer
  useEffect(() => {
    if (timerState.isActive && timerState.mode === 'FOCUS') {
      setPetStats(prev => ({ ...prev, mood: 'focus' }));
    } else if (!timerState.isActive && petStats.mood === 'focus') {
      setPetStats(prev => ({ ...prev, mood: 'neutral' }));
    }
  }, [timerState.isActive, timerState.mode]);

  // Check achievements logic
  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });

    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({
        ...prev,
        unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked]
      }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  // Calculate learning totals
  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }

    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;

      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }

      return {
        ...prev,
        level: newLevel,
        currentXp: newXp,
        nextLevelXp: nextXp,
        totalFocusMinutes: prev.totalFocusMinutes + minutes,
        mood: 'happy'
      };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);

    // Clear previous results based on mode
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') {
          newWords = await fetchWordDefinitions(input);
          setCurrentDefinitions(newWords);
        } else if (inputMode === 'GRAMMAR') {
          newGrammar = await fetchGrammarDetails(input);
          setCurrentGrammar(newGrammar);
        } else if (inputMode === 'READING') {
          newReading = await analyzeReadingText(input);
          setCurrentReading(newReading);
        }
      } else {
        // Recommendations
        let excludedWords: string[] = [];
        let excludedGrammar: string[] = [];
        history.forEach(rec => {
          if (rec.words) excludedWords.push(...rec.words.map(w => w.word));
          if (rec.grammar) excludedGrammar.push(...rec.grammar.map(g => g.grammarPoint));
        });

        if (inputMode === 'WORD') {
          newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords);
          setCurrentDefinitions(newWords);
        } else if (inputMode === 'GRAMMAR') {
          newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar);
          setCurrentGrammar(newGrammar);
        } else if (inputMode === 'READING') {
          newReading = await generateRecommendedReading(selectedLevel);
          setCurrentReading(newReading);
        }
      }

      const today = new Date().toISOString().split('T')[0];
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          const existingRecord = newHistory[existingIndex];
          newHistory[existingIndex] = {
            ...existingRecord,
            words: [...(newWords || []), ...(existingRecord.words || [])],
            grammar: [...(newGrammar || []), ...(existingRecord.grammar || [])],
            readings: newReading ? [newReading, ...(existingRecord.readings || [])] : existingRecord.readings
          };
          return newHistory;
        } else {
          return [{ 
             id: Date.now().toString(), 
             date: today, 
             words: newWords || [], 
             grammar: newGrammar || [],
             readings: newReading ? [newReading] : []
          }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');

      // PROPORTIONAL XP GAIN
      let xpToGains = 0;
      if (inputMode === 'WORD') xpToGains = newWords.length * 5;
      else if (inputMode === 'GRAMMAR') xpToGains = newGrammar.length * 15;
      else if (inputMode === 'READING' && newReading) xpToGains = 50;

      updatePetXp(Math.max(xpToGains, 10)); // At least 10 XP per interaction
    } catch (error) {
      alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ");
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const startQuiz = (words: WordDefinition[], grammar: GrammarDefinition[] = [], title?: string) => {
    setQuizConfig({ sourceWords: words, sourceGrammar: grammar, dateLabel: title });
    setMode(AppMode.QUIZ);
  };

  const handleQuizExit = () => {
    const questionCount = quizConfig ? (quizConfig.sourceWords.length + quizConfig.sourceGrammar.length) : 3;
    setMode(AppMode.LEARN);
    updatePetXp(Math.max(questionCount * 10, 30)); // 10 XP per question, min 30
  };

  // Timer Handlers
  const handleTimerComplete = () => {
    setTimerState(prev => ({ 
      ...prev, 
      isActive: false,
      timeLeft: 0,
      endTime: undefined 
    }));

    if (timerState.mode === 'FOCUS') {
      updatePetXp(50, timerState.focusDuration);
      setShowCelebration(true);
    } else {
      // Break is over
      alert("ϊ╝ΣόΒψύ╡ΡόζθΎ╝Βό║ΨίΓβώΨΜίπΜόΨ░ύγΕί░Ιό│ρϊ║ΗίΩΟΎ╝θ");
      // Reset to Focus mode automatically for convenience? 
      // Let's just reset the current mode's time
      resetTimer();
    }
  };

  const toggleTimer = () => {
    setTimerState(prev => {
      const isStarting = !prev.isActive;
      if (isStarting) {
        // Start Timer: Set endTime based on current timeLeft
        const targetEndTime = Date.now() + (prev.timeLeft * 1000);
        return { ...prev, isActive: true, endTime: targetEndTime };
      } else {
        // Pause Timer: Clear endTime
        return { ...prev, isActive: false, endTime: undefined };
      }
    });
  };

  const resetTimer = () => {
    setTimerState(prev => ({
      ...prev,
      isActive: false,
      endTime: undefined,
      timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60
    }));
  };

  const switchTimerMode = () => {
    const newMode = timerState.mode === 'FOCUS' ? 'BREAK' : 'FOCUS';
    const newDuration = newMode === 'FOCUS' ? timerState.focusDuration : timerState.breakDuration;
    setTimerState(prev => ({
      ...prev,
      mode: newMode,
      isActive: false,
      endTime: undefined,
      timeLeft: newDuration * 60
    }));
  };

  const updateTimerSettings = (focus: number, breakTime: number) => {
    setTimerState(prev => {
      const isFocus = prev.mode === 'FOCUS';
      return {
        ...prev,
        focusDuration: focus,
        breakDuration: breakTime,
        isActive: false,
        endTime: undefined,
        timeLeft: isFocus ? focus * 60 : breakTime * 60
      };
    });
  };

  const renderContent = () => {
    switch (mode) {
