const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- PERSISTENT DATA LOADING (LAZY) ---
  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  // --- PERSISTENT DATA SAVING ---
  // Use a ref to prevent saving the empty initial state before loading from localstorage (though lazy init handles this)
  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }

    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));

    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  // Learning states
  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  // Global Timer Tick
  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  // Achievement Check
  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);

        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await generateRecommendedReading(selectedLevel); setCurrentReading(newReading); }
      }

      const today = new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          newHistory[existingIndex] = {
            ...newHistory[existingIndex],
            words: [...(newHistory[existingIndex].words || []), ...(newWords || [])],
            grammar: [...(newHistory[existingIndex].grammar || []), ...(newGrammar || [])],
            readings: newReading ? [...(newHistory[existingIndex].readings || []), newReading] : newHistory[existingIndex].readings
          };
          return newHistory;
        } else {
          return [{ id: Date.now().toString(), date: today, words: newWords || [], grammar: newGrammar || [], readings: newReading ? [newReading] : [] }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      let xp = inputMode === 'WORD' ? newWords.length * 5 : inputMode === 'GRAMMAR' ? newGrammar.length * 15 : newReading ? 50 : 10;
      updatePetXp(Math.max(xp, 10));
    } catch (e) { alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ"); } finally { setLoading(false); }
  };

  const handleTimerComplete = () => {
    setTimerState(prev => ({ ...prev, isActive: false, timeLeft: 0, endTime: undefined }));
    if (timerState.mode === 'FOCUS') { updatePetXp(50, timerState.focusDuration); setShowCelebration(true); }
    else { resetTimer(); }
  };

  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, endTime: undefined, timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60 }));
  const toggleTimer = () => setTimerState(prev => {
    const isStarting = !prev.isActive;
    return isStarting ? { ...prev, isActive: true, endTime: Date.now() + (prev.timeLeft * 1000) } : { ...prev, isActive: false, endTime: undefined };
  });

  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-3xl mx-auto space-y-8 pb-20">
             <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-white p-8 rounded-2xl shadow-sm border border-gray-200">
                <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">ϊ╗ΛίνσόΔ│ίφ╕ϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-2 flex-wrap">
                     <div className="flex bg-gray-100 p-1 rounded-lg">
                      {['WORD', 'GRAMMAR', 'READING'].map(m => (
                        <button key={m} onClick={() => setInputMode(m as InputMode)} className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${inputMode === m ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}>
                          {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                        </button>
                      ))}
                    </div>
                    <div className="flex bg-gray-100 p-1 rounded-lg">
                      <button onClick={() => setLearningMethod('MANUAL')} className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${learningMethod === 'MANUAL' ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}>ϋΘςϋκΝϋ╝╕ίΖξ</button>
                      <button onClick={() => setLearningMethod('RECOMMEND')} className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${learningMethod === 'RECOMMEND' ? 'bg-indigo-600 text-white shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>AI όΟρϋΨο έερ</button>
                    </div>
                  </div>
                </div>
                {learningMethod === 'MANUAL' ? (
                  <div className="relative">
                    <textarea className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-gray-400 focus:border-transparent outline-none text-lg text-gray-800 transition-all resize-none h-32 placeholder-gray-300" placeholder={inputMode === 'WORD' ? "ϊ╛ΜίοΓ: ύΝτ ώμθήΒ╣ήΓΜ ίυΚήΒΩήΒΕ" : inputMode === 'GRAMMAR' ? "ϊ╛ΜίοΓ: Ύ╜ηώΑγήΓΛήΒτ, Ύ╜ηήΒ░ήΓΙήΒΜήΒμήΒθ" : "ίερόφνϋ▓╝ϊ╕ΛόΩξόΨΘόΨΘύτι..."} value={input} onChange={(e) => setInput(e.target.value)} />
                    <div className="absolute bottom-4 right-4"><Button onClick={handleLearn} disabled={loading}>{loading ? 'όΑζϋΑΔϊ╕φ...' : 'ώΨΜίπΜϋπμόηΡ'}</Button></div>
                  </div>
                ) : (
                  <div className="space-y-6">
                    <div className="flex gap-2">{(['N5', 'N4', 'N3', 'N2', 'N1'] as JLPTLevel[]).map(lvl => <button key={lvl} onClick={() => setSelectedLevel(lvl)} className={`px-4 py-2 rounded-full font-bold transition-all ${selectedLevel === lvl ? 'bg-gray-800 text-white shadow-md transform scale-105' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}>{lvl}</button>)}</div>
                    {inputMode !== 'READING' && (
                        <div>
                        <div className="flex justify-between mb-2"><label className="block text-sm font-bold text-gray-700">{inputMode === 'WORD' ? 'ίΨχίφΩόΧ╕ώΘΠ' : 'όΨΘό│ΧόΧ╕ώΘΠ'}</label><span className="text-2xl font-bold text-indigo-600">{recommendCount}</span></div>
                        <input type="range" min="1" max="20" value={recommendCount} onChange={(e) => setRecommendCount(parseInt(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600" />
                        </div>
                    )}
                    <Button onClick={handleLearn} fullWidth disabled={loading}>{loading ? 'όφμίερίΓβϋς▓ϊ╕φ...' : inputMode === 'READING' ? 'ύΦθόΙΡόΟρϋΨοόΨΘύτι' : `ύΦθόΙΡ ${recommendCount} ίΑΜόΟρϋΨοίΖπίχ╣`}</Button>
                  </div>
                )}
             </motion.div>
             {!loading && (currentDefinitions.length > 0 || currentGrammar.length > 0) && (
               <div className="space-y-6">
                 <div className="flex items-center justify-between"><h3 className="text-xl font-semibold text-gray-700">ϋπμόηΡύ╡Ρόηε</h3><Button variant="secondary" onClick={() => setQuizConfig({ sourceWords: currentDefinitions, sourceGrammar: currentGrammar, dateLabel: "ί┐τώΑθϋνΘύ┐Τ" }) || setMode(AppMode.QUIZ)}>ί░Πϋσοϋ║τόΚΜ</Button></div>
                 <div className="grid gap-6 md:grid-cols-2">{currentDefinitions.map((w, i) => <WordCard key={i} layoutId={`${w.word}-${i}`} data={w} onClick={() => setSelectedWordId(`${w.word}-${i}`)} />)}</div>
                 <div className="grid gap-6">{currentGrammar.map((g, i) => <GrammarCard key={i} layoutId={g.id || `g-${i}`} data={g} onClick={() => setSelectedGrammarId(g.id || `g-${i}`)} />)}</div>
               </div>
             )}
             {!loading && currentReading && <ReadingView material={currentReading} />}
          </div>
        );
      case AppMode.HISTORY:
        return (
          <div className="max-w-3xl mx-auto pb-20">
             <div className="mb-10 bg-white p-8 rounded-3xl border border-gray-200 shadow-sm flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-32 bg-gray-50 rounded-full transform translate-x-1/3 -translate-y-1/3 z-0"></div>
                <div className="relative z-10 flex flex-col items-center">
                  <div className="w-28 h-28 flex items-center justify-center bg-gray-800 rounded-full text-5xl shadow-lg border-4 border-gray-100 relative">ΏθΣ╗<AnimatePresence>{xpToast && <motion.div key={xpToast.id} initial={{ opacity: 0, y: 0, scale: 0.5 }} animate={{ opacity: 1, y: -60, scale: 1.2 }} exit={{ opacity: 0 }} className="absolute top-0 right-[-40px] text-green-500 font-black text-xl pointer-events-none drop-shadow-md">+{xpToast.amount} XP</motion.div>}</AnimatePresence></div>
                  <span className="mt-3 font-bold text-gray-800 text-lg">ίλρώζΙ Lv.{petStats.level}</span>
                </div>
                <div className="flex-1 w-full relative z-10">
                   <h3 className="text-2xl font-bold text-gray-800 mb-6 text-center md:text-left">ίφ╕ύ┐ΤόοΓό│Β</h3>
                   <div className="grid grid-cols-3 gap-4 text-center">
                     <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100"><span className="block text-2xl font-bold text-gray-800">{Math.floor(petStats.totalFocusMinutes / 60)}h</span><span className="text-xs text-gray-500 uppercase tracking-wide">ί░Ιό│ρόβΓώΨΥ</span></div>
                     <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100"><span className="block text-2xl font-bold text-gray-800">{totalWordsLearned}</span><span className="text-xs text-gray-500 uppercase tracking-wide">ίφ╕ύ┐ΤίΨχίφΩ</span></div>
                     <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100"><span className="block text-2xl font-bold text-gray-800">{totalGrammarLearned}</span><span className="text-xs text-gray-500 uppercase tracking-wide">ίφ╕ύ┐ΤόΨΘό│Χ</span></div>
                   </div>
                   <div className="mt-6 px-4">
                     <div className="flex justify-between text-[10px] font-bold text-gray-400 mb-1"><span>ύ╢ΥώσΩώΑ▓ί║ο</span><span>{petStats.currentXp} / {petStats.nextLevelXp} XP</span></div>
                     <div className="w-full bg-gray-100 rounded-full h-2"><motion.div className="bg-gray-800 h-2 rounded-full shadow-sm" animate={{ width: `${Math.min((petStats.currentXp / petStats.nextLevelXp) * 100, 100)}%` }} /></div>
                   </div>
                </div>
             </div>
             <div className="mb-12"><h3 className="text-xl font-bold text-gray-800 mb-4 px-2">όΙΡί░▒ύΞΟύτι</h3><div className="grid grid-cols-2 md:grid-cols-3 gap-4">{ACHIEVEMENTS.map(ach => <motion.button key={ach.id} onClick={() => setSelectedAchievement(ach)} whileHover={{ scale: 1.02 }} className={`p-4 rounded-xl border flex flex-col items-center text-center transition-all ${petStats.unlockedAchievements.includes(ach.id) ? 'bg-white border-yellow-200 shadow-sm' : 'bg-gray-50 border-gray-200 opacity-60'}`}><div className="text-4xl mb-2">{petStats.unlockedAchievements.includes(ach.id) ? ach.icon : 'ΏθΦΤ'}</div><h4 className="font-bold text-sm">{ach.title}</h4></motion.button>)}</div></div>
             <h2 className="text-2xl font-bold text-gray-800 mb-6 px-2">ίφ╕ύ┐ΤόΩξϋςΝ</h2>
             {history.length === 0 ? <div className="text-center py-20 text-gray-400 bg-gray-50 rounded-2xl border border-dashed border-gray-300">ώΓΕό▓ΤόεΚύ┤ΑώΝΕίΨΦΎ╝ΝώΨΜίπΜίφ╕ύ┐ΤίΡπΎ╝Β</div> : (
               <div className="space-y-4">{history.map((record) => {
                   const isExpanded = expandedHistoryId === record.id;
                   return (
                     <motion.div key={record.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} className={`bg-white rounded-xl border overflow-hidden ${isExpanded ? 'border-gray-400 shadow-md' : 'border-gray-200'}`}>
                       <div className="p-6 cursor-pointer flex justify-between items-center" onClick={() => setExpandedHistoryId(isExpanded ? null : record.id)}>
                         <div className="flex items-center gap-4">
                            <div className={`p-2 rounded-lg ${isExpanded ? 'bg-gray-800 text-white' : 'bg-gray-100 text-gray-400'}`}><ClockIcon /></div>
                            <div><h3 className="text-lg font-bold text-gray-800">{record.date}</h3><p className="text-gray-500 text-xs">{(record.words?.length || 0)} ίΨχίφΩ έΑλ {(record.grammar?.length || 0)} όΨΘό│Χ</p></div>
                         </div>
                         <Button variant="secondary" className="text-xs" onClick={(e) => { e.stopPropagation(); setQuizConfig({ sourceWords: record.words || [], sourceGrammar: record.grammar || [], dateLabel: `ϋνΘύ┐Τ: ${record.date}` }); setMode(AppMode.QUIZ); }}>ϋΘςόΙΣό╕υώσΩ</Button>
                       </div>
                       <AnimatePresence>{isExpanded && (
                           <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="overflow-hidden border-t border-gray-100 bg-gray-50 p-6 space-y-4">
                             {record.words?.length > 0 && <div className="flex flex-wrap gap-2">{record.words.map((w, i) => <button key={i} onClick={() => setSelectedWordId(`${w.word}-history-${record.id}-${i}`)} className="bg-white border border-gray-200 px-3 py-2 rounded-lg text-sm font-bold shadow-sm">{w.word}</button>)}</div>}
                             {record.grammar?.length > 0 && <div className="flex flex-wrap gap-2">{record.grammar.map((g, i) => <button key={i} onClick={() => setSelectedGrammarId(`g-h-${record.id}-${i}`)} className="bg-indigo-50 border border-indigo-100 text-indigo-700 px-3 py-2 rounded-lg text-sm font-bold shadow-sm">{g.grammarPoint}</button>)}</div>}
                           </motion.div>
                       )}</AnimatePresence>
                     </motion.div>
                   );
               })}</div>
             )}
          </div>
        );
      case AppMode.CHAT: return <ChatInterface onBack={() => setMode(AppMode.LEARN)} onXpUpdate={updatePetXp} />;
      case AppMode.QUIZ: return quizConfig ? <Quiz sourceWords={quizConfig.sourceWords} sourceGrammar={quizConfig.sourceGrammar} title={quizConfig.dateLabel} onExit={() => setMode(AppMode.LEARN)} /> : null;
      case AppMode.FOCUS: return <div className="max-w-3xl mx-auto flex flex-col items-center justify-center min-h-[60vh] space-y-12"><PomodoroTimer state={timerState} onToggle={toggleTimer} onReset={resetTimer} onSwitchMode={() => setTimerState(prev => ({ ...prev, mode: prev.mode === 'FOCUS' ? 'BREAK' : 'FOCUS', isActive: false, timeLeft: (prev.mode === 'FOCUS' ? prev.breakDuration : prev.focusDuration) * 60 }))} onUpdateSettings={(f, b) => setTimerState(prev => ({ ...prev, focusDuration: f, breakDuration: b, timeLeft: f * 60 }))} /><PetCompanion stats={petStats} onClick={() => updatePetXp(1)} /></div>;
      default: return null;
    }
  };

  const findWord = (id: string | null) => {
    if (!id) return null;
    const match = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (match) return match;
    if (id.includes('-history-')) {
       const [word, recId, idx] = id.split('-history-')[1].split('-');
       const rec = history.find(h => h.id === recId);
       return rec?.words[parseInt(idx)];
    }
    return null;
  };

  const findGrammar = (id: string | null) => {
    if (!id) return null;
    const match = currentGrammar.find(g => g.id === id);
    if (match) return match;
    if (id.includes('g-h-')) {
       const [recId, idx] = id.split('g-h-')[1].split('-');
       const rec = history.find(h => h.id === recId);
       return rec?.grammar?.[parseInt(idx)];
    }
    return null;
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-gray-200">
      <header className="bg-white/80 backdrop-blur-md sticky top-0 z-40 border-b border-gray-200">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2 cursor-pointer" onClick={() => setMode(AppMode.LEARN)}>
            <div className="w-8 h-8 bg-gray-900 rounded-lg flex items-center justify-center text-white font-bold">όΩξ</div>
            <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">Mono-Kuro Nihongo</h1>
            <div className="flex items-center ml-2 text-gray-400 group">
                {isSyncing ? (
                    <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1 }} className="w-3 h-3 border-2 border-indigo-400 border-t-transparent rounded-full" />
                ) : (
                    <div className="flex items-center gap-1 opacity-60">
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>
                        <span className="text-[10px] font-bold uppercase tracking-widest hidden group-hover:block">ί╖▓ίχΚίΖρίφαίΕ▓όΨ╝όευίε░</span>
                    </div>
                )}
            </div>
          </div>
          <nav className="flex space-x-1 bg-gray-100/50 p-1 rounded-xl overflow-x-auto no-scrollbar">
            {[{m:AppMode.LEARN, i:<BookIcon/>, l:'ίφ╕ύ┐Τ'}, {m:AppMode.CHAT, i:<ChatIcon/>, l:'ϋςηϊ╝┤'}, {m:AppMode.HISTORY, i:<ClockIcon/>, l:'ύ┤ΑώΝΕ'}, {m:AppMode.FOCUS, i:<FocusIcon/>, l:'ί░Ιό│ρ'}].map(nav => (
                <button key={nav.m} onClick={() => setMode(nav.m)} className={`px-4 py-2 rounded-lg text-sm font-medium transition-all flex items-center space-x-2 ${mode === nav.m ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
                    {nav.i}<span className="hidden sm:inline">{nav.l}</span>
                </button>
            ))}
          </nav>
        </div>
      </header>
      <main className="max-w-5xl mx-auto px-4 sm:px-6 py-8 relative z-0">
        <AnimatePresence mode="wait"><motion.div key={mode} initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: 10 }} transition={{ duration: 0.2 }}>{renderContent()}</motion.div></AnimatePresence>
      </main>
      <AnimatePresence>{mode !== AppMode.FOCUS && (timerState.isActive || timerState.timeLeft !== timerState.focusDuration * 60) && <MiniTimer state={timerState} onClick={() => setMode(AppMode.FOCUS)} />}</AnimatePresence>
      <AnimatePresence>{newAchievement && <motion.div initial={{ opacity: 0, y: 50 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }} className="fixed bottom-24 left-1/2 -translate-x-1/2 z-50 bg-gray-900 text-white px-6 py-4 rounded-full shadow-2xl flex items-center space-x-4"><div className="text-3xl">{newAchievement.icon}</div><div><p className="text-xs text-gray-400 font-bold uppercase tracking-wider">όΙΡί░▒ϋπμώΟΨΎ╝Β</p><p className="font-bold text-lg">{newAchievement.title}</p></div></motion.div>}</AnimatePresence>
      <AnimatePresence>{selectedAchievement && <div className="fixed inset-0 z-[70] flex items-center justify-center bg-gray-900/60 backdrop-blur-sm" onClick={() => setSelectedAchievement(null)}><motion.div initial={{ scale: 0.9 }} animate={{ scale: 1 }} className="bg-white rounded-2xl p-8 max-w-sm w-full text-center" onClick={e => e.stopPropagation()}><div className="text-6xl mb-4">{selectedAchievement.icon}</div><h3 className="text-2xl font-bold mb-2">{selectedAchievement.title}</h3><p className="text-gray-600 mb-6">{selectedAchievement.description}</p><div className={`text-xs font-bold py-1 px-3 rounded-full inline-block ${petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-400'}`}>{petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'ί╖▓ϋπμώΟΨ' : 'όεςϋπμώΟΨ'}</div></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedWordId && <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-sm" onClick={() => setSelectedWordId(null)}><div className="w-full max-w-lg" onClick={e => e.stopPropagation()}><WordCard layoutId={selectedWordId} data={findWord(selectedWordId)!} isExpanded onClose={() => setSelectedWordId(null)} /></div></div>}</AnimatePresence>
      <AnimatePresence>{selectedGrammarId && <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-sm" onClick={() => setSelectedGrammarId(null)}><div className="w-full max-w-2xl" onClick={e => e.stopPropagation()}><GrammarCard layoutId={selectedGrammarId} data={findGrammar(selectedGrammarId)!} isExpanded onClose={() => setSelectedGrammarId(null)} /></div></div>}</AnimatePresence>
      <footer className="py-8 text-center text-gray-400 text-sm"><p>Powered by Gemini 2.5 Flash έΑλ όΧ╕όΥγόΝΒϊ╣ΖίΝΨίΛιίδ║</p></footer>
    </div>
  );
}
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordDefinition, DailyRecord, AppMode, QuizConfig, InputMode, GrammarDefinition, PetStats, Achievement, TimerState, ReadingMaterial } from './types';
import { fetchWordDefinitions, fetchGrammarDetails, fetchRecommendedWords, fetchRecommendedGrammar, analyzeReadingText, generateRecommendedReading } from './services/geminiService';
import { WordCard } from './components/WordCard';
import { GrammarCard } from './components/GrammarCard';
import { ReadingView } from './components/ReadingView';
import { ChatInterface } from './components/ChatInterface';
import { Quiz } from './components/Quiz';
import { Button } from './components/Button';
import { Loader } from './components/Loader';
import { PetCompanion } from './components/PetCompanion';
import { PomodoroTimer } from './components/PomodoroTimer';
import { MiniTimer } from './components/MiniTimer';

// Icons
const BookIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 006 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 016 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 016-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0018 18a8.967 8.967 0 00-6 2.292m0-14.25v14.25" /></svg>;
const ClockIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6h4.5m4.5 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const FocusIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" /></svg>;
const ChatIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M20.25 8.511c.884.284 1.5 1.128 1.5 2.097v4.286c0 1.136-.847 2.1-1.98 2.193-.34.027-.68.052-1.02.072v3.091l-3-3c-1.354 0-2.694-.055-4.02-.163a2.115 2.115 0 01-.825-.242m9.345-8.334a2.126 2.126 0 00-.476-.095 48.64 48.64 0 00-8.048 0c-1.131.094-1.976 1.057-1.976 2.192v4.286c0 .837.46 1.58 1.155 1.951m9.345-8.334V6.637c0-1.621-1.152-3.026-2.76-3.235A48.455 48.455 0 0011.25 3c-2.115 0-4.198.137-6.24.402-1.608.209-2.76 1.614-2.76 3.235v6.226c0 1.621 1.152 3.026 2.76 3.235.577.075 1.157.14 1.74.194V21l4.155-4.155" /></svg>;

const ACHIEVEMENTS: Achievement[] = [
  { id: 'first_step', title: 'ίΙζίΘ║ϋΝΖί╗υ', description: 'ίχΝόΙΡύυυϊ╕Αόυκί░Ιό│ρύ╖┤ύ┐Τ', icon: 'ΏθΝ▒', condition: (stats) => stats.totalFocusMinutes >= 1 },
  { id: 'focus_master_bronze', title: 'ί░Ιό│ρόΨ░όΚΜ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 60 ίΙΗώΡα', icon: 'ΏθξΚ', condition: (stats) => stats.totalFocusMinutes >= 60 },
  { id: 'focus_master_silver', title: 'ί░Ιό│ρώΒΦϊ║║', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 300 ίΙΗώΡα', icon: 'ΏθξΙ', condition: (stats) => stats.totalFocusMinutes >= 300 },
  { id: 'focus_master_gold', title: 'ύοςίχγίνπί╕τ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 1000 ίΙΗώΡα', icon: 'ΏθξΘ', condition: (stats) => stats.totalFocusMinutes >= 1000 },
  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 },
  { id: 'level_10', title: 'ίλρώζΙϊ╣ΜίΠΜ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10', icon: 'ΏθΣΣ', condition: (stats) => stats.level >= 10 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);
        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await generateRecommendedReading(selectedLevel); setCurrentReading(newReading); }
      }

      const today = new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          newHistory[existingIndex] = {
            ...newHistory[existingIndex],
            words: [...(newHistory[existingIndex].words || []), ...(newWords || [])],
            grammar: [...(newHistory[existingIndex].grammar || []), ...(newGrammar || [])],
            readings: newReading ? [...(newHistory[existingIndex].readings || []), newReading] : newHistory[existingIndex].readings
          };
          return newHistory;
        } else {
          return [{ id: Date.now().toString(), date: today, words: newWords || [], grammar: newGrammar || [], readings: newReading ? [newReading] : [] }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      let xp = inputMode === 'WORD' ? newWords.length * 5 : inputMode === 'GRAMMAR' ? newGrammar.length * 15 : newReading ? 50 : 10;
      updatePetXp(Math.max(xp, 10));
    } catch (e) { alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ"); } finally { setLoading(false); }
  };

  const handleTimerComplete = () => {
    setTimerState(prev => ({ ...prev, isActive: false, timeLeft: 0, endTime: undefined }));
    if (timerState.mode === 'FOCUS') { updatePetXp(50, timerState.focusDuration); setShowCelebration(true); }
    else { resetTimer(); }
  };

  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, endTime: undefined, timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60 }));
  const toggleTimer = () => setTimerState(prev => {
    const isStarting = !prev.isActive;
    return isStarting ? { ...prev, isActive: true, endTime: Date.now() + (prev.timeLeft * 1000) } : { ...prev, isActive: false, endTime: undefined };
  });

  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const findWord = (id: string | null) => {
    if (!id) return null;
    const match = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (match) return match;
    if (id.includes('-history-')) {
       const parts = id.split('-history-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.words[idx] || null;
    }
    return null;
  };

  const findGrammar = (id: string | null) => {
    if (!id) return null;
    const match = currentGrammar.find(g => g.id === id);
    if (match) return match;
    if (id.includes('g-h-')) {
       const parts = id.split('g-h-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.grammar?.[idx] || null;
    }
    return null;
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-3xl mx-auto space-y-8 pb-20 px-2">
             <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-white p-8 rounded-3xl shadow-sm border border-gray-200">
                <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">ϊ╗ΛίνσόΔ│ίφ╕ϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-2 flex-wrap">
                     <div className="flex bg-gray-100 p-1 rounded-xl">
                      {['WORD', 'GRAMMAR', 'READING'].map(m => (
                        <button key={m} onClick={() => setInputMode(m as InputMode)} className={`px-4 py-2 text-sm font-bold rounded-lg transition-all ${inputMode === m ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}>
                          {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                        </button>
                      ))}
                    </div>
                    <div className="flex bg-gray-100 p-1 rounded-xl">
                      <button onClick={() => setLearningMethod('MANUAL')} className={`px-4 py-2 text-sm font-bold rounded-lg transition-all ${learningMethod === 'MANUAL' ? 'bg-white shadow-sm text-gray-800' : 'text-gray-500 hover:text-gray-700'}`}>ϋ╝╕ίΖξ</button>
                      <button onClick={() => setLearningMethod('RECOMMEND')} className={`px-4 py-2 text-sm font-bold rounded-lg transition-all ${learningMethod === 'RECOMMEND' ? 'bg-gray-800 text-white shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>όΟρϋΨοέερ</button>
                    </div>
                  </div>
                </div>
                {learningMethod === 'MANUAL' ? (
                  <div className="relative">
                    <textarea className="w-full p-6 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-gray-300 focus:border-transparent outline-none text-lg text-gray-800 transition-all resize-none h-40 placeholder-gray-300 shadow-inner" placeholder={inputMode === 'WORD' ? "ϊ╛ΜίοΓ: ύΝτ ώμθήΒ╣ήΓΜ ίυΚήΒΩήΒΕ" : inputMode === 'GRAMMAR' ? "ϊ╛ΜίοΓ: Ύ╜ηώΑγήΓΛήΒτ, Ύ╜ηήΒ░ήΓΙήΒΜήΒμήΒθ" : "ίερόφνϋ▓╝ϊ╕ΛόΩξόΨΘόΨΘύτι..."} value={input} onChange={(e) => setInput(e.target.value)} />
                    <div className="absolute bottom-6 right-6"><Button onClick={handleLearn} disabled={loading}>{loading ? 'όΑζϋΑΔϊ╕φ...' : 'ώΨΜίπΜϋπμόηΡ'}</Button></div>
                  </div>
                ) : (
                  <div className="space-y-6">
                    <div className="flex gap-3">{(['N5', 'N4', 'N3', 'N2', 'N1'] as JLPTLevel[]).map(lvl => <motion.button whileTap={{scale: 0.95}} key={lvl} onClick={() => setSelectedLevel(lvl)} className={`flex-1 py-3 rounded-2xl font-bold transition-all border ${selectedLevel === lvl ? 'bg-gray-800 text-white border-gray-800 shadow-md' : 'bg-gray-100 text-gray-400 border-transparent hover:bg-gray-200'}`}>{lvl}</motion.button>)}</div>
                    {inputMode !== 'READING' && (
                        <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                          <div className="flex justify-between mb-4"><label className="block text-sm font-bold text-gray-500 uppercase tracking-widest">{inputMode === 'WORD' ? 'ίΨχίφΩόΧ╕ώΘΠ' : 'όΨΘό│ΧόΧ╕ώΘΠ'}</label><span className="text-3xl font-black text-gray-800">{recommendCount}</span></div>
                          <input type="range" min="1" max="20" value={recommendCount} onChange={(e) => setRecommendCount(parseInt(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-gray-800" />
                        </div>
                    )}
                    <Button onClick={handleLearn} fullWidth disabled={loading}>{loading ? 'AI όφμίερίΓβϋς▓ϊ╕φ...' : inputMode === 'READING' ? 'ύΦθόΙΡόΟρϋΨοόΨΘύτι' : `ύΦθόΙΡ ${recommendCount} ίΑΜόΟρϋΨοίΖπίχ╣`}</Button>
                  </div>
                )}
             </motion.div>
             {!loading && (currentDefinitions.length > 0 || currentGrammar.length > 0) && (
               <div className="space-y-6">
                 <div className="flex items-center justify-between px-2"><h3 className="text-xl font-bold text-gray-800 uppercase tracking-widest">ϋπμόηΡύ╡Ρόηε</h3><Button variant="secondary" onClick={() => setQuizConfig({ sourceWords: currentDefinitions, sourceGrammar: currentGrammar, dateLabel: "ί┐τώΑθϋνΘύ┐Τ" }) || setMode(AppMode.QUIZ)}>ί░Πϋσοϋ║τόΚΜ</Button></div>
                 <div className="grid gap-6 md:grid-cols-2">{currentDefinitions.map((w, i) => <WordCard key={i} layoutId={`${w.word}-${i}`} data={w} onClick={() => setSelectedWordId(`${w.word}-${i}`)} />)}</div>
                 <div className="grid gap-6">{currentGrammar.map((g, i) => <GrammarCard key={i} layoutId={g.id || `g-${i}`} data={g} onClick={() => setSelectedGrammarId(g.id || `g-${i}`)} />)}</div>
               </div>
             )}
             {!loading && currentReading && <ReadingView material={currentReading} />}
          </div>
        );
      case AppMode.HISTORY:
        return (
          <div className="max-w-3xl mx-auto pb-20 px-2">
             <div className="mb-10 bg-white p-10 rounded-[2.5rem] border border-gray-200 shadow-sm flex flex-col md:flex-row items-center gap-10 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-40 bg-gray-50 rounded-full transform translate-x-1/2 -translate-y-1/2 z-0"></div>
                <div className="relative z-10 flex flex-col items-center">
                  <div className="w-32 h-32 flex items-center justify-center bg-gray-800 rounded-full text-6xl shadow-xl border-4 border-gray-50 relative">ΏθΣ╗<AnimatePresence>{xpToast && <motion.div key={xpToast.id} initial={{ opacity: 0, y: 0, scale: 0.5 }} animate={{ opacity: 1, y: -70, scale: 1.4 }} exit={{ opacity: 0 }} className="absolute top-0 right-[-50px] text-green-500 font-black text-2xl drop-shadow-md">+{xpToast.amount} XP</motion.div>}</AnimatePresence></div>
                  <span className="mt-4 font-black text-gray-800 text-xl tracking-tight">ίλρώζΙ Lv.{petStats.level}</span>
                </div>
