import React from 'react';
import { motion } from 'framer-motion';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'glass';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-2xl font-bold transition-all duration-300 flex items-center justify-center space-x-2 focus:outline-none focus:ring-2 focus:ring-offset-2 overflow-hidden relative group";

  const variants = {
    primary: "bg-gray-900 text-white hover:bg-black shadow-lg shadow-gray-200 focus:ring-gray-500",
    secondary: "bg-gray-100 text-gray-800 hover:bg-gray-200 focus:ring-gray-300",
    outline: "bg-transparent border-2 border-gray-200 text-gray-500 hover:border-gray-800 hover:text-gray-800 focus:ring-gray-300",
    glass: "bg-white/40 backdrop-blur-md border border-white/40 text-gray-800 shadow-xl shadow-gray-200/50 hover:bg-white/60 focus:ring-white/50"
  };

  return (
    <motion.button
      whileHover={{ scale: 1.02, y: -2 }}
      whileTap={{ scale: 0.96 }}
      transition={{ type: "spring", stiffness: 400, damping: 15 }}
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      <div className="absolute inset-0 w-1/2 h-full bg-white/20 skew-x-[-25deg] -translate-x-full group-hover:translate-x-[250%] transition-transform duration-700 ease-in-out pointer-events-none" />
      <span className="relative z-10">{children}</span>
    </motion.button>
  );
};

