                           ))}
                        </div>
                     </div>
                   )}
                </div>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordDefinition, DailyRecord, AppMode, QuizConfig, InputMode, GrammarDefinition, PetStats, Achievement, TimerState, ReadingMaterial } from './types';
