const ACHIEVEMENTS: Achievement[] = [
  { id: 'first_step', title: 'ίΙζίΘ║ϋΝΖί╗υ', description: 'ίχΝόΙΡύυυϊ╕Αόυκί░Ιό│ρύ╖┤ύ┐Τ', icon: 'ΏθΝ▒', condition: (stats) => stats.totalFocusMinutes >= 1 },
  { id: 'focus_master_bronze', title: 'ί░Ιό│ρόΨ░όΚΜ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 60 ίΙΗώΡα', icon: 'ΏθξΚ', condition: (stats) => stats.totalFocusMinutes >= 60 },
  { id: 'focus_master_silver', title: 'ί░Ιό│ρώΒΦϊ║║', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 300 ίΙΗώΡα', icon: 'ΏθξΙ', condition: (stats) => stats.totalFocusMinutes >= 300 },
  { id: 'focus_master_gold', title: 'ύοςίχγίνπί╕τ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 1000 ίΙΗώΡα', icon: 'ΏθξΘ', condition: (stats) => stats.totalFocusMinutes >= 1000 },
  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 },
  { id: 'level_10', title: 'ίλρώζΙϊ╣ΜίΠΜ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10', icon: 'ΏθΣΣ', condition: (stats) => stats.level >= 10 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);
        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await generateRecommendedReading(selectedLevel); setCurrentReading(newReading); }
      }

      const today = new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          newHistory[existingIndex] = {
            ...newHistory[existingIndex],
            words: [...(newHistory[existingIndex].words || []), ...(newWords || [])],
            grammar: [...(newHistory[existingIndex].grammar || []), ...(newGrammar || [])],
            readings: newReading ? [...(newHistory[existingIndex].readings || []), newReading] : newHistory[existingIndex].readings
          };
          return newHistory;
        } else {
          return [{ id: Date.now().toString(), date: today, words: newWords || [], grammar: newGrammar || [], readings: newReading ? [newReading] : [] }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      let xp = inputMode === 'WORD' ? newWords.length * 5 : inputMode === 'GRAMMAR' ? newGrammar.length * 15 : newReading ? 50 : 10;
      updatePetXp(Math.max(xp, 10));
    } catch (e) { alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ"); } finally { setLoading(false); }
  };

  const handleTimerComplete = () => {
    setTimerState(prev => ({ ...prev, isActive: false, timeLeft: 0, endTime: undefined }));
    if (timerState.mode === 'FOCUS') { updatePetXp(50, timerState.focusDuration); setShowCelebration(true); }
    else { resetTimer(); }
  };

  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, endTime: undefined, timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60 }));
  const toggleTimer = () => setTimerState(prev => {
    const isStarting = !prev.isActive;
    return isStarting ? { ...prev, isActive: true, endTime: Date.now() + (prev.timeLeft * 1000) } : { ...prev, isActive: false, endTime: undefined };
  });

  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const findWord = (id: string | null) => {
    if (!id) return null;
    const match = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (match) return match;
    if (id.includes('-history-')) {
       const parts = id.split('-history-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.words[idx] || null;
    }
    return null;
  };

  const findGrammar = (id: string | null) => {
    if (!id) return null;
    const match = currentGrammar.find(g => g.id === id);
    if (match) return match;
    if (id.includes('g-h-')) {
       const parts = id.split('g-h-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.grammar?.[idx] || null;
    }
    return null;
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-3xl mx-auto space-y-12 pb-20 px-2">
             <motion.div initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-gray-100 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-gray-50 rounded-full translate-x-1/2 -translate-y-1/2" />
                <div className="relative z-10 flex flex-col md:flex-row md:justify-between md:items-center gap-6 mb-10">
                  <h2 className="text-3xl font-black text-gray-900 tracking-tighter">ϊ╗ΛίνσόΔ│ίφ╕ϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-3 flex-wrap">
                     <div className="flex bg-gray-50 p-1.5 rounded-2xl shadow-inner border border-gray-100">
                      {['WORD', 'GRAMMAR', 'READING'].map(m => (
                        <button key={m} onClick={() => setInputMode(m as InputMode)} className={`px-5 py-2 text-sm font-black rounded-xl transition-all ${inputMode === m ? 'bg-white shadow-md text-gray-900' : 'text-gray-400 hover:text-gray-600'}`}>
                          {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                        </button>
                      ))}
                    </div>
                    <div className="flex bg-gray-50 p-1.5 rounded-2xl shadow-inner border border-gray-100">
                      <button onClick={() => setLearningMethod('MANUAL')} className={`px-5 py-2 text-sm font-black rounded-xl transition-all ${learningMethod === 'MANUAL' ? 'bg-white shadow-md text-gray-900' : 'text-gray-400 hover:text-gray-600'}`}>ϋ╝╕ίΖξ</button>
                      <button onClick={() => setLearningMethod('RECOMMEND')} className={`px-5 py-2 text-sm font-black rounded-xl transition-all ${learningMethod === 'RECOMMEND' ? 'bg-gray-900 text-white shadow-lg' : 'text-gray-400 hover:text-gray-600'}`}>όΟρϋΨοέερ</button>
                    </div>
                  </div>
                </div>
                {learningMethod === 'MANUAL' ? (
                  <div className="relative">
                    <textarea className="w-full p-8 bg-gray-50/50 border border-gray-100 rounded-[2rem] focus:ring-4 focus:ring-gray-100 focus:border-gray-200 outline-none text-xl text-gray-900 font-bold transition-all resize-none h-48 placeholder-gray-300 shadow-inner" placeholder={inputMode === 'WORD' ? "ϊ╛ΜίοΓ: ύΝτ ώμθήΒ╣ήΓΜ ίυΚήΒΩήΒΕ" : inputMode === 'GRAMMAR' ? "ϊ╛ΜίοΓ: Ύ╜ηώΑγήΓΛήΒτ, Ύ╜ηήΒ░ήΓΙήΒΜήΒμήΒθ" : "ίερόφνϋ▓╝ϊ╕ΛόΩξόΨΘόΨΘύτι..."} value={input} onChange={(e) => setInput(e.target.value)} />
                    <div className="absolute bottom-8 right-8"><Button onClick={handleLearn} disabled={loading}>{loading ? 'όΑζϋΑΔϊ╕φ...' : 'ώΨΜίπΜϋπμόηΡ'}</Button></div>
                  </div>
                ) : (
                  <div className="space-y-8">
                    <div className="grid grid-cols-5 gap-3">{(['N5', 'N4', 'N3', 'N2', 'N1'] as JLPTLevel[]).map(lvl => <motion.button whileHover={{ y: -2 }} whileTap={{scale: 0.95}} key={lvl} onClick={() => setSelectedLevel(lvl)} className={`py-4 rounded-2xl font-black text-sm transition-all border-2 ${selectedLevel === lvl ? 'bg-gray-900 text-white border-gray-900 shadow-xl' : 'bg-gray-50 text-gray-400 border-transparent hover:bg-gray-100'}`}>{lvl}</motion.button>)}</div>
                    {inputMode !== 'READING' && (
                        <div className="bg-gray-50/50 p-8 rounded-[2rem] border border-gray-100 shadow-inner">
                          <div className="flex justify-between mb-6"><label className="block text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">όΧ╕ώΘΠώΒ╕όΥΘ</label><span className="text-4xl font-black text-gray-900 tracking-tighter">{recommendCount}</span></div>
                          <input type="range" min="1" max="20" value={recommendCount} onChange={(e) => setRecommendCount(parseInt(e.target.value))} className="w-full h-3 bg-gray-200 rounded-full appearance-none cursor-pointer accent-gray-900 shadow-inner" />
                        </div>
                    )}
                    <Button onClick={handleLearn} fullWidth disabled={loading} className="py-5 text-lg">{loading ? 'AI όφμίερίΓβϋς▓ϊ╕φ...' : inputMode === 'READING' ? 'ύΦθόΙΡόΟρϋΨοόΨΘύτι' : `ύΦθόΙΡ ${recommendCount} ίΑΜόΟρϋΨοίΖπίχ╣`}</Button>
                  </div>
                )}
             </motion.div>
             {!loading && (currentDefinitions.length > 0 || currentGrammar.length > 0) && (
               <div className="space-y-8">
                 <div className="flex items-center justify-between px-4"><h3 className="text-2xl font-black text-gray-900 tracking-tighter uppercase">ϋπμόηΡύ╡Ρόηε</h3><Button variant="glass" className="py-2 px-6 rounded-xl" onClick={() => setQuizConfig({ sourceWords: currentDefinitions, sourceGrammar: currentGrammar, dateLabel: "ί┐τώΑθϋνΘύ┐Τ" }) || setMode(AppMode.QUIZ)}>ί░Πϋσοϋ║τόΚΜ</Button></div>
                 <div className="grid gap-8 md:grid-cols-2">{currentDefinitions.map((w, i) => <WordCard key={i} layoutId={`${w.word}-${i}`} data={w} onClick={() => setSelectedWordId(`${w.word}-${i}`)} />)}</div>
                 <div className="grid gap-8">{currentGrammar.map((g, i) => <GrammarCard key={i} layoutId={g.id || `g-${i}`} data={g} onClick={() => setSelectedGrammarId(g.id || `g-${i}`)} />)}</div>
               </div>
             )}
             {!loading && currentReading && <ReadingView material={currentReading} />}
          </div>
        );
      case AppMode.HISTORY:
        return (
          <div className="max-w-3xl mx-auto pb-20 px-2">
             <div className="mb-12 bg-white p-12 rounded-[3rem] border border-gray-100 shadow-sm flex flex-col md:flex-row items-center gap-12 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-48 bg-gray-50/50 rounded-full transform translate-x-1/2 -translate-y-1/2 z-0" />
                <div className="relative z-10 flex flex-col items-center">
                  <div className="w-36 h-36 flex items-center justify-center bg-gray-900 rounded-full text-7xl shadow-2xl border-4 border-white relative group">
                    <motion.span animate={{ rotate: [0, -5, 5, 0] }} transition={{ repeat: Infinity, duration: 4 }}>ΏθΣ╗</motion.span>
                    <AnimatePresence>{xpToast && <motion.div key={xpToast.id} initial={{ opacity: 0, y: 0, scale: 0.5 }} animate={{ opacity: 1, y: -90, scale: 1.5 }} exit={{ opacity: 0 }} className="absolute top-0 right-[-60px] text-green-500 font-black text-3xl drop-shadow-xl z-20">+{xpToast.amount} XP</motion.div>}</AnimatePresence>
                  </div>
                  <span className="mt-6 font-black text-gray-900 text-2xl tracking-tighter">ίλρώζΙ Lv.{petStats.level}</span>
                </div>
                <div className="flex-1 w-full relative z-10">
                   <h3 className="text-3xl font-black text-gray-900 mb-10 text-center md:text-left tracking-tighter">ίφ╕ύ┐ΤόΙΡί░▒</h3>
                   <div className="grid grid-cols-3 gap-6 text-center">
                     <div className="bg-gray-50/80 backdrop-blur-sm rounded-[2rem] p-6 border border-white/50 shadow-sm"><span className="block text-4xl font-black text-gray-900 tracking-tighter">{Math.floor(petStats.totalFocusMinutes / 60)}h</span><span className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-2 block">ί░Ιό│ρόβΓώΨΥ</span></div>
                     <div className="bg-gray-50/80 backdrop-blur-sm rounded-[2rem] p-6 border border-white/50 shadow-sm"><span className="block text-4xl font-black text-gray-900 tracking-tighter">{totalWordsLearned}</span><span className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-2 block">ίΨχίφΩώΘΠ</span></div>
                     <div className="bg-gray-50/80 backdrop-blur-sm rounded-[2rem] p-6 border border-white/50 shadow-sm"><span className="block text-4xl font-black text-gray-900 tracking-tighter">{totalGrammarLearned}</span><span className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-2 block">όΨΘό│ΧώΘΠ</span></div>
                   </div>
                   <div className="mt-10 px-2">
                     <div className="flex justify-between text-[10px] font-black text-gray-400 mb-3 uppercase tracking-widest"><span>όΙΡώΧ╖ώΑ▓ί║ο</span><span>{petStats.currentXp} / {petStats.nextLevelXp} XP</span></div>
                     <div className="w-full bg-gray-100/50 rounded-full h-4 shadow-inner overflow-hidden border border-gray-100"><motion.div className="bg-gray-900 h-full shadow-lg" initial={{ width: 0 }} animate={{ width: `${Math.min((petStats.currentXp / petStats.nextLevelXp) * 100, 100)}%` }} transition={{ duration: 1.5, type: "spring" }} /></div>
                </div>
             </div>
             </div>
             <div className="mb-16 px-2"><h3 className="text-xl font-black text-gray-900 mb-8 uppercase tracking-widest px-4 border-l-8 border-gray-900">όοχϋφ╜ί╛╜ύτι</h3><div className="grid grid-cols-2 md:grid-cols-3 gap-6">{ACHIEVEMENTS.map(ach => <motion.button key={ach.id} onClick={() => setSelectedAchievement(ach)} whileHover={{ scale: 1.05, y: -8 }} whileTap={{ scale: 0.95 }} className={`p-8 rounded-[2.5rem] border transition-all ${petStats.unlockedAchievements.includes(ach.id) ? 'bg-white border-yellow-100 shadow-xl shadow-yellow-50' : 'bg-gray-50 border-gray-100 opacity-60 grayscale'}`}><div className="text-6xl mb-6">{petStats.unlockedAchievements.includes(ach.id) ? ach.icon : 'ΏθΦΤ'}</div><h4 className="font-black text-sm text-gray-900 tracking-tight">{ach.title}</h4></motion.button>)}</div></div>
             <h2 className="text-3xl font-black text-gray-900 mb-10 px-6 uppercase tracking-tighter">όφ╖ίΠ▓όΩξϋςΝ</h2>
             {history.length === 0 ? <div className="text-center py-32 text-gray-300 bg-gray-50 rounded-[3rem] border border-dashed border-gray-200 font-black text-xl">ώΓΕό▓ΤόεΚύ┤ΑώΝΕίΨΦΎ╝ΝώΨΜίπΜίφ╕ύ┐ΤίΡπΎ╝Β</div> : (
               <div className="space-y-8 px-2">{history.map((record) => {
                   const isExpanded = expandedHistoryId === record.id;
                   return (
                     <motion.div key={record.id} layout className={`bg-white rounded-[2.5rem] border overflow-hidden transition-all duration-500 shadow-sm ${isExpanded ? 'border-gray-900 shadow-2xl shadow-gray-100 ring-8 ring-gray-50' : 'border-gray-100 hover:border-gray-300'}`}>
