                            <Button variant="glass" className="text-xs font-black py-2 px-6 rounded-xl" onClick={(e) => { e.stopPropagation(); setQuizConfig({ sourceWords: record.words || [], sourceGrammar: record.grammar || [], dateLabel: `ϋνΘύ┐Τ: ${record.date}` }); setMode(AppMode.QUIZ); }}>ϋνΘύ┐Τό╕υώσΩ</Button>
                            <motion.div animate={{ rotate: isExpanded ? 180 : 0 }} className="text-gray-200"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-8 h-8"><path strokeLinecap="round" strokeLinejoin="round" d="M19.5 8.25l-7.5 7.5-7.5-7.5" /></svg></motion.div>
                         </div>
                       </div>
                       <AnimatePresence>{isExpanded && (
                           <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="overflow-hidden border-t border-gray-50 bg-gray-50/30 p-10 space-y-10">
                             {record.words?.length > 0 && (
                               <div>
                                 <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mb-6">ίφ╕ύ┐ΤίΨχίφΩ</h4>
                                 <div className="flex flex-wrap gap-4">{record.words.map((w, i) => (
                                    <motion.button key={i} layoutId={`${w.word}-history-${record.id}-${i}`} whileHover={{ scale: 1.1, y: -5 }} whileTap={{ scale: 0.95 }} onClick={() => setSelectedWordId(`${w.word}-history-${record.id}-${i}`)} className="bg-white border border-gray-100 px-6 py-4 rounded-2xl text-base font-black shadow-sm text-gray-800 hover:border-gray-900 hover:shadow-xl transition-all">
                                      {w.word}
