                             {record.grammar?.length > 0 && (
                               <div>
                                 <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mb-6">ίφ╕ύ┐ΤόΨΘό│Χ</h4>
                                 <div className="flex flex-wrap gap-4">{record.grammar.map((g, i) => (
                                    <motion.button key={i} layoutId={`g-h-${record.id}-${i}`} whileHover={{ scale: 1.1, y: -5 }} whileTap={{ scale: 0.95 }} onClick={() => setSelectedGrammarId(`g-h-${record.id}-${i}`)} className="bg-gray-900 text-white border border-gray-900 px-6 py-4 rounded-2xl text-base font-black shadow-lg hover:bg-black hover:shadow-2xl transition-all">
                                      {g.grammarPoint}
                                    </motion.button>
                                 ))}</div>
                               </div>
                             )}
                           </motion.div>
                       )}</AnimatePresence>
                     </motion.div>
                   );
               })}</div>
             )}
          </div>
        );
      case AppMode.CHAT: return <ChatInterface onBack={() => setMode(AppMode.LEARN)} onXpUpdate={updatePetXp} />;
      case AppMode.QUIZ: return quizConfig ? <Quiz sourceWords={quizConfig.sourceWords} sourceGrammar={quizConfig.sourceGrammar} title={quizConfig.dateLabel} onExit={() => setMode(AppMode.LEARN)} /> : null;
      case AppMode.FOCUS: return <div className="max-w-3xl mx-auto flex flex-col items-center justify-center min-h-[70vh] space-y-20 py-10"><PomodoroTimer state={timerState} onToggle={toggleTimer} onReset={resetTimer} onSwitchMode={() => setTimerState(prev => ({ ...prev, mode: prev.mode === 'FOCUS' ? 'BREAK' : 'FOCUS', isActive: false, timeLeft: (prev.mode === 'FOCUS' ? prev.breakDuration : prev.focusDuration) * 60 }))} onUpdateSettings={(f, b) => setTimerState(prev => ({ ...prev, focusDuration: f, breakDuration: b, timeLeft: f * 60 }))} /><PetCompanion stats={petStats} onClick={() => updatePetXp(1)} /></div>;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-gray-900 selection:text-white">
