            <div><h1 className="text-2xl font-black tracking-tighter text-gray-900 hidden sm:block">Mono-Kuro</h1><p className="text-[10px] font-black text-gray-300 uppercase tracking-[0.3em] leading-none hidden sm:block">Japanese Learner</p></div>
            <div className="flex items-center ml-6">{isSyncing ? <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }} className="w-5 h-5 border-4 border-gray-900 border-t-transparent rounded-full" /> : <div className="flex items-center gap-2 bg-gray-50/80 px-4 py-2 rounded-full border border-gray-100 shadow-inner group-hover:bg-green-50 group-hover:border-green-100 transition-colors"><div className="w-2 h-2 bg-green-500 rounded-full shadow-lg animate-pulse" /><span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] hidden group-hover:block text-green-600">ί╖▓ώδ▓ύτψίΕ▓ίφα</span></div>}</div>
          </div>
          <nav className="flex space-x-3 bg-gray-50/50 p-2 rounded-[1.5rem] shadow-inner border border-gray-100 overflow-x-auto no-scrollbar">
            {[{m:AppMode.LEARN, i:<BookIcon/>, l:'ίφ╕ύ┐Τ'}, {m:AppMode.CHAT, i:<ChatIcon/>, l:'ϋςηϊ╝┤'}, {m:AppMode.HISTORY, i:<ClockIcon/>, l:'ύ┤ΑώΝΕ'}, {m:AppMode.FOCUS, i:<FocusIcon/>, l:'ί░Ιό│ρ'}].map(nav => (
                <button key={nav.m} onClick={() => setMode(nav.m)} className={`px-6 py-3 rounded-2xl text-sm font-black transition-all flex items-center space-x-2 ${mode === nav.m ? 'bg-white text-gray-900 shadow-xl transform scale-105 ring-4 ring-gray-100/50' : 'text-gray-400 hover:text-gray-600'}`}>
                    {nav.i}<span className="hidden md:inline">{nav.l}</span>
                </button>
            ))}
          </nav>
        </div>
      </header>
      <main className="max-w-5xl mx-auto px-4 py-12 relative z-0">
        <AnimatePresence mode="wait"><motion.div key={mode} initial={{ opacity: 0, scale: 0.97, y: 10 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 1.03, y: -10 }} transition={{ duration: 0.4, type: "spring", damping: 20 }}>{renderContent()}</motion.div></AnimatePresence>
      </main>
      <AnimatePresence>{mode !== AppMode.FOCUS && (timerState.isActive || timerState.timeLeft !== timerState.focusDuration * 60) && <MiniTimer state={timerState} onClick={() => setMode(AppMode.FOCUS)} />}</AnimatePresence>
      <AnimatePresence>{newAchievement && <motion.div initial={{ opacity: 0, y: 150, scale: 0.8 }} animate={{ opacity: 1, y: 0, scale: 1 }} exit={{ opacity: 0, scale: 0.5 }} className="fixed bottom-40 left-1/2 -translate-x-1/2 z-50 bg-gray-900 text-white px-10 py-6 rounded-[3rem] shadow-[0_35px_60px_-15px_rgba(0,0,0,0.5)] flex items-center space-x-8 border border-gray-800"><div className="text-7xl">{newAchievement.icon}</div><div><p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em]">όΙΡί░▒ϋπμώΟΨΎ╝Β</p><p className="font-black text-2xl tracking-tight">{newAchievement.title}</p></div></motion.div>}</AnimatePresence>
      <AnimatePresence>{selectedAchievement && <div className="fixed inset-0 z-[70] flex items-center justify-center bg-gray-900/60 backdrop-blur-2xl p-6" onClick={() => setSelectedAchievement(null)}><motion.div initial={{ scale: 0.85, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.85, opacity: 0 }} className="bg-white rounded-[4rem] p-16 max-w-md w-full text-center shadow-[0_50px_100px_-20px_rgba(0,0,0,0.3)] relative" onClick={e => e.stopPropagation()}><div className="text-[120px] mb-12 drop-shadow-2xl">{selectedAchievement.icon}</div><h3 className="text-4xl font-black mb-6 text-gray-900 tracking-tighter">{selectedAchievement.title}</h3><p className="text-gray-500 mb-10 text-xl leading-relaxed font-bold tracking-tight">{selectedAchievement.description}</p><div className={`text-xs font-black py-3 px-10 rounded-full inline-block shadow-lg ${petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-400'}`}>{petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'ί╖▓όΦ╢ϋΩΠ' : 'όεςώΒΦόΙΡ'}</div></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedWordId && <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-gray-900/50 backdrop-blur-2xl" onClick={() => setSelectedWordId(null)}><motion.div className="w-full max-w-lg" onClick={e => e.stopPropagation()}><WordCard layoutId={selectedWordId} data={findWord(selectedWordId)!} isExpanded onClose={() => setSelectedWordId(null)} /></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedGrammarId && <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-gray-900/50 backdrop-blur-2xl" onClick={() => setSelectedGrammarId(null)}><motion.div className="w-full max-w-2xl" onClick={e => e.stopPropagation()}><GrammarCard layoutId={selectedGrammarId} data={findGrammar(selectedGrammarId)!} isExpanded onClose={() => setSelectedGrammarId(null)} /></motion.div></div>}</AnimatePresence>
      {mode !== AppMode.FOCUS && mode !== AppMode.QUIZ && mode !== AppMode.CHAT && <div className="fixed bottom-12 right-12 z-50"><PetCompanion stats={petStats} compact onClick={() => updatePetXp(1)} /></div>}
      <footer className="py-20 text-center text-gray-300 text-xs font-black uppercase tracking-[0.4em]"><p>Mono-Kuro Nihongo έΑλ Built with Heart</p></footer>
    </div>
  );
}
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordDefinition, DailyRecord, AppMode, QuizConfig, InputMode, GrammarDefinition, PetStats, Achievement, TimerState, ReadingMaterial } from './types';
import { fetchWordDefinitions, fetchGrammarDetails, fetchRecommendedWords, fetchRecommendedGrammar, analyzeReadingText, generateRecommendedReading } from './services/geminiService';
import { WordCard } from './components/WordCard';
import { GrammarCard } from './components/GrammarCard';
import { ReadingView } from './components/ReadingView';
import { ChatInterface } from './components/ChatInterface';
import { Quiz } from './components/Quiz';
import { Button } from './components/Button';
import { Loader } from './components/Loader';
import { PetCompanion } from './components/PetCompanion';
import { PomodoroTimer } from './components/PomodoroTimer';
import { MiniTimer } from './components/MiniTimer';

// Icons
const BookIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 006 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 016 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 016-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0018 18a8.967 8.967 0 00-6 2.292m0-14.25v14.25" /></svg>;
const ClockIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6h4.5m4.5 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const FocusIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4"><path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" /></svg>;
const ChatIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4"><path strokeLinecap="round" strokeLinejoin="round" d="M20.25 8.511c.884.284 1.5 1.128 1.5 2.097v4.286c0 1.136-.847 2.1-1.98 2.193-.34.027-.68.052-1.02.072v3.091l-3-3c-1.354 0-2.694-.055-4.02-.163a2.115 2.115 0 01-.825-.242m9.345-8.334a2.126 2.126 0 00-.476-.095 48.64 48.64 0 00-8.048 0c-1.131.094-1.976 1.057-1.976 2.192v4.286c0 .837.46 1.58 1.155 1.951m9.345-8.334V6.637c0-1.621-1.152-3.026-2.76-3.235A48.455 48.455 0 0011.25 3c-2.115 0-4.198.137-6.24.402-1.608.209-2.76 1.614-2.76 3.235v6.226c0 1.621 1.152 3.026 2.76 3.235.577.075 1.157.14 1.74.194V21l4.155-4.155" /></svg>;

const ACHIEVEMENTS: Achievement[] = [
  { id: 'first_step', title: 'ίΙζίΘ║ϋΝΖί╗υ', description: 'ίχΝόΙΡύυυϊ╕Αόυκί░Ιό│ρύ╖┤ύ┐Τ', icon: 'ΏθΝ▒', condition: (stats) => stats.totalFocusMinutes >= 1 },
  { id: 'focus_master_bronze', title: 'ί░Ιό│ρόΨ░όΚΜ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 60 ίΙΗώΡα', icon: 'ΏθξΚ', condition: (stats) => stats.totalFocusMinutes >= 60 },
  { id: 'focus_master_silver', title: 'ί░Ιό│ρώΒΦϊ║║', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 300 ίΙΗώΡα', icon: 'ΏθξΙ', condition: (stats) => stats.totalFocusMinutes >= 300 },
  { id: 'focus_master_gold', title: 'ύοςίχγίνπί╕τ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 1000 ίΙΗώΡα', icon: 'ΏθξΘ', condition: (stats) => stats.totalFocusMinutes >= 1000 },
  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 },
  { id: 'level_10', title: 'ίλρώζΙϊ╣ΜίΠΜ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10', icon: 'ΏθΣΣ', condition: (stats) => stats.level >= 10 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);
        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
