  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 },
  { id: 'level_10', title: 'ίλρώζΙϊ╣ΜίΠΜ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10', icon: 'ΏθΣΣ', condition: (stats) => stats.level >= 10 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);
        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await generateRecommendedReading(selectedLevel); setCurrentReading(newReading); }
      }

      const today = new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          newHistory[existingIndex] = {
            ...newHistory[existingIndex],
            words: [...(newHistory[existingIndex].words || []), ...(newWords || [])],
            grammar: [...(newHistory[existingIndex].grammar || []), ...(newGrammar || [])],
            readings: newReading ? [...(newHistory[existingIndex].readings || []), newReading] : newHistory[existingIndex].readings
          };
          return newHistory;
        } else {
          return [{ id: Date.now().toString(), date: today, words: newWords || [], grammar: newGrammar || [], readings: newReading ? [newReading] : [] }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      let xp = inputMode === 'WORD' ? newWords.length * 5 : inputMode === 'GRAMMAR' ? newGrammar.length * 15 : newReading ? 50 : 10;
      updatePetXp(Math.max(xp, 10));
    } catch (error) { alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ"); } finally { setLoading(false); }
  };

  const handleTimerComplete = () => {
    setTimerState(prev => ({ ...prev, isActive: false, timeLeft: 0, endTime: undefined }));
    if (timerState.mode === 'FOCUS') { updatePetXp(50, timerState.focusDuration); setShowCelebration(true); }
    else { resetTimer(); }
  };

  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, endTime: undefined, timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60 }));
  const toggleTimer = () => setTimerState(prev => {
    const isStarting = !prev.isActive;
    return isStarting ? { ...prev, isActive: true, endTime: Date.now() + (prev.timeLeft * 1000) } : { ...prev, isActive: false, endTime: undefined };
  });

  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const findWord = (id: string | null) => {
    if (!id) return null;
    const match = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (match) return match;
    if (id.includes('-history-')) {
       const parts = id.split('-history-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.words[idx] || null;
    }
    return null;
  };

  const findGrammar = (id: string | null) => {
    if (!id) return null;
    const match = currentGrammar.find(g => g.id === id);
    if (match) return match;
    if (id.includes('g-h-')) {
       const parts = id.split('g-h-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.grammar?.[idx] || null;
    }
    return null;
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-2xl mx-auto space-y-6 pb-16 px-2">
             <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} className="bg-white/70 backdrop-blur-2xl p-6 rounded-[1.8rem] shadow-sm border border-white/60 ring-1 ring-black/5 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-20 h-20 bg-gray-50/50 rounded-full translate-x-1/2 -translate-y-1/2" />
                <div className="relative z-10 flex flex-col md:flex-row md:justify-between md:items-center gap-4 mb-6">
                  <h2 className="text-xl font-black text-gray-900 tracking-tighter">όΔ│ίφ╕ώ╗ηϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-2 flex-wrap">
                     <div className="flex bg-gray-50/50 p-1 rounded-xl border border-gray-100/30 shadow-inner">
                      {['WORD', 'GRAMMAR', 'READING'].map(m => (
                        <button key={m} onClick={() => setInputMode(m as InputMode)} className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${inputMode === m ? 'bg-white shadow-md text-gray-900 border border-black/5' : 'text-gray-400 hover:text-gray-600'}`}>
                          {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                        </button>
                      ))}
                    </div>
                    <div className="flex bg-gray-50/50 p-1 rounded-xl border border-gray-100/30 shadow-inner">
                      <button onClick={() => setLearningMethod('MANUAL')} className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${learningMethod === 'MANUAL' ? 'bg-white shadow-md text-gray-900 border border-black/5' : 'text-gray-400 hover:text-gray-600'}`}>ϋ╝╕ίΖξ</button>
                      <button onClick={() => setLearningMethod('RECOMMEND')} className={`px-3 py-1 text-[10px] font-black rounded-lg transition-all ${learningMethod === 'RECOMMEND' ? 'bg-gray-900 text-white shadow-md' : 'text-gray-400 hover:text-gray-600'}`}>όΟρϋΨοέερ</button>
                    </div>
                  </div>
                </div>
                {learningMethod === 'MANUAL' ? (
                  <div className="relative">
                    <textarea className="w-full p-5 bg-gray-50/30 border border-gray-100/50 rounded-2xl focus:ring-2 focus:ring-gray-100 outline-none text-base text-gray-900 font-bold transition-all resize-none h-32 placeholder-gray-300 shadow-inner" placeholder={inputMode === 'WORD' ? "ϊ╛ΜίοΓ: ύΝτ ώμθήΒ╣ήΓΜ" : inputMode === 'GRAMMAR' ? "ϊ╛ΜίοΓ: Ύ╜ηώΑγήΓΛήΒτ" : "ϋ▓╝ϊ╕ΛόΨΘύτι..."} value={input} onChange={(e) => setInput(e.target.value)} />
                    <div className="absolute bottom-4 right-4"><Button onClick={handleLearn} disabled={loading} variant="liquid" className="text-[10px] px-4 py-1.5">{loading ? '...' : 'ώΨΜίπΜϋπμόηΡ'}</Button></div>
                  </div>
                ) : (
                  <div className="space-y-5">
                    <div className="grid grid-cols-5 gap-1.5">{(['N5', 'N4', 'N3', 'N2', 'N1'] as JLPTLevel[]).map(lvl => <motion.button whileHover={{ y: -1 }} whileTap={{scale: 0.95}} key={lvl} onClick={() => setSelectedLevel(lvl)} className={`py-2 rounded-lg font-black text-[10px] transition-all border ${selectedLevel === lvl ? 'bg-gray-900 text-white border-gray-900 shadow-md' : 'bg-gray-50/50 text-gray-400 border-transparent hover:bg-gray-100'}`}>{lvl}</motion.button>)}</div>
                    {inputMode !== 'READING' && (
                        <div className="bg-gray-50/30 p-4 rounded-2xl border border-gray-100/30 shadow-inner">
                          <div className="flex justify-between mb-3"><label className="block text-[8px] font-black text-gray-400 uppercase tracking-[0.2em]">όΧ╕ώΘΠ</label><span className="text-2xl font-black text-gray-900 tracking-tighter">{recommendCount}</span></div>
                          <input type="range" min="1" max="20" value={recommendCount} onChange={(e) => setRecommendCount(parseInt(e.target.value))} className="w-full h-1.5 bg-gray-200 rounded-full appearance-none cursor-pointer accent-gray-900" />
                        </div>
                    )}
                    <Button onClick={handleLearn} fullWidth disabled={loading} className="py-3 text-sm">{loading ? 'ίΓβϋς▓ϊ╕φ...' : 'ύΦθόΙΡίΖπίχ╣'}</Button>
                  </div>
                )}
             </motion.div>
             {!loading && (currentDefinitions.length > 0 || currentGrammar.length > 0) && (
               <div className="space-y-5">
                 <div className="flex items-center justify-between px-2"><h3 className="text-sm font-black text-gray-900 tracking-tighter uppercase">ϋπμόηΡύ╡Ρόηε</h3><Button variant="liquid" className="py-1 px-3 rounded-lg text-[10px]" onClick={() => setQuizConfig({ sourceWords: currentDefinitions, sourceGrammar: currentGrammar, dateLabel: "ί┐τώΑθϋνΘύ┐Τ" }) || setMode(AppMode.QUIZ)}>ί░Πϋσοϋ║τόΚΜ</Button></div>
                 <div className="grid gap-4 md:grid-cols-2">{currentDefinitions.map((w, i) => <WordCard key={i} layoutId={`${w.word}-${i}`} data={w} onClick={() => setSelectedWordId(`${w.word}-${i}`)} />)}</div>
                 <div className="grid gap-4">{currentGrammar.map((g, i) => <GrammarCard key={i} layoutId={g.id || `g-${i}`} data={g} onClick={() => setSelectedGrammarId(g.id || `g-${i}`)} />)}</div>
               </div>
             )}
             {!loading && currentReading && <ReadingView material={currentReading} />}
          </div>
        );
      case AppMode.HISTORY:
        return (
          <div className="max-w-2xl mx-auto pb-16 px-2">
             <div className="mb-8 bg-white/70 backdrop-blur-2xl p-6 rounded-[2rem] border border-white/50 shadow-sm flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 p-32 bg-gray-50/30 rounded-full transform translate-x-1/2 -translate-y-1/2 z-0" />
                <div className="relative z-10 flex flex-col items-center">
                  <div className="w-24 h-24 flex items-center justify-center bg-gray-900 rounded-full text-4xl shadow-xl border-4 border-white relative group">
                    <motion.span animate={{ rotate: [0, -2, 2, 0] }} transition={{ repeat: Infinity, duration: 4 }}>ΏθΣ╗</motion.span>
                    <AnimatePresence>{xpToast && <motion.div key={xpToast.id} initial={{ opacity: 0, y: 0, scale: 0.5 }} animate={{ opacity: 1, y: -60, scale: 1.3 }} exit={{ opacity: 0 }} className="absolute top-0 right-[-30px] text-green-500 font-black text-xl drop-shadow-xl z-20">+{xpToast.amount}</motion.div>}</AnimatePresence>
                  </div>
                  <span className="mt-3 font-black text-gray-900 text-lg tracking-tighter">ίλρώζΙ Lv.{petStats.level}</span>
                </div>
                <div className="flex-1 w-full relative z-10">
                   <h3 className="text-xl font-black text-gray-900 mb-6 text-center md:text-left tracking-tighter">ίφ╕ύ┐ΤόΙΡί░▒</h3>
                   <div className="grid grid-cols-3 gap-3 text-center">
                     <div className="bg-white/40 backdrop-blur-md rounded-xl p-3 border border-white/40 shadow-sm"><span className="block text-xl font-black text-gray-900 tracking-tighter">{Math.floor(petStats.totalFocusMinutes / 60)}h</span><span className="text-[8px] font-black text-gray-400 uppercase tracking-widest mt-1 block">ί░Ιό│ρ</span></div>
                     <div className="bg-white/40 backdrop-blur-md rounded-xl p-3 border border-white/40 shadow-sm"><span className="block text-xl font-black text-gray-900 tracking-tighter">{totalWordsLearned}</span><span className="text-[8px] font-black text-gray-400 uppercase tracking-widest mt-1 block">ίΨχίφΩ</span></div>
                     <div className="bg-white/40 backdrop-blur-md rounded-xl p-3 border border-white/40 shadow-sm"><span className="block text-xl font-black text-gray-900 tracking-tighter">{totalGrammarLearned}</span><span className="text-[8px] font-black text-gray-400 uppercase tracking-widest mt-1 block">όΨΘό│Χ</span></div>
                   </div>
                   <div className="mt-6 px-1">
                     <div className="flex justify-between text-[8px] font-black text-gray-400 mb-1.5 uppercase tracking-widest"><span>ώΑ▓ί║ο</span><span>{petStats.currentXp} / {petStats.nextLevelXp}</span></div>
                     <div className="w-full bg-gray-100/50 rounded-full h-2 shadow-inner overflow-hidden border border-gray-100"><motion.div className="bg-gray-900 h-full" initial={{ width: 0 }} animate={{ width: `${Math.min((petStats.currentXp / petStats.nextLevelXp) * 100, 100)}%` }} transition={{ duration: 1, type: "spring" }} /></div>
                </div>
             </div>
             </div>
             <div className="mb-10 px-1"><h3 className="text-sm font-black text-gray-900 mb-5 uppercase tracking-widest px-2 border-l-4 border-gray-900">ίΜ│ύτι</h3><div className="grid grid-cols-3 gap-3">{ACHIEVEMENTS.map(ach => <motion.button key={ach.id} onClick={() => setSelectedAchievement(ach)} whileHover={{ scale: 1.05, y: -2 }} whileTap={{ scale: 0.95 }} className={`p-4 rounded-2xl border transition-all ${petStats.unlockedAchievements.includes(ach.id) ? 'bg-white border-yellow-100 shadow-md ring-1 ring-yellow-50/50' : 'bg-gray-50/50 border-gray-100 opacity-60 grayscale'}`}><div className="text-3xl mb-3">{petStats.unlockedAchievements.includes(ach.id) ? ach.icon : 'ΏθΦΤ'}</div><h4 className="font-black text-[9px] text-gray-900 tracking-tight leading-tight">{ach.title}</h4></motion.button>)}</div></div>
             <h2 className="text-xl font-black text-gray-900 mb-6 px-3 uppercase tracking-tighter">όφ╖ίΠ▓όΩξϋςΝ</h2>
             {history.length === 0 ? <div className="text-center py-16 text-gray-300 bg-gray-50/50 rounded-[2rem] border border-dashed border-gray-200 font-black text-sm">όγτύΕκίφ╕ύ┐Τύ┤ΑώΝΕ</div> : (
               <div className="space-y-4 px-1">{history.map((record) => {
                   const isExpanded = expandedHistoryId === record.id;
                   return (
                     <motion.div key={record.id} layout className={`bg-white/80 backdrop-blur-xl rounded-[1.5rem] border overflow-hidden transition-all duration-300 ${isExpanded ? 'border-gray-900 shadow-lg ring-2 ring-gray-50' : 'border-gray-100 hover:border-gray-200 shadow-sm'}`}>
                       <div className="p-6 cursor-pointer flex justify-between items-center" onClick={() => setExpandedHistoryId(isExpanded ? null : record.id)}>
                         <div className="flex items-center gap-5">
                            <motion.div animate={{ rotate: isExpanded ? 360 : 0 }} className={`w-9 h-9 rounded-lg flex items-center justify-center transition-all ${isExpanded ? 'bg-gray-900 text-white shadow-md' : 'bg-gray-50/50 text-gray-400'}`}><ClockIcon /></motion.div>
                            <div><h3 className="text-base font-black text-gray-900 tracking-tighter">{record.date}</h3><p className="text-gray-400 text-[8px] font-black uppercase tracking-widest mt-0.5">{(record.words?.length || 0)} ίΨχίφΩ έΑλ {(record.grammar?.length || 0)} όΨΘό│Χ</p></div>
                         </div>
                         <div className="flex gap-2">
                            <Button variant="liquid" className="text-[8px] font-black py-1 px-3 rounded-md" onClick={(e) => { e.stopPropagation(); setQuizConfig({ sourceWords: record.words || [], sourceGrammar: record.grammar || [], dateLabel: `ϋνΘύ┐Τ: ${record.date}` }); setMode(AppMode.QUIZ); }}>ό╕υώσΩ</Button>
                            <motion.div animate={{ rotate: isExpanded ? 180 : 0 }} className="text-gray-200"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M19.5 8.25l-7.5 7.5-7.5-7.5" /></svg></motion.div>
                         </div>
                       </div>
                       <AnimatePresence>{isExpanded && (
                           <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="overflow-hidden border-t border-gray-50 bg-gray-50/10 p-6 space-y-6">
                             {record.words?.length > 0 && (
                               <div>
                                 <h4 className="text-[8px] font-black text-gray-400 uppercase tracking-[0.3em] mb-3">ί╖▓ίφ╕ίΨχίφΩ</h4>
                                 <div className="flex flex-wrap gap-2.5">{record.words.map((w, i) => (
                                    <motion.button key={i} layoutId={`${w.word}-history-${record.id}-${i}`} whileHover={{ scale: 1.05, y: -1 }} whileTap={{ scale: 0.95 }} onClick={() => setSelectedWordId(`${w.word}-history-${record.id}-${i}`)} className="bg-white border border-gray-100 px-3 py-2 rounded-lg text-xs font-black shadow-sm text-gray-800 hover:border-gray-800 transition-all border-white/50 ring-1 ring-black/5">
                                      {w.word}
                                    </motion.button>
                                 ))}</div>
                               </div>
                             )}
                             {record.grammar?.length > 0 && (
                               <div>
                                 <h4 className="text-[8px] font-black text-gray-400 uppercase tracking-[0.3em] mb-3">ί╖▓ίφ╕όΨΘό│Χ</h4>
                                 <div className="flex flex-wrap gap-2.5">{record.grammar.map((g, i) => (
                                    <motion.button key={i} layoutId={`g-h-${record.id}-${i}`} whileHover={{ scale: 1.05, y: -1 }} whileTap={{ scale: 0.95 }} onClick={() => setSelectedGrammarId(`g-h-${record.id}-${i}`)} className="bg-gray-900 text-white border border-gray-900 px-3 py-2 rounded-lg text-xs font-black shadow-md hover:bg-black transition-all">
                                      {g.grammarPoint}
                                    </motion.button>
                                 ))}</div>
                               </div>
                             )}
                           </motion.div>
                       )}</AnimatePresence>
                     </motion.div>
                   );
               })}</div>
             )}
          </div>
        );
      case AppMode.CHAT: return <ChatInterface onBack={() => setMode(AppMode.LEARN)} onXpUpdate={updatePetXp} />;
      case AppMode.QUIZ: return quizConfig ? <Quiz sourceWords={quizConfig.sourceWords} sourceGrammar={quizConfig.sourceGrammar} title={quizConfig.dateLabel} onExit={() => setMode(AppMode.LEARN)} /> : null;
      case AppMode.FOCUS: return <div className="max-w-2xl mx-auto flex flex-col items-center justify-center min-h-[50vh] space-y-12 py-6"><PomodoroTimer state={timerState} onToggle={toggleTimer} onReset={resetTimer} onSwitchMode={() => setTimerState(prev => ({ ...prev, mode: prev.mode === 'FOCUS' ? 'BREAK' : 'FOCUS', isActive: false, timeLeft: (prev.mode === 'FOCUS' ? prev.breakDuration : prev.focusDuration) * 60 }))} onUpdateSettings={(f, b) => setTimerState(prev => ({ ...prev, focusDuration: f, breakDuration: b, timeLeft: f * 60 }))} /><PetCompanion stats={petStats} onClick={() => updatePetXp(1)} /></div>;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-gray-900 selection:text-white">
      <header className="bg-white/50 backdrop-blur-2xl sticky top-0 z-40 border-b border-white/20 shadow-sm">
        <div className="max-w-2xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2.5 cursor-pointer group" onClick={() => setMode(AppMode.LEARN)}>
            <motion.div whileHover={{ scale: 1.1, rotate: 10 }} className="w-8 h-8 bg-gray-900 rounded-lg flex items-center justify-center text-white font-black text-lg shadow-lg">όΩξ</motion.div>
            <div><h1 className="text-base font-black tracking-tighter text-gray-900 hidden sm:block">Mono-Kuro</h1><p className="text-[7px] font-black text-gray-300 uppercase tracking-[0.2em] leading-none hidden sm:block">Japanese Learner</p></div>
            <div className="flex items-center ml-3">{isSyncing ? <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1.2, ease: "linear" }} className="w-3 h-3 border-2 border-gray-900 border-t-transparent rounded-full" /> : <div className="flex items-center gap-1 bg-gray-50/50 px-2.5 py-1 rounded-full border border-gray-100/30 group-hover:bg-green-50 transition-colors"><div className="w-1 h-1 bg-green-500 rounded-full animate-pulse" /><span className="text-[7px] font-black text-gray-400 uppercase tracking-[0.1em] hidden group-hover:block">SAVED</span></div>}</div>
          </div>
          <nav className="flex space-x-1.5 bg-gray-50/30 p-1 rounded-[1.2rem] shadow-inner border border-white/20 overflow-x-auto no-scrollbar">
            {[{m:AppMode.LEARN, i:<BookIcon/>, l:'ίφ╕ύ┐Τ'}, {m:AppMode.CHAT, i:<ChatIcon/>, l:'ϋςηϊ╝┤'}, {m:AppMode.HISTORY, i:<ClockIcon/>, l:'ύ┤ΑώΝΕ'}, {m:AppMode.FOCUS, i:<FocusIcon/>, l:'ί░Ιό│ρ'}].map(nav => (
                <button key={nav.m} onClick={() => setMode(nav.m)} className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all flex items-center space-x-1.5 ${mode === nav.m ? 'bg-white text-gray-900 shadow-sm ring-2 ring-black/5' : 'text-gray-400 hover:text-gray-600'}`}>
                    {nav.i}<span className="hidden md:inline">{nav.l}</span>
                </button>
            ))}
          </nav>
        </div>
      </header>
      <main className="max-w-2xl mx-auto px-4 py-8 relative z-0">
        <AnimatePresence mode="wait"><motion.div key={mode} initial={{ opacity: 0, scale: 0.99, y: 3 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 1.01, y: -3 }} transition={{ duration: 0.25 }}>{renderContent()}</motion.div></AnimatePresence>
      </main>
      <AnimatePresence>{mode !== AppMode.FOCUS && (timerState.isActive || timerState.timeLeft !== timerState.focusDuration * 60) && <MiniTimer state={timerState} onClick={() => setMode(AppMode.FOCUS)} />}</AnimatePresence>
      <AnimatePresence>{newAchievement && <motion.div initial={{ opacity: 0, y: 80, scale: 0.8 }} animate={{ opacity: 1, y: 0, scale: 1 }} exit={{ opacity: 0, scale: 0.5 }} className="fixed bottom-24 left-1/2 -translate-x-1/2 z-50 bg-gray-900/90 backdrop-blur-xl text-white px-6 py-4 rounded-[2rem] shadow-2xl flex items-center space-x-5 border border-white/10"><div className="text-4xl">{newAchievement.icon}</div><div><p className="text-[8px] font-black text-gray-400 uppercase tracking-[0.2em]">όΙΡί░▒ϋπμώΟΨΎ╝Β</p><p className="font-black text-lg tracking-tight">{newAchievement.title}</p></div></motion.div>}</AnimatePresence>
      <AnimatePresence>{selectedAchievement && <div className="fixed inset-0 z-[70] flex items-center justify-center bg-gray-900/40 backdrop-blur-2xl p-6" onClick={() => setSelectedAchievement(null)}><motion.div initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }} className="bg-white rounded-[2.5rem] p-10 max-w-xs w-full text-center shadow-2xl relative border border-white/20" onClick={e => e.stopPropagation()}><div className="text-8xl mb-8 drop-shadow-xl">{selectedAchievement.icon}</div><h3 className="text-2xl font-black mb-3 text-gray-900 tracking-tighter">{selectedAchievement.title}</h3><p className="text-gray-500 mb-6 text-base leading-relaxed font-bold tracking-tight">{selectedAchievement.description}</p><div className={`text-[8px] font-black py-2 px-6 rounded-full inline-block shadow-sm ${petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'bg-gray-900 text-white' : 'bg-gray-100 text-gray-400'}`}>{petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'COLLECTED' : 'LOCKED'}</div></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedWordId && <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-gray-900/20 backdrop-blur-xl" onClick={() => setSelectedWordId(null)}><motion.div className="w-full max-w-sm" onClick={e => e.stopPropagation()}><WordCard layoutId={selectedWordId} data={findWord(selectedWordId)!} isExpanded onClose={() => setSelectedWordId(null)} /></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedGrammarId && <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-gray-900/20 backdrop-blur-xl" onClick={() => setSelectedGrammarId(null)}><motion.div className="w-full max-w-lg" onClick={e => e.stopPropagation()}><GrammarCard layoutId={selectedGrammarId} data={findGrammar(selectedGrammarId)!} isExpanded onClose={() => setSelectedGrammarId(null)} /></motion.div></div>}</AnimatePresence>
      {mode !== AppMode.FOCUS && mode !== AppMode.QUIZ && mode !== AppMode.CHAT && <div className="fixed bottom-8 right-8 z-50"><PetCompanion stats={petStats} compact onClick={() => updatePetXp(1)} /></div>}
      <footer className="py-12 text-center text-gray-300 text-[8px] font-black uppercase tracking-[0.2em]"><p>Mono-Kuro Nihongo έΑλ Compact Glass</p></footer>
    </div>
  );
}
export default App;

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordDefinition, DailyRecord, AppMode, QuizConfig, InputMode, GrammarDefinition, PetStats, Achievement, TimerState, ReadingMaterial } from './types';
import { fetchWordDefinitions, fetchGrammarDetails, fetchRecommendedWords, fetchRecommendedGrammar, analyzeReadingText, generateRecommendedReading } from './services/geminiService';
import { WordCard } from './components/WordCard';
import { GrammarCard } from './components/GrammarCard';
import { ReadingView } from './components/ReadingView';
import { ChatInterface } from './components/ChatInterface';
import { Quiz } from './components/Quiz';
import { Button } from './components/Button';
import { Loader } from './components/Loader';
import { PetCompanion } from './components/PetCompanion';
import { PomodoroTimer } from './components/PomodoroTimer';
import { MiniTimer } from './components/MiniTimer';

// Icons
const BookIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 006 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 016 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 016-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0018 18a8.967 8.967 0 00-6 2.292m0-14.25v14.25" /></svg>;
const ClockIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6h4.5m4.5 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const FocusIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 3v2.25m6.364.386l-1.591 1.591M21 12h-2.25m-.386 6.364l-1.591-1.591M12 18.75V21m-4.773-4.227l-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" /></svg>;
const ChatIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M20.25 8.511c.884.284 1.5 1.128 1.5 2.097v4.286c0 1.136-.847 2.1-1.98 2.193-.34.027-.68.052-1.02.072v3.091l-3-3c-1.354 0-2.694-.055-4.02-.163a2.115 2.115 0 01-.825-.242m9.345-8.334a2.126 2.126 0 00-.476-.095 48.64 48.64 0 00-8.048 0c-1.131.094-1.976 1.057-1.976 2.192v4.286c0 .837.46 1.58 1.155 1.951m9.345-8.334V6.637c0-1.621-1.152-3.026-2.76-3.235A48.455 48.455 0 0011.25 3c-2.115 0-4.198.137-6.24.402-1.608.209-2.76 1.614-2.76 3.235v6.226c0 1.621 1.152 3.026 2.76 3.235.577.075 1.157.14 1.74.194V21l4.155-4.155" /></svg>;

const ACHIEVEMENTS: Achievement[] = [
  { id: 'first_step', title: 'ίΙζίΘ║ϋΝΖί╗υ', description: 'ίχΝόΙΡύυυϊ╕Αόυκί░Ιό│ρύ╖┤ύ┐Τ', icon: 'ΏθΝ▒', condition: (stats) => stats.totalFocusMinutes >= 1 },
  { id: 'focus_master_bronze', title: 'ί░Ιό│ρόΨ░όΚΜ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 60 ίΙΗώΡα', icon: 'ΏθξΚ', condition: (stats) => stats.totalFocusMinutes >= 60 },
  { id: 'focus_master_silver', title: 'ί░Ιό│ρώΒΦϊ║║', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 300 ίΙΗώΡα', icon: 'ΏθξΙ', condition: (stats) => stats.totalFocusMinutes >= 300 },
  { id: 'focus_master_gold', title: 'ύοςίχγίνπί╕τ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 1000 ίΙΗώΡα', icon: 'ΏθξΘ', condition: (stats) => stats.totalFocusMinutes >= 1000 },
  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 },
  { id: 'level_10', title: 'ίλρώζΙϊ╣ΜίΠΜ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10', icon: 'ΏθΣΣ', condition: (stats) => stats.level >= 10 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);
    if (inputMode === 'WORD') setCurrentGrammar([]);
    else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
    else setCurrentReading(null);

    try {
      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);
        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await generateRecommendedReading(selectedLevel); setCurrentReading(newReading); }
      }

      const today = new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          newHistory[existingIndex] = {
            ...newHistory[existingIndex],
            words: [...(newHistory[existingIndex].words || []), ...(newWords || [])],
            grammar: [...(newHistory[existingIndex].grammar || []), ...(newGrammar || [])],
            readings: newReading ? [...(newHistory[existingIndex].readings || []), newReading] : newHistory[existingIndex].readings
          };
          return newHistory;
        } else {
          return [{ id: Date.now().toString(), date: today, words: newWords || [], grammar: newGrammar || [], readings: newReading ? [newReading] : [] }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      let xp = inputMode === 'WORD' ? newWords.length * 5 : inputMode === 'GRAMMAR' ? newGrammar.length * 15 : newReading ? 50 : 10;
      updatePetXp(Math.max(xp, 10));
    } catch (error) { alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ"); } finally { setLoading(false); }
  };

  const handleTimerComplete = () => {
    setTimerState(prev => ({ ...prev, isActive: false, timeLeft: 0, endTime: undefined }));
    if (timerState.mode === 'FOCUS') { updatePetXp(50, timerState.focusDuration); setShowCelebration(true); }
    else { resetTimer(); }
  };

  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, endTime: undefined, timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60 }));
  const toggleTimer = () => setTimerState(prev => {
    const isStarting = !prev.isActive;
    return isStarting ? { ...prev, isActive: true, endTime: Date.now() + (prev.timeLeft * 1000) } : { ...prev, isActive: false, endTime: undefined };
  });

  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const findWord = (id: string | null) => {
    if (!id) return null;
    const match = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (match) return match;
    if (id.includes('-history-')) {
       const parts = id.split('-history-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.words[idx] || null;
    }
    return null;
  };

  const findGrammar = (id: string | null) => {
    if (!id) return null;
    const match = currentGrammar.find(g => g.id === id);
    if (match) return match;
    if (id.includes('g-h-')) {
       const parts = id.split('g-h-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.grammar?.[idx] || null;
    }
    return null;
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-3xl mx-auto space-y-8 pb-16 px-2">
             <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} className="bg-white/70 backdrop-blur-2xl p-8 rounded-[2.2rem] shadow-sm border border-white/60 ring-1 ring-black/5 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-24 h-24 bg-gray-50/50 rounded-full translate-x-1/2 -translate-y-1/2" />
                <div className="relative z-10 flex flex-col md:flex-row md:justify-between md:items-center gap-5 mb-8">
                  <h2 className="text-2xl font-black text-gray-900 tracking-tighter">όΔ│ίφ╕ώ╗ηϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-3 flex-wrap">
                     <div className="flex bg-gray-50/50 p-1.5 rounded-xl border border-gray-100/30 shadow-inner">
                      {['WORD', 'GRAMMAR', 'READING'].map(m => (
                        <button key={m} onClick={() => setInputMode(m as InputMode)} className={`px-4 py-2 text-xs font-black rounded-lg transition-all ${inputMode === m ? 'bg-white shadow-md text-gray-900 border border-black/5' : 'text-gray-400 hover:text-gray-600'}`}>
                          {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                        </button>
                      ))}
                    </div>
                    <div className="flex bg-gray-50/50 p-1.5 rounded-xl border border-gray-100/30 shadow-inner">
