interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'glass' | 'liquid';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'liquid', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-2xl font-black transition-all duration-500 flex items-center justify-center space-x-2 focus:outline-none overflow-hidden relative group text-[13px] tracking-tight";

  const variants = {
    primary: "bg-gray-900 text-white hover:bg-black shadow-xl shadow-gray-200 ring-1 ring-white/10",
    secondary: "bg-gray-100 text-gray-800 hover:bg-gray-200",
    outline: "bg-transparent border-2 border-gray-200 text-gray-500 hover:border-gray-800 hover:text-gray-800",
    glass: "bg-white/40 backdrop-blur-md border border-white/60 text-gray-800 shadow-lg hover:bg-white/60",
    liquid: "bg-white/40 backdrop-blur-2xl border border-white/50 ring-1 ring-white/30 text-gray-900 shadow-[0_10px_40px_0_rgba(31,38,135,0.08)] hover:bg-white/60 hover:shadow-[0_10px_40px_0_rgba(31,38,135,0.18)]"
  };

  return (
    <motion.button
      whileHover={{ scale: 1.02, y: -2 }}
      whileTap={{ scale: 0.96 }}
      transition={{ type: "spring", stiffness: 500, damping: 20 }}
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {/* Liquid Reflection Effect */}
      <motion.div 
        className="absolute inset-0 w-1/2 h-full bg-gradient-to-r from-transparent via-white/50 to-transparent skew-x-[-35deg] -translate-x-full pointer-events-none"
