const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);
  const [showCelebration, setShowCelebration] = useState(false);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
