      <AnimatePresence>{newAchievement && <motion.div initial={{ opacity: 0, y: 100, scale: 0.8 }} animate={{ opacity: 1, y: 0, scale: 1 }} exit={{ opacity: 0, scale: 0.5 }} className="fixed bottom-32 left-1/2 -translate-x-1/2 z-50 bg-gray-800/95 backdrop-blur-xl text-white px-8 py-5 rounded-[2.5rem] shadow-2xl flex items-center space-x-6 border border-white/10"><div className="text-5xl">{newAchievement.icon}</div><div><p className="text-[9px] font-black text-gray-400 uppercase tracking-[0.3em]">όΙΡί░▒ϋπμώΟΨΎ╝Β</p><p className="font-black text-xl tracking-tight">{newAchievement.title}</p></div></motion.div>}</AnimatePresence>
      <AnimatePresence>{selectedAchievement && <div className="fixed inset-0 z-[70] flex items-center justify-center bg-gray-900/40 backdrop-blur-2xl p-6" onClick={() => setSelectedAchievement(null)}><motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="bg-white rounded-[3rem] p-12 max-w-sm w-full text-center shadow-2xl relative border border-white/20" onClick={e => e.stopPropagation()}><div className="text-8xl mb-8 drop-shadow-xl">{selectedAchievement.icon}</div><h3 className="text-3xl font-black mb-4 text-gray-700 tracking-tighter">{selectedAchievement.title}</h3><p className="text-gray-500 mb-8 text-lg leading-relaxed font-bold tracking-tight">{selectedAchievement.description}</p><div className={`text-[10px] font-black py-2.5 px-8 rounded-full inline-block shadow-sm ${petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'bg-gray-800 text-white' : 'bg-gray-100 text-gray-400'}`}>{petStats.unlockedAchievements.includes(selectedAchievement.id) ? 'ί╖▓ώΒΦόΙΡ' : 'όεςώΒΦόΙΡ'}</div></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedWordId && <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-gray-900/20 backdrop-blur-xl" onClick={() => setSelectedWordId(null)}><motion.div className="w-full max-w-md" onClick={e => e.stopPropagation()}><WordCard layoutId={selectedWordId} data={findWord(selectedWordId)!} isExpanded onClose={() => setSelectedWordId(null)} /></motion.div></div>}</AnimatePresence>
      <AnimatePresence>{selectedGrammarId && <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-gray-900/20 backdrop-blur-xl" onClick={() => setSelectedGrammarId(null)}><motion.div className="w-full max-w-xl" onClick={e => e.stopPropagation()}><GrammarCard layoutId={selectedGrammarId} data={findGrammar(selectedGrammarId)!} isExpanded onClose={() => setSelectedGrammarId(null)} /></motion.div></div>}</AnimatePresence>
      {mode !== AppMode.FOCUS && mode !== AppMode.QUIZ && mode !== AppMode.CHAT && <div className="fixed bottom-10 right-10 z-50"><PetCompanion stats={petStats} compact onClick={() => updatePetXp(1)} /></div>}
      <footer className="py-16 text-center text-gray-300 text-[10px] font-black uppercase tracking-[0.3em]"><p>Mono-Kuro Nihongo έΑλ Muted Glass</p></footer>
    </div>
  );
}
export default App;

