export const generateQuizFromContent = async (words: WordDefinition[], grammar: GrammarDefinition[], specificPrompt?: string): Promise<QuizQuestion[]> => {
  try {
    const contentContext = JSON.stringify({ words, grammar, specificPrompt });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `
      You are an expert Japanese quiz generator.
      Task: Create EXACTLY 15 multiple-choice questions based on: ${contentContext}.

      Question Types Mix:
      - 3 Translation (JP to ZH-TW)
      - 3 Kanji/Reading identification
      - 3 Particle Usage (e.g., ήΒψ, ήΒΝ, ήΒτ, ήΒπ)
      - 3 Contextual Fill-in-the-blank
      - 3 Sentence Reconstruction (Correct order of segments)

      Guidelines:
      - Prompts in Traditional Chinese (Taiwan).
      - Difficulty should match the input context.
      - Detailed explanations in Traditional Chinese.
      - Return EXACTLY 15 questions.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: quizSchema,
      },
    });
    return JSON.parse(response.text) as QuizQuestion[];
  } catch (error) { throw error; }
};

export const getChatResponse = async (history: ChatMessage[], newMessage: string, replyContext?: string): Promise<any> => {
  try {
    const conversationContext = history.slice(-10).map(msg => `${msg.role === 'user' ? 'Student' : 'Teacher'}: ${msg.text}`).join('\n');
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Japanese Tutor. Context: ${conversationContext}. New: ${newMessage}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: chatResponseSchema
      }
    });
    return JSON.parse(response.text);
  } catch (error) { throw error; }
};

