const ACHIEVEMENTS: Achievement[] = [
  { id: 'first_step', title: 'ίΙζίΘ║ϋΝΖί╗υ', description: 'ίχΝόΙΡύυυϊ╕Αόυκί░Ιό│ρύ╖┤ύ┐Τ', icon: 'ΏθΝ▒', condition: (stats) => stats.totalFocusMinutes >= 1 },
  { id: 'focus_master_bronze', title: 'ί░Ιό│ρόΨ░όΚΜ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 60 ίΙΗώΡα', icon: 'ΏθξΚ', condition: (stats) => stats.totalFocusMinutes >= 60 },
  { id: 'focus_master_silver', title: 'ί░Ιό│ρώΒΦϊ║║', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 300 ίΙΗώΡα', icon: 'Ίι╛Ί╡Ι', condition: (stats) => stats.totalFocusMinutes >= 300 },
  { id: 'focus_master_gold', title: 'ύοςίχγίνπί╕τ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 1000 ίΙΗώΡα', icon: 'ΏθξΘ', condition: (stats) => stats.totalFocusMinutes >= 1000 },
  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 },
  { id: 'level_10', title: 'ίλρώζΙϊ╣ΜίΠΜ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 10', icon: 'ΏθΣΣ', condition: (stats) => stats.level >= 10 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND' | 'QUIZ';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [isSyncing, setIsSyncing] = useState(false);

  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    if (saved) {
      try { return JSON.parse(saved); } catch (e) { return []; }
    }
    return [];
  });

  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
        return parsed;
      } catch (e) { return INITIAL_PET_STATS; }
    }
    return INITIAL_PET_STATS;
  });

  const isFirstMount = useRef(true);

  useEffect(() => {
    if (isFirstMount.current) {
        isFirstMount.current = false;
        return;
    }
    setIsSyncing(true);
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    const timer = setTimeout(() => setIsSyncing(false), 800);
    return () => clearTimeout(timer);
  }, [history, petStats]);

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [expandedHistoryId, setExpandedHistoryId] = useState<string | null>(null);
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);

  const [timerState, setTimerState] = useState<TimerState>({
    isActive: false,
    mode: 'FOCUS',
    focusDuration: 25,
    breakDuration: 5,
    timeLeft: 25 * 60,
  });

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive && timerState.endTime) {
      interval = window.setInterval(() => {
        const now = Date.now();
        const newTimeLeft = Math.ceil((timerState.endTime! - now) / 1000);
        if (newTimeLeft <= 0) {
          handleTimerComplete();
        } else {
           setTimerState(prev => prev.timeLeft === newTimeLeft ? prev : { ...prev, timeLeft: newTimeLeft });
        }
      }, 200); 
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive, timerState.endTime]);

  useEffect(() => {
    const newlyUnlocked: string[] = [];
    ACHIEVEMENTS.forEach(ach => {
      if (!petStats.unlockedAchievements.includes(ach.id) && ach.condition(petStats)) {
        newlyUnlocked.push(ach.id);
        setNewAchievement(ach);
      }
    });
    if (newlyUnlocked.length > 0) {
      setPetStats(prev => ({ ...prev, unlockedAchievements: [...prev.unlockedAchievements, ...newlyUnlocked] }));
      setTimeout(() => setNewAchievement(null), 5000);
    }
  }, [petStats.totalFocusMinutes, petStats.level]);

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const handleLearn = async () => {
    if (learningMethod === 'MANUAL' && !input.trim()) return;
    setLoading(true);

    try {
      if (learningMethod === 'QUIZ') {
         // Direct Quiz Mode
         const questions = await generateQuizFromContent([], [], input);
         setQuizConfig({ sourceWords: [], sourceGrammar: [], dateLabel: "ί░ΙώιΖύ╖┤ύ┐Τ" });
         setMode(AppMode.QUIZ);
         setLoading(false);
         return;
      }

      if (inputMode === 'WORD') setCurrentGrammar([]);
      else if (inputMode === 'GRAMMAR') setCurrentDefinitions([]);
      else setCurrentReading(null);

      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') { newWords = await fetchWordDefinitions(input); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchGrammarDetails(input); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await analyzeReadingText(input); setCurrentReading(newReading); }
      } else {
        const excludedWords = history.flatMap(rec => rec.words?.map(w => w.word) || []);
        const excludedGrammar = history.flatMap(rec => rec.grammar?.map(g => g.grammarPoint) || []);
        if (inputMode === 'WORD') { newWords = await fetchRecommendedWords(selectedLevel, recommendCount, excludedWords); setCurrentDefinitions(newWords); }
        else if (inputMode === 'GRAMMAR') { newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, excludedGrammar); setCurrentGrammar(newGrammar); }
        else if (inputMode === 'READING') { newReading = await generateRecommendedReading(selectedLevel); setCurrentReading(newReading); }
      }

      const today = new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
      setHistory(prev => {
        const existingIndex = prev.findIndex(h => h.date === today);
        if (existingIndex >= 0) {
          const newHistory = [...prev];
          newHistory[existingIndex] = {
            ...newHistory[existingIndex],
            words: [...(newHistory[existingIndex].words || []), ...(newWords || [])],
            grammar: [...(newHistory[existingIndex].grammar || []), ...(newGrammar || [])],
            readings: newReading ? [...(newHistory[existingIndex].readings || []), newReading] : newHistory[existingIndex].readings
          };
          return newHistory;
        } else {
          return [{ id: Date.now().toString(), date: today, words: newWords || [], grammar: newGrammar || [], readings: newReading ? [newReading] : [] }, ...prev];
        }
      });

      if (learningMethod === 'MANUAL') setInput('');
      let xp = inputMode === 'WORD' ? newWords.length * 5 : inputMode === 'GRAMMAR' ? newGrammar.length * 15 : newReading ? 50 : 10;
      updatePetXp(Math.max(xp, 10));
    } catch (error) { alert("ύβ╝ύΦθώΝψϋςνΎ╝ΝϋτΜώΘΞϋσοήΑΓ"); } finally { setLoading(false); }
  };

  const handleTimerComplete = () => {
    setTimerState(prev => ({ ...prev, isActive: false, timeLeft: 0, endTime: undefined }));
    if (timerState.mode === 'FOCUS') { updatePetXp(50, timerState.focusDuration); }
    else { resetTimer(); }
  };

  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, endTime: undefined, timeLeft: prev.mode === 'FOCUS' ? prev.focusDuration * 60 : prev.breakDuration * 60 }));
  const toggleTimer = () => setTimerState(prev => {
    const isStarting = !prev.isActive;
    return isStarting ? { ...prev, isActive: true, endTime: Date.now() + (prev.timeLeft * 1000) } : { ...prev, isActive: false, endTime: undefined };
  });

  const totalWordsLearned = history.reduce((acc, curr) => acc + (curr.words?.length || 0), 0);
  const totalGrammarLearned = history.reduce((acc, curr) => acc + (curr.grammar?.length || 0), 0);

  const findWord = (id: string | null) => {
    if (!id) return null;
    const match = currentDefinitions.find((w, i) => `${w.word}-${i}` === id);
    if (match) return match;
    if (id.includes('-history-')) {
       const parts = id.split('-history-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.words[idx] || null;
    }
    return null;
  };

  const findGrammar = (id: string | null) => {
    if (!id) return null;
    const match = currentGrammar.find(g => g.id === id);
    if (match) return match;
    if (id.includes('g-h-')) {
       const parts = id.split('g-h-')[1].split('-');
       const recId = parts[0];
       const idx = parseInt(parts[1]);
       const rec = history.find(h => h.id === recId);
       return rec?.grammar?.[idx] || null;
    }
    return null;
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="max-w-3xl mx-auto space-y-8 pb-16 px-2">
             <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} className="bg-white/40 backdrop-blur-3xl p-8 rounded-[2.2rem] shadow-sm border border-white/60 ring-1 ring-black/5 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-full translate-x-1/2 -translate-y-1/2" />
                <div className="relative z-10 flex flex-col md:flex-row md:justify-between md:items-center gap-5 mb-8">
                  <h2 className="text-xl font-bold text-gray-500 tracking-tighter">όΔ│ίφ╕ώ╗ηϊ╗Αώ║╝Ύ╝θ</h2>
                  <div className="flex gap-3 flex-wrap">
                     <div className="flex bg-white/10 backdrop-blur-xl p-1.5 rounded-xl border border-white/40 shadow-inner relative">
                      {['WORD', 'GRAMMAR', 'READING'].map(m => (
                        <button key={m} onClick={() => { setInputMode(m as InputMode); if(learningMethod==='QUIZ') setLearningMethod('MANUAL'); }} className={`px-4 py-2 text-xs font-black rounded-lg transition-all relative z-10 ${inputMode === m ? 'text-gray-700' : 'text-gray-400 hover:text-gray-500'}`}>
                          {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                          {inputMode === m && (
                            <motion.div layoutId="input-mode-pill" className="absolute inset-0 bg-white shadow-md rounded-lg border border-black/5 -z-10" transition={{ type: "spring", bounce: 0.25, duration: 0.5 }} />
                          )}
                        </button>
                      ))}
                    </div>
                    <div className="flex bg-white/10 backdrop-blur-xl p-1.5 rounded-xl border border-white/40 shadow-inner relative">
                      {['MANUAL', 'RECOMMEND', 'QUIZ'].map(m => (
                        <button key={m} onClick={() => setLearningMethod(m as LearningMethod)} className={`px-4 py-2 text-xs font-black rounded-lg transition-all relative z-10 ${learningMethod === m ? (m === 'QUIZ' ? 'text-indigo-600' : (m === 'RECOMMEND' ? 'text-white' : 'text-gray-800')) : 'text-gray-400 hover:text-gray-500'}`}>
                          {m === 'MANUAL' ? 'ϋ╝╕ίΖξ' : m === 'RECOMMEND' ? 'όΟρϋΨοέερ' : 'ό╕υώσΩΏθΟψ'}
                          {learningMethod === m && (
                            <motion.div layoutId="method-mode-pill" className={`absolute inset-0 shadow-md rounded-lg -z-10 ${m === 'RECOMMEND' ? 'bg-gray-800 ring-1 ring-white/40' : (m === 'QUIZ' ? 'bg-indigo-50 border border-indigo-200' : 'bg-white border border-black/5')}`} transition={{ type: "spring", bounce: 0.2, duration: 0.6 }} />
                          )}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
                {learningMethod === 'MANUAL' || learningMethod === 'QUIZ' ? (
                  <div className="relative">
                    <textarea 
                      className="w-full p-6 bg-white/10 border border-white/40 rounded-3xl focus:ring-4 focus:ring-indigo-100/30 outline-none text-xl text-gray-700 font-bold transition-all resize-none h-44 placeholder-gray-300 shadow-inner" 
