                         </div>
                       </div>
                       <AnimatePresence>{isExpanded && (
                           <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} transition={{ type: "spring", damping: 25, stiffness: 200 }} className="overflow-hidden border-t border-white/20 bg-white/10 p-8 space-y-8">
                             {record.words?.length > 0 && (
                               <div>
                                 <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mb-4">ίφ╕ύ┐ΤίΨχίφΩ</h4>
                                 <div className="flex flex-wrap gap-3">{record.words.map((w, i) => (
                                    <motion.button key={i} layoutId={`${w.word}-history-${record.id}-${i}`} whileHover={{ scale: 1.05, y: -2 }} whileTap={{ scale: 0.95 }} onClick={() => setSelectedWordId(`${w.word}-history-${record.id}-${i}`)} className="bg-white/80 border border-white/50 px-4 py-3 rounded-xl text-sm font-black shadow-sm text-gray-700 hover:border-gray-800 transition-all ring-1 ring-black/5">
                                      {w.word}
