                                 ))}</div>
                               </div>
                             )}
                             {record.grammar?.length > 0 && (
                               <div>
                                 <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mb-4">ίφ╕ύ┐ΤόΨΘό│Χ</h4>
                                 <div className="flex flex-wrap gap-3">{record.grammar.map((g, i) => (
                                    <motion.button key={i} layoutId={`g-h-${record.id}-${i}`} whileHover={{ scale: 1.05, y: -2 }} whileTap={{ scale: 0.95 }} onClick={() => setSelectedGrammarId(`g-h-${record.id}-${i}`)} className="bg-gray-800 text-white border border-gray-800 px-4 py-3 rounded-xl text-sm font-black shadow-md hover:bg-black transition-all">
                                      {g.grammarPoint}
                                    </motion.button>
                                 ))}</div>
                               </div>
                             )}
                           </motion.div>
                       )}</AnimatePresence>
                     </motion.div>
                   );
               })}</div>
             )}
          </div>
        );
      case AppMode.CHAT: return <ChatInterface onBack={() => setMode(AppMode.LEARN)} onXpUpdate={updatePetXp} />;
      case AppMode.QUIZ: return quizConfig ? <Quiz sourceWords={quizConfig.sourceWords} sourceGrammar={quizConfig.sourceGrammar} title={quizConfig.dateLabel} onExit={() => setMode(AppMode.LEARN)} /> : null;
      case AppMode.FOCUS: return <div className="max-w-3xl mx-auto flex flex-col items-center justify-center min-h-[55vh] space-y-14 py-8"><PomodoroTimer state={timerState} onToggle={toggleTimer} onReset={resetTimer} onSwitchMode={() => setTimerState(prev => ({ ...prev, mode: prev.mode === 'FOCUS' ? 'BREAK' : 'FOCUS', isActive: false, timeLeft: (prev.mode === 'FOCUS' ? prev.breakDuration : prev.focusDuration) * 60 }))} onUpdateSettings={(f, b) => setTimerState(prev => ({ ...prev, focusDuration: f, breakDuration: b, timeLeft: f * 60 }))} /><PetCompanion stats={petStats} onClick={() => updatePetXp(1)} /></div>;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-zinc-100 text-gray-700 font-sans selection:bg-gray-800 selection:text-white">
