import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { generateQuizFromContent } from '../services/geminiService';
import { WordDefinition, GrammarDefinition, QuizQuestion } from '../types';
import { Loader } from './Loader';
import { Button } from './Button';

interface QuizProps {
  sourceWords: WordDefinition[];
  sourceGrammar: GrammarDefinition[];
  onExit: () => void;
  title?: string;
}

export const Quiz: React.FC<QuizProps> = ({ sourceWords, sourceGrammar, onExit, title }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [userAnswers, setUserAnswers] = useState<(number | null)[]>([]);
  const [showResult, setShowResult] = useState(false);
  const [selectedReviewIndex, setSelectedReviewIndex] = useState<number | null>(null);

  useEffect(() => {
    const loadQuiz = async () => {
      try {
        const qs = await generateQuizFromContent(sourceWords, sourceGrammar);
        setQuestions(qs);
        setUserAnswers(new Array(qs.length).fill(null));
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    loadQuiz();
  }, [sourceWords, sourceGrammar]);

  const handleAnswer = (optionIndex: number) => {
    if (userAnswers[currentIndex] !== null) return;
    const newAnswers = [...userAnswers];
    newAnswers[currentIndex] = optionIndex;
    setUserAnswers(newAnswers);

    setTimeout(() => {
      if (currentIndex < questions.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        setShowResult(true);
      }
    }, 1200);
  };

  const calculateScore = () => userAnswers.reduce((acc, ans, idx) => acc + (ans === questions[idx].correctAnswerIndex ? 1 : 0), 0);

  if (loading) return <div className="h-64 flex items-center justify-center"><Loader text="ίΘ║ώκΝϊ╕φ..." /></div>;

  if (questions.length === 0) return (
    <div className="text-center p-8 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border border-white/60 ring-1 ring-black/5">
      <p className="text-gray-500 mb-6 font-bold">ύδχίΚΞόγτόβΓύΕκό│ΧύΦθόΙΡό╕υώσΩΎ╝ΝϋτΜύρΞί╛ΝίΗΞϋσοήΑΓ</p>
      <Button onClick={onExit} variant="liquid">ϋ┐ΦίδηώοΨώιΒ</Button>
    </div>
  );

  if (showResult) {
    const score = calculateScore();
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="max-w-3xl mx-auto pb-20 px-2">
        <div className="text-center mb-10 bg-white/40 backdrop-blur-3xl p-10 rounded-[3rem] border border-white/60 shadow-sm">
          <h2 className="text-2xl font-black text-gray-700 mb-2">ό╕υώσΩύ╡Ρόζθ</h2>
          <div className="text-6xl font-black text-gray-800 mb-4 tracking-tighter">
            {score} <span className="text-2xl text-gray-300 font-bold">/ {questions.length}</span>
          </div>
          <p className="text-gray-400 font-bold mb-8">ϋκρύΠ╛ί╛Ωί╛ΙόμΤΎ╝Βώ╗ηόΥΛϊ╕ΜόΨ╣ώκΝύδχόθξύεΜϋπμόηΡήΑΓ</p>
          <Button onClick={onExit} variant="liquid" className="px-10">ίδηίΙ░ώοΨώιΒ</Button>
        </div>

        <div className="grid gap-4">
          {questions.map((q, idx) => {
            const isCorrect = userAnswers[idx] === q.correctAnswerIndex;
            return (
              <motion.div
                layoutId={`question-card-${idx}`}
                key={q.id}
                onClick={() => setSelectedReviewIndex(idx)}
                className={`p-6 rounded-[1.8rem] border backdrop-blur-xl cursor-pointer transition-all ${
                  isCorrect ? 'bg-white/40 border-white/60 hover:bg-white/60' : 'bg-red-50/20 border-red-100 hover:bg-red-50/40'
                }`}
              >
                <div className="flex items-center gap-5">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-sm shadow-sm ${
                    isCorrect ? 'bg-gray-700 text-white' : 'bg-red-500 text-white'
                  }`}>
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                     <h4 className="text-gray-700 font-bold mb-1 line-clamp-1">{q.question}</h4>
                     <div className="flex items-center gap-3">
                        <span className={`text-[10px] font-black px-2 py-0.5 rounded-lg ${isCorrect ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                          {isCorrect ? 'όφμύλ║' : 'ώΝψϋςν'}
                        </span>
                        {!isCorrect && <span className="text-gray-400 text-xs font-bold tracking-tight">όφμϋπμ: {q.options[q.correctAnswerIndex]}</span>}
                     </div>
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>

        <AnimatePresence>
          {selectedReviewIndex !== null && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-gray-900/40 backdrop-blur-3xl" onClick={() => setSelectedReviewIndex(null)}>
              <motion.div layoutId={`question-card-${selectedReviewIndex}`} className="w-full max-w-lg bg-white/95 backdrop-blur-3xl rounded-[2.8rem] shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
                 <div className="p-8 border-b border-gray-100/50 flex justify-between items-center bg-gray-50/50">
                    <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-widest">Question {selectedReviewIndex + 1} ϋπμόηΡ</h3>
                    <button onClick={() => setSelectedReviewIndex(null)} className="p-2 bg-gray-100 rounded-full text-gray-400 hover:text-gray-600 transition-all shadow-inner">
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                 </div>
                 <div className="p-10 overflow-y-auto no-scrollbar">
                    {questions[selectedReviewIndex].context && <div className="mb-8 p-6 bg-gray-50 border-l-4 border-gray-200 rounded-r-2xl text-gray-700 text-lg font-bold leading-relaxed">{questions[selectedReviewIndex].context}</div>}
                    <h4 className="text-xl font-black text-gray-800 mb-8 leading-snug tracking-tight">{questions[selectedReviewIndex].question}</h4>
                    <div className="space-y-3 mb-10">
                      {questions[selectedReviewIndex].options.map((opt, i) => {
                        const isSelected = userAnswers[selectedReviewIndex] === i;
                        const isCorrect = questions[selectedReviewIndex].correctAnswerIndex === i;
                        let style = "border-gray-100 text-gray-400 bg-gray-50/30";
                        if (isCorrect) style = "border-green-500/30 bg-green-50 text-green-700 font-bold ring-2 ring-green-100";
                        else if (isSelected && !isCorrect) style = "border-red-500/30 bg-red-50 text-red-600 ring-2 ring-red-100";
                        return <div key={i} className={`p-5 border rounded-2xl flex justify-between items-center transition-all ${style}`}><span>{opt}</span>{isCorrect && <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>}</div>;
                      })}
                    </div>
                    <div className="bg-gray-50/80 p-8 rounded-[2rem] border border-gray-100">
                      <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">ϋΑΒί╕τύγΕϋσ▒</h5>
                      <p className="text-gray-600 leading-relaxed font-bold tracking-tight">{questions[selectedReviewIndex].explanation}</p>
                    </div>
                 </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    );
  }

  const currentQ = questions[currentIndex];
  const currentSelected = userAnswers[currentIndex];
  return (
    <div className="max-w-2xl mx-auto px-2">
      <div className="mb-8 flex items-center justify-between px-4">
        <h2 className="text-lg font-black text-gray-500 tracking-tighter uppercase">{title || "ό╕υώσΩώΑ▓ϋκΝϊ╕φ"}</h2>
        <span className="text-xs font-black text-gray-400 bg-white/50 backdrop-blur-xl px-4 py-2 rounded-xl shadow-sm border border-white/60">
          {currentIndex + 1} / {questions.length}
        </span>
      </div>
      <div className="relative min-h-[450px]">
        <AnimatePresence mode="wait">
          <motion.div key={currentQ.id} initial={{ x: 30, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -30, opacity: 0 }} className="bg-white/40 backdrop-blur-3xl rounded-[2.8rem] shadow-sm p-10 border border-white/60 ring-1 ring-black/5">
            {currentQ.context && <div className="mb-8 p-6 bg-gray-50/50 border-l-4 border-gray-300 text-gray-700 leading-relaxed rounded-r-2xl text-lg font-bold shadow-inner">{currentQ.context}</div>}
            <h3 className="text-xl font-black text-gray-800 mb-10 leading-snug tracking-tight">{currentQ.question}</h3>
            <div className="grid gap-4">
              {currentQ.options.map((option, idx) => {
                const isSelected = currentSelected === idx;
                const isCorrect = idx === currentQ.correctAnswerIndex;
                const hasAnswered = currentSelected !== null;
                let btnClass = "bg-white/50 border-white/80 shadow-sm text-gray-600";
                if (hasAnswered) {
                  if (isCorrect) btnClass = "bg-green-50 border-green-200 text-green-700 font-bold shadow-lg shadow-green-100/30 ring-2 ring-green-100";
                  else if (isSelected) btnClass = "bg-red-50 border-red-200 text-red-600 ring-2 ring-red-100";
                  else btnClass = "opacity-40 border-transparent bg-gray-50/20";
                } else btnClass += " hover:bg-white hover:border-gray-300 hover:shadow-md";
                return (
                  <motion.button key={idx} onClick={() => handleAnswer(idx)} className={`w-full text-left p-5 rounded-2xl font-bold transition-all duration-300 relative overflow-hidden border ${btnClass}`} disabled={hasAnswered} whileHover={!hasAnswered ? { y: -2 } : {}} whileTap={!hasAnswered ? { scale: 0.98 } : {}}>
                    <div className="flex justify-between items-center relative z-10">
                        <span className="text-lg tracking-tight">{option}</span>
                        {hasAnswered && isCorrect && <motion.span initial={{ scale: 0 }} animate={{ scale: 1 }} className="text-green-600 bg-white/80 rounded-full p-1 shadow-sm"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg></motion.span>}
                    </div>
                  </motion.button>
                );
              })}
            </div>
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
};

