interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'glass' | 'liquid';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'liquid', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-2xl font-black transition-all duration-700 flex items-center justify-center space-x-2 focus:outline-none overflow-hidden relative group text-[13px] tracking-tight";

  const variants = {
    primary: "bg-gray-800 text-white hover:bg-black shadow-xl shadow-gray-200 ring-1 ring-white/10",
    secondary: "bg-white/20 backdrop-blur-xl text-gray-700 hover:bg-white/30 border border-white/40 shadow-sm",
