      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {/* Background Refraction Pulse (Liquid Flow) */}
      <motion.div 
        className="absolute inset-0 bg-gradient-to-tr from-white/40 via-transparent to-white/20 opacity-0 group-hover:opacity-100 transition-opacity duration-1000"
        initial={false}
