      {/* Liquid Shimmer Effect - Shifting Light */}
      <motion.div 
        className="absolute -inset-[100%] bg-[radial-gradient(circle_at_center,_rgba(255,255,255,0.9)_0%,_transparent_50%)] opacity-0 group-hover:opacity-30 pointer-events-none"
        animate={{
          x: ['-20%', '20%', '-20%'],
          y: ['-10%', '10%', '-10%'],
        }}
        transition={{
          duration: 10,
          repeat: Infinity,
          ease: "linear"
        }}
      />

      {/* Edge Highlight Refraction (Animated) */}
      <div className="absolute inset-0 bg-gradient-to-b from-white/40 via-transparent to-transparent opacity-60 pointer-events-none" />

      {/* Moving Highlight Beam */}
      <motion.div 
        className="absolute inset-0 w-1/3 h-full bg-gradient-to-r from-transparent via-white/50 to-transparent skew-x-[-45deg] -translate-x-full pointer-events-none"
        variants={{
          hover: { x: '350%' }
        }}
        initial={false}
        animate={undefined}
        whileHover="hover"
        transition={{ duration: 1.2, ease: "circOut" }}
      />

      <span className="relative z-10 drop-shadow-[0_1px_1.5px_rgba(255,255,255,1)] font-black">{children}</span>
    </motion.button>
  );
};

