import React from 'react';
import { motion } from 'framer-motion';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'glass' | 'liquid';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'liquid', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "px-8 py-4 rounded-[1.5rem] font-black transition-all duration-700 flex items-center justify-center space-x-3 focus:outline-none overflow-hidden relative group text-[15px] tracking-wide";

  const variants = {
    primary: "bg-gray-900 text-white hover:bg-black shadow-2xl shadow-gray-400/20 ring-1 ring-white/10",
    secondary: "bg-white text-gray-900 hover:bg-gray-50 border border-gray-200 shadow-md",
    outline: "bg-transparent border-2 border-gray-800 text-gray-800 hover:bg-gray-800 hover:text-white",
    glass: "bg-white/40 backdrop-blur-2xl border border-white/20 text-gray-900 shadow-sm",
    liquid: "bg-gray-800 text-white border border-gray-700 ring-1 ring-white/20 shadow-[0_12px_40px_0_rgba(0,0,0,0.2)] hover:bg-black hover:shadow-gray-300 hover:scale-[1.02]"
  };

  return (
    <motion.button
      whileHover={{ y: -3 }}
      whileTap={{ scale: 0.97 }}
      transition={{ type: "spring", stiffness: 400, damping: 25 }}
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {/* Liquid Shimmer Effect - Shifting Light */}
      <motion.div 
        className="absolute -inset-[100%] bg-[radial-gradient(circle_at_center,_rgba(255,255,255,0.2)_0%,_transparent_60%)] opacity-0 group-hover:opacity-40 pointer-events-none"
        animate={{
          x: ['-20%', '20%', '-20%'],
          y: ['-10%', '10%', '-10%'],
        }}
        transition={{
          duration: 5,
          repeat: Infinity,
          ease: "linear"
        }}
      />

      {/* Moving Highlight Beam */}
      <motion.div 
        className="absolute inset-0 w-1/3 h-full bg-gradient-to-r from-transparent via-white/20 to-transparent skew-x-[-45deg] -translate-x-full pointer-events-none"
        variants={{
          hover: { x: '400%' }
        }}
        initial={false}
        animate={undefined}
        whileHover="hover"
        transition={{ duration: 1.5, ease: "circOut" }}
      />

      <span className="relative z-10 font-black">{children}</span>
    </motion.button>
  );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordDefinition } from '../types';

interface WordCardProps {
  data: WordDefinition;
  layoutId: string;
  onClick?: () => void;
  isExpanded?: boolean;
  onClose?: () => void;
}

export const WordCard: React.FC<WordCardProps> = ({ 
  data, 
  layoutId, 
  onClick, 
  isExpanded = false,
  onClose 
}) => {
  const [showSentenceDetail, setShowSentenceDetail] = useState(false);

  return (
    <>
      <motion.div
        layoutId={layoutId}
        onClick={onClick}
        className={`bg-white border border-gray-200 rounded-[2.5rem] shadow-sm overflow-hidden relative ${
          isExpanded 
            ? 'w-full max-w-xl p-12 shadow-[0_32px_64px_-12px_rgba(0,0,0,0.15)] z-50 cursor-default ring-1 ring-black/5' 
            : 'p-10 hover:shadow-2xl hover:shadow-gray-200 hover:border-gray-400 cursor-pointer'
        } transition-all duration-300`}
        initial={isExpanded ? { opacity: 0 } : { opacity: 0, scale: 0.98 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ 
          layout: { type: "spring", stiffness: 300, damping: 30 },
          opacity: { duration: 0.2 }
        }}
      >
        {isExpanded && onClose && (
          <motion.button 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            onClick={(e) => {
              e.stopPropagation();
              onClose();
            }}
