                <div className="p-8 space-y-10 overflow-y-auto max-h-[70vh] no-scrollbar">
                   <div className="text-center space-y-6">
                      <p className="text-2xl font-black text-gray-900 leading-tight tracking-tighter">
                        {data.exampleSentence}
                      </p>
                      <p className="text-lg text-gray-400 font-bold">
                        {data.exampleReading}
                      </p>
                      <div className="w-16 h-1.5 bg-gray-100 mx-auto rounded-full"></div>
                      <p className="text-lg font-bold text-gray-600 tracking-tight leading-relaxed">
                        {data.exampleTranslation}
                      </p>
                   </div>

                   {data.sentenceBreakdown && data.sentenceBreakdown.length > 0 && (
                     <div className="bg-gray-50/50 rounded-3xl p-6 border border-gray-100">
                        <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6">ίΨχίφΩόΜΗϋπμ</h4>
                        <div className="space-y-6">
                           {data.sentenceBreakdown.map((item, idx) => (
                             <div key={idx} className="flex items-center justify-between border-b border-gray-100 last:border-0 pb-4 last:pb-0">
                                <div>
                                   <p className="text-lg font-black text-gray-900 tracking-tight">{item.word}</p>
                                   <p className="text-[10px] text-gray-400 font-bold mt-0.5 uppercase tracking-widest">{item.reading}</p>
                                </div>
                                <div className="text-gray-800 font-black text-sm bg-white px-4 py-2 rounded-xl shadow-sm border border-gray-50">
                                   {item.meaning}
                                </div>
                             </div>
                           ))}
                        </div>
                     </div>
                   )}
                </div>
             </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WordDefinition, DailyRecord, AppMode, QuizConfig, InputMode, GrammarDefinition, PetStats, Achievement, TimerState, ReadingMaterial } from './types';
import { fetchWordDefinitions, fetchGrammarDetails, fetchRecommendedWords, fetchRecommendedGrammar, analyzeReadingText, generateRecommendedReading, generateQuizFromContent } from './services/geminiService';
import { WordCard } from './components/WordCard';
import { GrammarCard } from './components/GrammarCard';
