  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate JLPT ${level} reading practice (150-300 chars). Return JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: readingSchema,
      },
    });
    return { ...JSON.parse(response.text), id: `reading-rec-${Date.now()}` };
  } catch (error) { throw error; }
};

export const generateQuizFromContent = async (words: WordDefinition[], grammar: GrammarDefinition[], specificPrompt?: string): Promise<QuizQuestion[]> => {
  try {
    const contentContext = JSON.stringify({ words, grammar, userCustomContent: specificPrompt });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `
      You are an expert Japanese quiz generator. 
      Your primary source is: ${contentContext}.

      CRITICAL INSTRUCTION:
      1. If 'userCustomContent' is provided, you MUST extract key vocabulary, particles, and sentence patterns from that text to create the quiz.
      2. If 'words' and 'grammar' lists are provided, use them as your primary test items.

      Task: Create EXACTLY 15 multiple-choice questions based on the input.

      Mandatory Question Mix:
      - 3 Fill-in-the-blank (ίκτύσ║ώκΝ): Focusing on particles (ήΒψ, ήΒΝ, ήΒτ, ήΒπ) or verb conjugations.
      - 3 Sentence Ordering (όΟΤί║ΠώκΝ): Users must choose the correct sequence of segments to form a logical sentence.
      - 3 Reading Comprehension (όΨΘύτιώκΝ): Provide a short context (from the user content) and ask about its meaning.
      - 3 Kanji/Reading identification (ϋχΑώθ│ώκΝ): Focus on the kanji in the provided material.
      - 3 Meaning/Usage (ώΒ╕όΥΘώκΝ): General meaning in Traditional Chinese.

      Guidelines:
      - Prompts and Explanations must be in Traditional Chinese (Taiwan).
      - Difficulty should match the input context.
      - Return EXACTLY 15 questions.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: quizSchema,
      },
    });
    return JSON.parse(response.text) as QuizQuestion[];
  } catch (error) { throw error; }
};

export const getChatResponse = async (history: ChatMessage[], newMessage: string, replyContext?: string): Promise<any> => {
  try {
    const conversationContext = history.slice(-10).map(msg => `${msg.role === 'user' ? 'Student' : 'Teacher'}: ${msg.text}`).join('\n');
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Japanese Tutor. Context: ${conversationContext}. New: ${newMessage}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: chatResponseSchema
      }
    });
    return JSON.parse(response.text);
  } catch (error) { throw error; }
};

