                </div>
              </motion.div>
            );
          })}
        </div>

        <AnimatePresence>
          {selectedReviewIndex !== null && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/40 backdrop-blur-md" onClick={() => setSelectedReviewIndex(null)}>
