                 </div>
                 <div className="p-10 overflow-y-auto no-scrollbar space-y-10">
                    {questions[selectedReviewIndex].context && <div className="p-8 bg-gray-50 border-l-8 border-gray-900 rounded-r-3xl text-gray-900 text-xl font-bold leading-relaxed shadow-inner">{questions[selectedReviewIndex].context}</div>}
