      <div className="mb-10 flex items-center justify-between px-6">
        <div>
           <h2 className="text-2xl font-black text-gray-900 tracking-tighter uppercase">{title || "ό╕υώσΩώΑ▓ϋκΝϊ╕φ"}</h2>
           {specificPrompt && <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">ίθ║όΨ╝όΓρύγΕϋ╝╕ίΖξίΖπίχ╣ύΦθόΙΡ</p>}
        </div>
        <span className="text-sm font-black text-white bg-gray-900 px-6 py-2.5 rounded-2xl shadow-xl">
          {currentIndex + 1} / {questions.length}
        </span>
      </div>
      <div className="relative min-h-[500px]">
        <AnimatePresence mode="wait">
          <motion.div key={currentQ.id} initial={{ x: 20, opacity: 0 }} animate={{ x: 0, opacity: 1 }} exit={{ x: -20, opacity: 0 }} className="bg-white rounded-[3rem] shadow-2xl p-12 border border-gray-100 relative">
            {currentQ.context && <div className="mb-10 p-8 bg-gray-50 border-l-8 border-gray-900 text-gray-900 leading-relaxed rounded-r-[2rem] text-xl font-bold shadow-inner">{currentQ.context}</div>}
            <h3 className="text-2xl font-black text-gray-900 mb-12 leading-tight tracking-tighter">{currentQ.question}</h3>
            <div className="grid gap-5">
              {currentQ.options.map((option, idx) => {
                const isSelected = currentSelected === idx;
                const isCorrect = idx === currentQ.correctAnswerIndex;
                const hasAnswered = currentSelected !== null;
                let btnClass = "bg-gray-50 border-gray-100 text-gray-700";
                if (hasAnswered) {
                  if (isCorrect) btnClass = "bg-green-50 border-green-200 text-green-700 font-bold shadow-xl shadow-green-100/20 ring-4 ring-green-100";
                  else if (isSelected) btnClass = "bg-red-50 border-red-200 text-red-600 ring-4 ring-red-100";
                  else btnClass = "opacity-30 border-transparent bg-gray-50/20 grayscale";
                } else btnClass += " hover:bg-white hover:border-gray-900 hover:shadow-xl hover:scale-[1.01]";
                return (
                  <motion.button key={idx} onClick={() => handleAnswer(idx)} className={`w-full text-left p-6 rounded-2xl font-black transition-all duration-300 relative overflow-hidden border ${btnClass}`} disabled={hasAnswered} whileHover={!hasAnswered ? { y: -3 } : {}} whileTap={!hasAnswered ? { scale: 0.98 } : {}}>
                    <div className="flex justify-between items-center relative z-10">
                        <span className="text-xl tracking-tight leading-snug">{option}</span>
                        {hasAnswered && isCorrect && <motion.span initial={{ scale: 0 }} animate={{ scale: 1 }} className="text-green-600 bg-white/80 rounded-full p-2 shadow-md"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={4} stroke="currentColor" className="w-6 h-6"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg></motion.span>}
                    </div>
                  </motion.button>
                );
              })}
            </div>
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
};

export interface SentenceWord {
  word: string;
  reading: string;
  meaning: string;
}

export interface WordDefinition {
  word: string;
  reading: string;
  meaning: string;
  exampleSentence: string;
  exampleReading?: string; // Hiragana reading of the example sentence
  exampleTranslation: string;
  sentenceBreakdown?: SentenceWord[]; // Detailed breakdown of words in the sentence
}

export interface GrammarExample {
  sentence: string;
  reading: string;
  translation: string;
}

export interface GrammarDefinition {
  id: string; // unique internal id
  grammarPoint: string; // e.g., Ύ╜ηήΒοήΒψήΒΕήΒΣήΒςήΒΕ
  connection: string; // e.g., Verb Te-form
  meaning: string;
  explanation: string;
  examples: GrammarExample[];
}

export interface AnalyzedToken {
  text: string; // The word as it appears
  dictionaryForm: string;
  reading: string;
  meaning: string;
  jlpt: 'N5' | 'N4' | 'N3' | 'N2' | 'N1' | 'Unknown';
  type: 'VOCAB' | 'GRAMMAR';
  // New fields for the Word Card feature
  exampleSentence?: string;
  exampleReading?: string;
  exampleTranslation?: string;
}

export interface ReadingMaterial {
  id: string;
  title: string;
  content: string; // Japanese text
  translation: string; // Chinese translation
  tokens: AnalyzedToken[]; // List of extracted vocab/grammar
}

export interface DailyRecord {
  id: string;
  date: string; // ISO Date string YYYY-MM-DD
  words: WordDefinition[];
  grammar?: GrammarDefinition[];
  readings?: ReadingMaterial[];
}

export interface QuizQuestion {
  id: string;
  context?: string; // For reading passages or additional context
  question: string; // Could be the word or the meaning
  options: string[]; // 4 options
  correctAnswerIndex: number;
  explanation: string;
}

export enum AppMode {
  LEARN = 'LEARN',
  HISTORY = 'HISTORY',
  QUIZ = 'QUIZ',
  FOCUS = 'FOCUS',
  CHAT = 'CHAT',
}

export interface QuizConfig {
  sourceWords: WordDefinition[];
  sourceGrammar: GrammarDefinition[];
  dateLabel?: string;
  specificPrompt?: string; // New field
}

export type InputMode = 'WORD' | 'GRAMMAR' | 'READING';

export interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string;
  condition: (stats: PetStats) => boolean;
}

export interface PetStats {
  level: number;
  currentXp: number;
  nextLevelXp: number;
  totalFocusMinutes: number;
  mood: 'neutral' | 'happy' | 'focus' | 'sleep';
  unlockedAchievements: string[]; // List of Achievement IDs
}

export interface TimerState {
  isActive: boolean;
  mode: 'FOCUS' | 'BREAK';
  timeLeft: number;
  focusDuration: number;
  breakDuration: number;
  endTime?: number; // Timestamp for when the timer should end (for background persistence)
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  translation?: string; // Chinese translation for model response
  correction?: string; // Correction of user's grammar if applicable
  timestamp: number;
}

