const ChatIcon = () => <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M20.25 8.511c.884.284 1.5 1.128 1.5 2.097v4.286c0 1.136-.847 2.1-1.98 2.193-.34.027-.68.052-1.02.072v3.091l-3-3c-1.354 0-2.694-.055-4.02-.163a2.115 2.115 0 01-.825-.242m9.345-8.334a2.126 2.126 0 00-.476-.095 48.64 48.64 0 00-8.048 0c-1.131.094-1.976 1.057-1.976 2.192v4.286c0 .837.46 1.58 1.155 1.951m9.345-8.334V6.637c0-1.621-1.152-3.026-2.76-3.235A48.455 48.455 0 0011.25 3c-2.115 0-4.198.137-6.24.402-1.608.209-2.76 1.614-2.76 3.235v6.226c0 1.621 1.152 3.026 2.76 3.235.577.075 1.157.14 1.74.194V21l4.155-4.155" /></svg>;

const ACHIEVEMENTS: Achievement[] = [
  { id: 'first_step', title: 'ίΙζίΘ║ϋΝΖί╗υ', description: 'ίχΝόΙΡύυυϊ╕Αόυκί░Ιό│ρύ╖┤ύ┐Τ', icon: 'ΏθΝ▒', condition: (stats) => stats.totalFocusMinutes >= 1 },
  { id: 'focus_master_bronze', title: 'ί░Ιό│ρόΨ░όΚΜ', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 60 ίΙΗώΡα', icon: 'ΏθξΚ', condition: (stats) => stats.totalFocusMinutes >= 60 },
  { id: 'focus_master_silver', title: 'ί░Ιό│ρώΒΦϊ║║', description: 'ύ┤ψύσΞί░Ιό│ρόβΓώΨΥώΒΦίΙ░ 300 ίΙΗώΡα', icon: 'ΏθξΙ', condition: (stats) => stats.totalFocusMinutes >= 300 },
  { id: 'level_5', title: 'ίλρίχΙόΙΡϋοΠ', description: 'ίψ╡ύΚσύφΚύ┤γώΒΦίΙ░ 5', icon: 'ΏθΡ╛', condition: (stats) => stats.level >= 5 }
];

const INITIAL_PET_STATS: PetStats = { level: 1, currentXp: 0, nextLevelXp: 100, totalFocusMinutes: 0, mood: 'neutral', unlockedAchievements: [] };

type LearningMethod = 'MANUAL' | 'RECOMMEND' | 'QUIZ';
type JLPTLevel = 'N5' | 'N4' | 'N3' | 'N2' | 'N1';

function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.LEARN);
  const [inputMode, setInputMode] = useState<InputMode>('WORD');
  const [history, setHistory] = useState<DailyRecord[]>(() => {
    const saved = localStorage.getItem('mk-nihongo-history');
    return saved ? JSON.parse(saved) : [];
  });
  const [petStats, setPetStats] = useState<PetStats>(() => {
    const saved = localStorage.getItem('mk-nihongo-pet');
    return saved ? JSON.parse(saved) : INITIAL_PET_STATS;
  });

  const [learningMethod, setLearningMethod] = useState<LearningMethod>('MANUAL');
  const [selectedLevel, setSelectedLevel] = useState<JLPTLevel>('N5');
  const [recommendCount, setRecommendCount] = useState<number>(5);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [currentDefinitions, setCurrentDefinitions] = useState<WordDefinition[]>([]);
  const [currentGrammar, setCurrentGrammar] = useState<GrammarDefinition[]>([]);
  const [currentReading, setCurrentReading] = useState<ReadingMaterial | null>(null);
  const [quizConfig, setQuizConfig] = useState<QuizConfig | null>(null);
  const [selectedWordId, setSelectedWordId] = useState<string | null>(null);
  const [selectedGrammarId, setSelectedGrammarId] = useState<string | null>(null);
  const [xpToast, setXpToast] = useState<{ amount: number; id: number } | null>(null);

  const [timerState, setTimerState] = useState<TimerState>(() => {
    const saved = localStorage.getItem('mk-nihongo-timer');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Ensure we don't restore an 'active' state directly to avoid desync
      return { ...parsed, isActive: false, timeLeft: parsed.focusDuration * 60 };
    }
    return {
      isActive: false,
      mode: 'FOCUS',
      focusDuration: 25,
      breakDuration: 5,
      timeLeft: 25 * 60,
    };
  });

  useEffect(() => {
    localStorage.setItem('mk-nihongo-history', JSON.stringify(history));
    localStorage.setItem('mk-nihongo-pet', JSON.stringify(petStats));
    localStorage.setItem('mk-nihongo-timer', JSON.stringify({
      focusDuration: timerState.focusDuration,
      breakDuration: timerState.breakDuration,
      mode: timerState.mode
    }));
  }, [history, petStats, timerState.focusDuration, timerState.breakDuration, timerState.mode]);

  useEffect(() => {
    let interval: number | null = null;
    if (timerState.isActive) {
      interval = window.setInterval(() => {
        setTimerState(prev => {
          if (prev.timeLeft <= 1) {
            handleTimerComplete(prev);
            return prev;
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [timerState.isActive]);

  const handleTimerComplete = (prev: TimerState) => {
    if (prev.mode === 'FOCUS') {
      updatePetXp(50, prev.focusDuration);
      setTimerState({ 
        ...prev, 
        isActive: false, 
        mode: 'BREAK', 
        timeLeft: prev.breakDuration * 60 
      });
    } else {
      setTimerState({ 
        ...prev, 
        isActive: false, 
        mode: 'FOCUS', 
        timeLeft: prev.focusDuration * 60 
      });
    }
    // Simple browser notification if possible
    if (Notification.permission === "granted") {
        new Notification(prev.mode === 'FOCUS' ? "ί░Ιό│ρίχΝόΙΡΎ╝Β" : "ϊ╝ΣόΒψύ╡ΡόζθΎ╝Β", {
            body: prev.mode === 'FOCUS' ? "ϊ╝ΣόΒψϊ╕Αϊ╕ΜίΡπΎ╝Β" : "ό║ΨίΓβίξ╜ώΨΜίπΜϊ╕Μϊ╕Αϋ╝ςϊ║ΗίΩΟΎ╝θ"
        });
    }
  };

  const updatePetXp = (amount: number, minutes: number = 0) => {
    if (amount > 0) {
      setXpToast({ amount, id: Date.now() });
      setTimeout(() => setXpToast(null), 3000);
    }
    setPetStats(prev => {
      let newXp = prev.currentXp + amount;
      let newLevel = prev.level;
      let nextXp = prev.nextLevelXp;
      while (newXp >= nextXp) {
        newXp -= nextXp;
        newLevel += 1;
        nextXp = Math.floor(nextXp * 1.2);
      }
      return { ...prev, level: newLevel, currentXp: newXp, nextLevelXp: nextXp, totalFocusMinutes: prev.totalFocusMinutes + minutes, mood: 'happy' };
    });
  };

  const toggleTimer = () => setTimerState(prev => ({ ...prev, isActive: !prev.isActive }));
  const resetTimer = () => setTimerState(prev => ({ ...prev, isActive: false, timeLeft: (prev.mode === 'FOCUS' ? prev.focusDuration : prev.breakDuration) * 60 }));
  const switchTimerMode = () => setTimerState(prev => {
    const nextMode = prev.mode === 'FOCUS' ? 'BREAK' : 'FOCUS';
    return { ...prev, mode: nextMode, isActive: false, timeLeft: (nextMode === 'FOCUS' ? prev.focusDuration : prev.breakDuration) * 60 };
  });

  const handleLearn = async () => {
    if ((learningMethod === 'MANUAL' || learningMethod === 'QUIZ') && !input.trim()) return;
    setLoading(true);

    try {
      if (learningMethod === 'QUIZ') {
         setQuizConfig({ 
            sourceWords: [], 
            sourceGrammar: [], 
            dateLabel: "AI ίχγϋμ╜ύ╖┤ύ┐Τ",
            specificPrompt: input 
         });
         setMode(AppMode.QUIZ);
         setLoading(false);
         return;
      }

      let newWords: WordDefinition[] = [];
      let newGrammar: GrammarDefinition[] = [];
      let newReading: ReadingMaterial | null = null;

      if (learningMethod === 'MANUAL') {
        if (inputMode === 'WORD') newWords = await fetchWordDefinitions(input);
        else if (inputMode === 'GRAMMAR') newGrammar = await fetchGrammarDetails(input);
        else if (inputMode === 'READING') newReading = await analyzeReadingText(input);
      } else {
        if (inputMode === 'WORD') newWords = await fetchRecommendedWords(selectedLevel, recommendCount, []);
        else if (inputMode === 'GRAMMAR') newGrammar = await fetchRecommendedGrammar(selectedLevel, recommendCount, []);
        else if (inputMode === 'READING') newReading = await generateRecommendedReading(selectedLevel);
      }

      setCurrentDefinitions(newWords);
      setCurrentGrammar(newGrammar);
      setCurrentReading(newReading);

      const today = new Date().toISOString().split('T')[0];
      setHistory(prev => [{ id: Date.now().toString(), date: today, words: newWords, grammar: newGrammar, readings: newReading ? [newReading] : [] }, ...prev]);

      if (learningMethod === 'MANUAL') setInput('');
      updatePetXp(20);
    } catch (error) { 
      console.error(error);
      alert("ύΦθόΙΡίν▒όΧΩΎ╝ΝϋτΜόςλόθξύ╢▓ϋ╖ψόΙΨ API KEYήΑΓ"); 
    } finally { 
      setLoading(false); 
    }
  };

  const renderContent = () => {
    switch (mode) {
      case AppMode.LEARN:
        return (
          <div className="flex flex-col gap-10">
            <motion.div initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} className="bg-white p-6 sm:p-10 rounded-[3rem] shadow-xl border border-gray-100">
              <div className="flex flex-col gap-8 w-full">
                <h2 className="text-xl font-black text-zinc-400 tracking-tighter uppercase">όΔ│ίφ╕ώ╗ηϊ╗Αώ║╝Ύ╝θ</h2>

                <div className="flex bg-zinc-100/80 p-1 rounded-2xl border border-zinc-200 relative">
                  <div className="grid grid-cols-3 w-full relative z-10 text-center">
                    {['WORD', 'GRAMMAR', 'READING'].map((m) => (
                      <button key={m} onClick={() => setInputMode(m as InputMode)} className={`py-3 text-base font-bold transition-all ${inputMode === m ? 'text-black' : 'text-zinc-400'}`}>
                        {m === 'WORD' ? 'ίΨχίφΩ' : m === 'GRAMMAR' ? 'όΨΘό│Χ' : 'όΨΘύτι'}
                      </button>
                    ))}
                  </div>
                  <motion.div className="absolute inset-y-1 bg-white shadow-sm rounded-xl border border-zinc-200" animate={{ x: inputMode === 'WORD' ? '0%' : inputMode === 'GRAMMAR' ? '100%' : '200%', width: '33.33%' }} />
                </div>

                <div className="flex bg-zinc-100/80 p-1 rounded-2xl border border-zinc-200 relative">
                  <div className="grid grid-cols-3 w-full relative z-10 text-center">
                    {['MANUAL', 'RECOMMEND', 'QUIZ'].map((m) => (
                      <button key={m} onClick={() => setLearningMethod(m as LearningMethod)} className={`py-3 text-base font-bold transition-all ${learningMethod === m ? 'text-black' : 'text-zinc-400'}`}>
                        {m === 'MANUAL' ? 'ϋ╝╕ίΖξ' : m === 'RECOMMEND' ? 'όΟρϋΨο' : 'ό╕υώσΩ'}
                      </button>
                    ))}
                  </div>
                  <motion.div className="absolute inset-y-1 bg-white shadow-sm rounded-xl border border-zinc-200" animate={{ x: learningMethod === 'MANUAL' ? '0%' : learningMethod === 'RECOMMEND' ? '100%' : '200%', width: '33.33%' }} />
                </div>

                <textarea
                  className="w-full p-8 bg-zinc-50/50 border border-zinc-200 rounded-[2rem] outline-none text-xl text-zinc-900 font-bold h-64 shadow-inner resize-none"
                  placeholder={learningMethod === 'QUIZ' ? "ϋ╝╕ίΖξόΔ│ό╕υώσΩύγΕίΖπίχ╣Ύ╝ΝAI όεΔύΓ║ϊ╜ιίΘ║ώκΝ..." : "ϋτΜϋ╝╕ίΖξίΖπίχ╣..."} 
                  value={input} 
                  onChange={(e) => setInput(e.target.value)}
                />
                <div className="flex justify-center">
                  <Button onClick={handleLearn} disabled={loading} className="px-12 py-5 text-xl">
                    {loading ? 'AI όΑζϋΑΔϊ╕φ...' : 'ΏθγΑ ώΨΜίπΜϋπμόηΡ'}
                  </Button>
                </div>
              </div>
            </motion.div>

            {(currentDefinitions.length > 0 || currentGrammar.length > 0) && (
              <div className="space-y-10 px-4">
                <h3 className="text-xl font-black text-zinc-900 border-l-8 border-zinc-900 pl-4 uppercase">ϋπμόηΡύ╡Ρόηε</h3>
                <div className="grid gap-8 md:grid-cols-2">
                  {currentDefinitions.map((w, i) => <WordCard key={i} layoutId={`w-${i}`} data={w} />)}
                  {currentGrammar.map((g, i) => <GrammarCard key={i} layoutId={`g-${i}`} data={g} />)}
                </div>
              </div>
            )}
            {currentReading && <ReadingView material={currentReading} />}
          </div>
        );
      case AppMode.CHAT: return <ChatInterface onBack={() => setMode(AppMode.LEARN)} onXpUpdate={updatePetXp} />;
      case AppMode.QUIZ: return quizConfig ? <Quiz {...quizConfig} onExit={() => setMode(AppMode.LEARN)} /> : null;
      case AppMode.FOCUS: 
        return (
          <div className="max-w-4xl mx-auto flex flex-col items-center gap-16 py-10">
            <PomodoroTimer 
              state={timerState} 
              onToggle={toggleTimer} 
              onReset={resetTimer} 
              onSwitchMode={switchTimerMode}
              onUpdateSettings={(f, b) => setTimerState(prev => ({ 
                ...prev, 
                focusDuration: f, 
                breakDuration: b, 
                timeLeft: (prev.mode === 'FOCUS' ? f : b) * 60,
                isActive: false 
              }))}
            />
            <PetCompanion stats={petStats} onClick={() => updatePetXp(1)} />
          </div>
        );
      case AppMode.HISTORY:
        return (
          <div className="max-w-4xl mx-auto space-y-8 pb-24 px-5">
            <h2 className="text-3xl font-black text-zinc-900 tracking-tighter uppercase border-l-8 border-zinc-900 pl-4">ίφ╕ύ┐Τόφ╖ίΠ▓</h2>
            {history.length > 0 ? (
              <div className="grid gap-4">
                {history.map((record) => (
                  <div key={record.id} className="p-6 bg-white rounded-2xl border border-zinc-100 shadow-sm flex justify-between items-center">
                    <div>
                      <p className="text-zinc-900 font-black text-xl">{record.date}</p>
                      <p className="text-zinc-400 text-sm">{record.words.length} ίΑΜίΨχίφΩ / {record.grammar?.length || 0} ίΑΜόΨΘό│Χ</p>
                    </div>
                    <Button variant="outline" onClick={() => {
                      setQuizConfig({ sourceWords: record.words, sourceGrammar: record.grammar || [], dateLabel: record.date });
                      setMode(AppMode.QUIZ);
                    }}>ϋνΘύ┐Τό╕υώσΩ</Button>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-20 text-zinc-300 font-bold">ύδχίΚΞώΓΕό▓ΤόεΚϋραώΝΕίΨΦ</div>
            )}
          </div>
        );
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-zinc-50 font-sans text-zinc-900">
      <header className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-zinc-200">
        <div className="max-w-5xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setMode(AppMode.LEARN)}>
            <div className="w-10 h-10 bg-black rounded-xl flex items-center justify-center text-white font-black text-xl">όΩξ</div>
            <h1 className="text-xl font-black tracking-tighter uppercase hidden sm:block">Mono-Kuro</h1>
          </div>
          <nav className="flex gap-2">
            {[
              { m: AppMode.LEARN, i: <BookIcon />, l: 'ίφ╕ύ┐Τ' },
              { m: AppMode.CHAT, i: <ChatIcon />, l: 'ί░Ξϋσ▒' },
              { m: AppMode.HISTORY, i: <ClockIcon />, l: 'ύ┤ΑώΝΕ' },
              { m: AppMode.FOCUS, i: <FocusIcon />, l: 'ί░Ιό│ρ' }
            ].map(nav => (
              <button 
                key={nav.m} 
                onClick={() => setMode(nav.m)}
                className={`p-3 rounded-xl flex items-center gap-2 transition-all ${mode === nav.m ? 'bg-zinc-900 text-white' : 'text-zinc-400 hover:bg-zinc-100'}`}
              >
                {nav.i} <span className="text-sm font-bold hidden md:block">{nav.l}</span>
              </button>
            ))}
          </nav>
        </div>
      </header>
      <main className="max-w-5xl mx-auto py-10 px-6">
        <AnimatePresence mode="wait">
          <motion.div key={mode} initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            {renderContent()}
          </motion.div>
        </AnimatePresence>
      </main>
      <AnimatePresence>
        {mode !== AppMode.FOCUS && (timerState.isActive || timerState.timeLeft < (timerState.mode === 'FOCUS' ? timerState.focusDuration : timerState.breakDuration) * 60) && (
          <MiniTimer state={timerState} onClick={() => setMode(AppMode.FOCUS)} />
        )}
      </AnimatePresence>
    </div>
  );
}

export default App;

export interface SentenceWord {
  word: string;
  reading: string;
  meaning: string;
}

export interface WordDefinition {
  word: string;
  reading: string;
  meaning: string;
  exampleSentence: string;
  exampleReading?: string; // Hiragana reading of the example sentence
  exampleTranslation: string;
  sentenceBreakdown?: SentenceWord[]; // Detailed breakdown of words in the sentence
}

export interface GrammarExample {
  sentence: string;
  reading: string;
  translation: string;
}

export interface GrammarDefinition {
  id: string; // unique internal id
  grammarPoint: string; // e.g., Ύ╜ηήΒοήΒψήΒΕήΒΣήΒςήΒΕ
  connection: string; // e.g., Verb Te-form
  meaning: string;
  explanation: string;
  examples: GrammarExample[];
}

export interface AnalyzedToken {
  text: string; // The word as it appears
  dictionaryForm: string;
  reading: string;
  meaning: string;
  jlpt: 'N5' | 'N4' | 'N3' | 'N2' | 'N1' | 'Unknown';
  type: 'VOCAB' | 'GRAMMAR';
  // New fields for the Word Card feature
  exampleSentence?: string;
  exampleReading?: string;
  exampleTranslation?: string;
}

export interface ReadingMaterial {
  id: string;
  title: string;
  content: string; // Japanese text
  translation: string; // Chinese translation
  tokens: AnalyzedToken[]; // List of extracted vocab/grammar
}

export interface DailyRecord {
  id: string;
  date: string; // ISO Date string YYYY-MM-DD
  words: WordDefinition[];
  grammar?: GrammarDefinition[];
  readings?: ReadingMaterial[];
}

export interface QuizQuestion {
  id: string;
  context?: string; // For reading passages or additional context
  question: string; // The question text
  questionReading?: string; // Hiragana/Reading for the whole question
  questionTranslation?: string; // Chinese translation for the whole question
  options: string[]; // 4 options
  correctAnswerIndex: number;
  explanation: string;
}

export enum AppMode {
  LEARN = 'LEARN',
  HISTORY = 'HISTORY',
  QUIZ = 'QUIZ',
  FOCUS = 'FOCUS',
  CHAT = 'CHAT',
}

export interface QuizConfig {
  sourceWords: WordDefinition[];
  sourceGrammar: GrammarDefinition[];
  dateLabel?: string;
  specificPrompt?: string; // New field
}

export type InputMode = 'WORD' | 'GRAMMAR' | 'READING';

export interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string;
  condition: (stats: PetStats) => boolean;
}

export interface PetStats {
  level: number;
  currentXp: number;
  nextLevelXp: number;
  totalFocusMinutes: number;
  mood: 'neutral' | 'happy' | 'focus' | 'sleep';
  unlockedAchievements: string[]; // List of Achievement IDs
}

export interface TimerState {
  isActive: boolean;
  mode: 'FOCUS' | 'BREAK';
  timeLeft: number;
  focusDuration: number;
  breakDuration: number;
  endTime?: number; // Timestamp for when the timer should end (for background persistence)
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  translation?: string; // Chinese translation for model response
  correction?: string; // Correction of user's grammar if applicable
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { WordDefinition, QuizQuestion, GrammarDefinition, ReadingMaterial, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- WORD SCHEMA ---
