export const generateQuizFromContent = async (words: WordDefinition[], grammar: GrammarDefinition[], specificPrompt?: string): Promise<QuizQuestion[]> => {
  const context = JSON.stringify({ words, grammar, rawInput: specificPrompt });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `
      Based on this content: ${context}

      Generate a 10-question mixed Japanese quiz.

      MANDATORY MIX:
      1. 3 Fill-in-the-blank questions (___) about particles or conjugation.
      2. 2 Sentence ordering questions (e.g. Arrange A, B, C, D to form a sentence).
      3. 2 Reading comprehension questions based on a context snippet.
      4. 3 Vocabulary/Kanji usage questions.

      CRITICAL: For EVERY question, provide:
      - 'questionReading': The full phonetic reading (Hiragana/Katakana) for the question text.
      - 'questionTranslation': A natural Traditional Chinese translation for the question text.

      Difficulty: Match the input content.
      Language: Traditional Chinese (Taiwan).
      Target: 10 total questions.
    `,
    config: { responseMimeType: "application/json", responseSchema: quizSchema },
  });
  return JSON.parse(response.text) as QuizQuestion[];
};

export const getChatResponse = async (history: ChatMessage[], newMessage: string, context?: string): Promise<any> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `You are a Japanese tutor. User says: "${newMessage}". History: ${JSON.stringify(history)}. Context: ${context}.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          reply: { type: Type.STRING },
          translation: { type: Type.STRING },
          correction: { type: Type.STRING, description: "Grammar correction if needed" }
        },
        required: ["reply", "translation"]
      }
    }
  });
  return JSON.parse(response.text);
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { generateQuizFromContent } from '../services/geminiService';
import { WordDefinition, GrammarDefinition, QuizQuestion } from '../types';
import { Loader } from './Loader';
import { Button } from './Button';

interface QuizProps {
  sourceWords: WordDefinition[];
  sourceGrammar: GrammarDefinition[];
  specificPrompt?: string; // New prop for user-defined quiz content
  onExit: () => void;
  title?: string;
}

export const Quiz: React.FC<QuizProps> = ({ sourceWords, sourceGrammar, specificPrompt, onExit, title }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [userAnswers, setUserAnswers] = useState<(number | null)[]>([]);
  const [showResult, setShowResult] = useState(false);
  const [selectedReviewIndex, setSelectedReviewIndex] = useState<number | null>(null);

  useEffect(() => {
    const loadQuiz = async () => {
      try {
        setLoading(true);
        const qs = await generateQuizFromContent(sourceWords, sourceGrammar, specificPrompt);
        setQuestions(qs);
        setUserAnswers(new Array(qs.length).fill(null));
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    loadQuiz();
  }, [sourceWords, sourceGrammar, specificPrompt]);

  const handleAnswer = (optionIndex: number) => {
    if (userAnswers[currentIndex] !== null) return;
    const newAnswers = [...userAnswers];
    newAnswers[currentIndex] = optionIndex;
    setUserAnswers(newAnswers);

    setTimeout(() => {
      if (currentIndex < questions.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        setShowResult(true);
      }
    }, 1200);
  };

  const calculateScore = () => userAnswers.reduce((acc, ans, idx) => acc + (ans === questions[idx].correctAnswerIndex ? 1 : 0), 0);

  if (loading) return <div className="h-64 flex items-center justify-center"><Loader text={specificPrompt ? "όφμίερϋπμόηΡίΖπίχ╣ϊ╕ούΦθόΙΡί░Ιί▒υώκΝύδχ..." : "ίΘ║ώκΝϊ╕φ..."} /></div>;

  if (questions.length === 0) return (
    <div className="text-center p-8 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border border-white/60 ring-1 ring-black/5">
      <p className="text-gray-500 mb-6 font-bold">ύδχίΚΞόγτόβΓύΕκό│ΧύΦθόΙΡό╕υώσΩΎ╝ΝϋτΜύρΞί╛ΝίΗΞϋσοήΑΓ</p>
      <Button onClick={onExit} variant="liquid">ϋ┐ΦίδηώοΨώιΒ</Button>
    </div>
  );

  if (showResult) {
    const score = calculateScore();
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="max-w-3xl mx-auto pb-20 px-2">
        <div className="text-center mb-10 bg-white p-12 rounded-[3rem] border border-gray-100 shadow-xl relative overflow-hidden">
          <div className="absolute top-0 right-0 p-32 bg-gray-50 rounded-full -translate-y-1/2 translate-x-1/2 -z-10" />
          <h2 className="text-2xl font-black text-gray-500 mb-2 uppercase tracking-tighter">ό╕υώσΩύ╡Ρόζθ</h2>
          <div className="text-7xl font-black text-gray-900 mb-6 tracking-tighter">
            {score} <span className="text-2xl text-gray-300 font-bold">/ {questions.length}</span>
          </div>
          <p className="text-gray-400 font-bold mb-10 text-lg">ϋκρύΠ╛ί╛Ωί╛ΙόμΤΎ╝Βώ╗ηόΥΛϊ╕ΜόΨ╣ώκΝύδχόθξύεΜϋσ│ύ┤░ϋπμόηΡϋΙΘύ┐╗ϋφψί░ΞόψΦήΑΓ</p>
          <Button onClick={onExit} variant="liquid" className="px-12 py-5">ίδηίΙ░ώοΨώιΒ</Button>
        </div>

        <div className="grid gap-6">
          {questions.map((q, idx) => {
            const isCorrect = userAnswers[idx] === q.correctAnswerIndex;
            return (
              <motion.div
                layoutId={`question-card-${idx}`}
                key={q.id}
                onClick={() => setSelectedReviewIndex(idx)}
                className={`p-8 rounded-[2.5rem] border transition-all cursor-pointer ${
                  isCorrect ? 'bg-white border-gray-100 hover:border-gray-300 shadow-sm' : 'bg-red-50/10 border-red-100 hover:bg-red-50/20 shadow-sm'
                }`}
              >
                <div className="flex items-center gap-6">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg shadow-md ${
                    isCorrect ? 'bg-gray-900 text-white' : 'bg-red-500 text-white'
                  }`}>
                    {idx + 1}
                  </div>
                  <div className="flex-1">
                     <h4 className="text-gray-900 font-black text-lg mb-2 line-clamp-1">{q.question}</h4>
                     <div className="flex items-center gap-4">
                        <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${isCorrect ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                          {isCorrect ? 'όφμύλ║' : 'ώΝψϋςν'}
                        </span>
                        {!isCorrect && <span className="text-gray-400 text-sm font-bold tracking-tight">όφμϋπμ: {q.options[q.correctAnswerIndex]}</span>}
                     </div>
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>

        <AnimatePresence>
          {selectedReviewIndex !== null && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/40 backdrop-blur-md" onClick={() => setSelectedReviewIndex(null)}>
              <motion.div layoutId={`question-card-${selectedReviewIndex}`} className="w-full max-w-lg bg-white rounded-[3rem] shadow-2xl overflow-hidden max-h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
                 <div className="p-8 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                    <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em]">ώκΝύδχϋσ│ϋπμ έΑλ ύυυ {selectedReviewIndex + 1} ώκΝ</h3>
                    <button onClick={() => setSelectedReviewIndex(null)} className="p-3 bg-white rounded-full text-gray-400 hover:text-gray-900 transition-all shadow-sm">
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={4} stroke="currentColor" className="w-5 h-5"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                 </div>
                 <div className="p-10 overflow-y-auto no-scrollbar space-y-10">
                    {/* Language Review Helper Section */}
                    <div className="bg-zinc-50 border-2 border-zinc-200 rounded-[2rem] p-8 space-y-6 shadow-inner">
                      <div className="space-y-1">
                        <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">όΩξόΨΘίΟθόΨΘ</h4>
                        <p className="text-2xl font-black text-zinc-900 leading-tight tracking-tighter">
                          {questions[selectedReviewIndex].question}
                        </p>
                      </div>

                      {questions[selectedReviewIndex].questionReading && (
                        <div className="space-y-1 pt-2 border-t border-zinc-100">
                          <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">ί╣│ίΒΘίΡΞ/ϋχΑώθ│όρβύν║</h4>
                          <p className="text-lg font-bold text-zinc-500 tracking-tight">
                            {questions[selectedReviewIndex].questionReading}
                          </p>
                        </div>
                      )}

                      {questions[selectedReviewIndex].questionTranslation && (
                        <div className="space-y-1 pt-2 border-t border-zinc-100">
                          <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">ϊ╕φόΨΘύ┐╗ϋφψ</h4>
                          <p className="text-lg font-black text-indigo-600/80 tracking-tight">
                            {questions[selectedReviewIndex].questionTranslation}
                          </p>
                        </div>
                      )}
                    </div>

                    {questions[selectedReviewIndex].context && <div className="p-8 bg-gray-50 border-l-8 border-gray-900 rounded-r-3xl text-gray-900 text-xl font-bold leading-relaxed shadow-inner">{questions[selectedReviewIndex].context}</div>}

                    <div className="space-y-4">
                      <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">ώΒ╕ώιΖίΙΗόηΡ</h5>
                      {questions[selectedReviewIndex].options.map((opt, i) => {
                        const isSelected = userAnswers[selectedReviewIndex] === i;
                        const isCorrect = questions[selectedReviewIndex].correctAnswerIndex === i;
                        let style = "border-gray-100 text-gray-400 bg-gray-50/30";
                        if (isCorrect) style = "border-green-500/30 bg-green-50 text-green-700 font-bold ring-4 ring-green-100/50";
                        else if (isSelected && !isCorrect) style = "border-red-500/30 bg-red-50 text-red-600 ring-4 ring-red-100/50";
                        return <div key={i} className={`p-6 border rounded-2xl flex justify-between items-center transition-all text-lg ${style}`}><span>{opt}</span>{isCorrect && <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={4} stroke="currentColor" className="w-6 h-6"><path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" /></svg>}</div>;
                      })}
                    </div>

                    <div className="bg-gray-900 p-10 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
                      <div className="absolute top-0 left-0 w-2 h-full bg-indigo-500" />
                      <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6">AI ϋΑΒί╕τύγΕϋσ│ύ┤░ϋπμόηΡ</h5>
                      <p className="text-white leading-relaxed font-bold text-lg tracking-tight">{questions[selectedReviewIndex].explanation}</p>
                    </div>
                 </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    );
  }

  const currentQ = questions[currentIndex];
  const currentSelected = userAnswers[currentIndex];
  return (
    <div className="max-w-3xl mx-auto px-4">
      <div className="mb-10 flex items-center justify-between px-6">
        <div>
           <h2 className="text-2xl font-black text-gray-900 tracking-tighter uppercase">{title || "ό╕υώσΩώΑ▓ϋκΝϊ╕φ"}</h2>
           {specificPrompt && <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">ίθ║όΨ╝όΓρύγΕϋ╝╕ίΖξίΖπίχ╣ύΦθόΙΡ</p>}
        </div>
        <span className="text-sm font-black text-white bg-gray-900 px-6 py-2.5 rounded-2xl shadow-xl">
          {currentIndex + 1} / {questions.length}
